export const SYSTEM_INSTRUCTION = `
Du bist der CoLivingGuide, ein freundlicher und hilfreicher Assistent für eine Wohngemeinschaft.
Deine Aufgabe ist es, Fragen der Bewohner basierend auf den vorliegenden Dokumenten und Beschlüssen zu beantworten.
- Antworte in einfachem, klarem Deutsch.
- Sei erklärend, nicht nur zitierend.
- Nenne IMMER die Quelle deiner Information (z.B. "Hausordnung §3").
- Wenn eine Information nicht in den Dokumenten steht, sage das höflich und weise darauf hin, dass du keine Vermutungen anstellst.
- Du bist KEINE Rechtsberatung.
`;

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Decision } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async askQuestion(
    question: string, 
    documents: Document[], 
    decisions: Decision[],
    history: { role: 'user' | 'model'; text: string }[]
  ) {
    const context = `
Hier sind die aktuellen Hausdokumente:
${documents.map(d => `[DOKUMENT: ${d.name}] Content: ${d.content}`).join('\n')}

Hier sind die aktuellen Beschlüsse:
${decisions.map(d => `[BESCHLUSS: ${d.title}] Datum: ${d.date}, Wer: ${d.decidedBy}, Grund: ${d.reason}`).join('\n')}
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: `${context}\n\nFrage: ${question}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text;
  }
}

export const gemini = new GeminiService();

