import React, { useState, useRef, useEffect } from 'react';
import { Message, Document, Decision } from '../types';
import { MicIcon, ArrowRightIcon } from './Icons';
import { gemini } from '../services/geminiService';

interface ChatViewProps {
  messages: Message[];
  onSendMessage: (text: string) => void;
  onEnterVoice: () => void;
  isLoading: boolean;
}

const ChatView: React.FC<ChatViewProps> = ({ messages, onSendMessage, onEnterVoice, isLoading }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isLoading) {
      onSendMessage(input.trim());
      setInput('');
    }
  };

  return (
    <div className="flex flex-col h-full max-w-3xl mx-auto w-full px-4 sm:px-6">
      <div ref={scrollRef} className="flex-1 overflow-y-auto py-10 space-y-8 scroll-smooth no-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="w-16 h-16 bg-sage-100 rounded-3xl flex items-center justify-center mb-6 shadow-sm">
              <ChatIcon className="w-8 h-8 text-green-600" />
            </div>
            <h1 className="text-3xl font-semibold tracking-tight mb-3">Wie kann ich helfen?</h1>
            <p className="text-gray-500 max-w-md mx-auto leading-relaxed">
              Frag mich nach der Hausordnung, dem Mietvertrag oder aktuellen Beschlüssen.
            </p>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}
          >
            <div className={`max-w-[85%] px-5 py-4 rounded-3xl shadow-sm ${
              msg.role === 'user' 
              ? 'bg-black text-white rounded-tr-none' 
              : 'bg-white border border-gray-100 rounded-tl-none'
            }`}>
              <p className="leading-relaxed whitespace-pre-wrap text-sm sm:text-base">{msg.text}</p>
              {msg.sources && msg.sources.length > 0 && (
                <div className="mt-3 pt-3 border-t border-gray-100/10 flex flex-wrap gap-2">
                  {msg.sources.map((s, i) => (
                    <span key={i} className="text-[10px] uppercase tracking-wider font-semibold opacity-60">
                      {s}
                    </span>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-50 px-5 py-4 rounded-3xl rounded-tl-none border border-gray-100">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce" />
                <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce [animation-delay:0.2s]" />
                <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce [animation-delay:0.4s]" />
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="pb-8 pt-4 safe-bottom">
        <form onSubmit={handleSubmit} className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Frag etwas..."
            className="w-full bg-white border border-gray-100 rounded-3xl px-6 py-4 pr-32 shadow-lg focus:outline-none focus:ring-2 focus:ring-black/5 transition-all text-lg placeholder:text-gray-300"
            disabled={isLoading}
          />
          <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-2">
            <button
              type="button"
              onClick={onEnterVoice}
              className="p-3 text-gray-400 hover:text-green-600 transition-colors rounded-full hover:bg-gray-50"
            >
              <MicIcon className="w-6 h-6" />
            </button>
            <button
              type="submit"
              disabled={!input.trim() || isLoading}
              className={`p-3 rounded-full transition-all ${
                input.trim() && !isLoading ? 'bg-black text-white' : 'bg-gray-100 text-gray-400'
              }`}
            >
              <ArrowRightIcon className="w-6 h-6" />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const ChatIcon = ({ className }: { className: string }) => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className={className}>
    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
  </svg>
);

export default ChatView;

import React, { useEffect, useState } from 'react';
import { CloseIcon, MicIcon } from './Icons';

interface VoiceModeProps {
  onClose: () => void;
}

const VoiceMode: React.FC<VoiceModeProps> = ({ onClose }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');

  useEffect(() => {
    // Simulation logic for voice mode
    const timer = setTimeout(() => setIsListening(true), 1000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-center p-6 animate-in fade-in duration-500">
      <button 
        onClick={onClose}
        className="absolute top-8 right-8 p-3 hover:bg-gray-100 rounded-full transition-colors"
      >
        <CloseIcon className="w-8 h-8" />
      </button>

      <div className="flex-1 flex flex-col items-center justify-center space-y-12">
        <div className="text-center space-y-4">
          <h2 className="text-3xl font-semibold tracking-tight">Frag den Guide</h2>
          <p className="text-gray-400 max-w-xs mx-auto">
            Ich höre zu. Frag mich nach Hausregeln oder Beschlüssen.
          </p>
        </div>

        <div className="relative group cursor-pointer" onClick={() => setIsListening(!isListening)}>
          <div className={`absolute inset-0 bg-green-100 rounded-full scale-150 blur-3xl opacity-20 transition-all duration-1000 ${isListening ? 'scale-[2] animate-pulse' : 'scale-100'}`} />
          <div className={`relative w-32 h-32 bg-white shadow-2xl rounded-full flex items-center justify-center border-2 border-gray-50 transition-all duration-500 ${isListening ? 'scale-110' : 'scale-100'}`}>
            <MicIcon className={`w-12 h-12 ${isListening ? 'text-green-600' : 'text-gray-300'}`} />
          </div>

          {/* Animated Waveform */}
          {isListening && (
            <div className="absolute -bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-1.5 h-8">
              {[...Array(5)].map((_, i) => (
                <div 
                  key={i}
                  className="w-1.5 bg-green-500 rounded-full animate-waveform"
                  style={{ 
                    animationDelay: `${i * 0.1}s`,
                    height: `${Math.random() * 100}%`
                  }}
                />
              ))}
            </div>
          )}
        </div>

        <div className="h-20 text-center px-4">
          <p className="text-xl text-gray-500 italic animate-in fade-in duration-1000">
            {transcript || (isListening ? '"Wie sind die Ruhezeiten am Wochenende?"' : '')}
          </p>
        </div>
      </div>

      <style>{`
        @keyframes waveform {
          0%, 100% { height: 20%; }
          50% { height: 100%; }
        }
        .animate-waveform {
          animation: waveform 0.8s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default VoiceMode;

import React, { useState } from 'react';
import { Document, Decision } from '../types';
import { PlusIcon, TrashIcon, DocIcon } from './Icons';

interface AdminPanelProps {
  documents: Document[];
  decisions: Decision[];
  onAddDoc: (doc: Document) => void;
  onRemoveDoc: (id: string) => void;
  onAddDecision: (dec: Decision) => void;
  activeTab: 'docs' | 'decisions';
  setActiveTab: (tab: 'docs' | 'decisions') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, decisions, onAddDoc, onRemoveDoc, onAddDecision, activeTab, setActiveTab 
}) => {
  const [showDocModal, setShowDocModal] = useState(false);
  const [newDoc, setNewDoc] = useState({ name: '', category: 'Hausordnung' as any, content: '' });

  const handleAddDoc = () => {
    if (newDoc.name && newDoc.content) {
      onAddDoc({
        id: Math.random().toString(36).substr(2, 9),
        name: newDoc.name,
        category: newDoc.category,
        uploadDate: new Date().toISOString().split('T')[0],
        content: newDoc.content,
        status: 'aktiv'
      });
      setShowDocModal(false);
      setNewDoc({ name: '', category: 'Hausordnung', content: '' });
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="mb-10">
        <h1 className="text-4xl font-semibold tracking-tight mb-2">Kuratierte Wahrheit</h1>
        <p className="text-gray-500">Verwalte Dokumente und Beschlüsse für dein Co-Living.</p>
      </header>

      <div className="flex gap-8 border-b border-gray-100 mb-8">
        <button 
          onClick={() => setActiveTab('docs')}
          className={`pb-4 text-sm font-medium transition-all relative ${activeTab === 'docs' ? 'text-black' : 'text-gray-400 hover:text-black'}`}
        >
          Dokumente
          {activeTab === 'docs' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black" />}
        </button>
        <button 
          onClick={() => setActiveTab('decisions')}
          className={`pb-4 text-sm font-medium transition-all relative ${activeTab === 'decisions' ? 'text-black' : 'text-gray-400 hover:text-black'}`}
        >
          Beschlüsse
          {activeTab === 'decisions' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black" />}
        </button>
      </div>

      {activeTab === 'docs' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <button 
              onClick={() => setShowDocModal(true)}
              className="border-2 border-dashed border-gray-100 rounded-3xl p-8 flex flex-col items-center justify-center text-gray-400 hover:border-black hover:text-black transition-all group"
            >
              <PlusIcon className="w-8 h-8 mb-3 group-hover:scale-110 transition-transform" />
              <span className="text-sm font-medium">Neues Dokument</span>
            </button>
            {documents.map(doc => (
              <div key={doc.id} className="bg-white border border-gray-100 rounded-3xl p-6 shadow-sm group hover:shadow-md transition-all">
                <div className="flex items-start justify-between mb-4">
                  <div className="p-3 bg-gray-50 rounded-2xl group-hover:bg-green-50 transition-colors">
                    <DocIcon className="w-6 h-6 text-gray-400 group-hover:text-green-600" />
                  </div>
                  <button onClick={() => onRemoveDoc(doc.id)} className="p-2 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                    <TrashIcon className="w-4 h-4" />
                  </button>
                </div>
                <h3 className="font-semibold text-gray-900 mb-1 truncate">{doc.name}</h3>
                <p className="text-xs text-gray-400 mb-3">{doc.category} • {doc.uploadDate}</p>
                <div className="px-2 py-1 bg-green-50 text-green-700 text-[10px] font-bold uppercase tracking-wider rounded-md inline-block">
                  {doc.status}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'decisions' && (
        <div className="space-y-4">
          {decisions.map(dec => (
            <div key={dec.id} className="bg-white border border-gray-100 rounded-3xl p-6 shadow-sm">
              <div className="flex justify-between items-start mb-2">
                <h3 className="text-lg font-semibold">{dec.title}</h3>
                <span className="text-xs text-gray-400">{dec.date}</span>
              </div>
              <p className="text-sm text-gray-600 mb-4">{dec.reason}</p>
              <div className="flex items-center gap-3 text-xs text-gray-400">
                <span className="px-2 py-1 bg-gray-50 rounded-md">Von: {dec.decidedBy}</span>
                <span className="px-2 py-1 bg-gray-50 rounded-md">Quelle: {dec.source}</span>
              </div>
            </div>
          ))}
          <button className="w-full border-2 border-dashed border-gray-100 rounded-3xl p-6 text-gray-400 hover:border-black hover:text-black transition-all flex items-center justify-center gap-2">
            <PlusIcon className="w-5 h-5" />
            <span>Beschluss hinzufügen</span>
          </button>
        </div>
      )}

      {/* Modal Mockup */}
      {showDocModal && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[200] flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-bold mb-6">Dokument hochladen</h2>
            <div className="space-y-4 mb-8">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
                <input 
                  type="text" 
                  value={newDoc.name}
                  onChange={e => setNewDoc({...newDoc, name: e.target.value})}
                  className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-black/5"
                  placeholder="z.B. Hausordnung_2025.pdf"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Inhalt (Textextrakt)</label>
                <textarea 
                  value={newDoc.content}
                  onChange={e => setNewDoc({...newDoc, content: e.target.value})}
                  className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl h-32 focus:outline-none focus:ring-2 focus:ring-black/5"
                  placeholder="Paste den Inhalt des Dokuments hier..."
                />
              </div>
            </div>
            <div className="flex gap-3">
              <button 
                onClick={() => setShowDocModal(false)}
                className="flex-1 px-6 py-3 bg-gray-100 hover:bg-gray-200 rounded-xl font-medium transition-colors"
              >
                Abbrechen
              </button>
              <button 
                onClick={handleAddDoc}
                className="flex-1 px-6 py-3 bg-black text-white hover:bg-gray-900 rounded-xl font-medium transition-colors"
              >
                Hinzufügen
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

