import React, { useState, useEffect } from 'react';
import { View, ChatSession, Document, Decision, Role } from './types';
import { INITIAL_DOCUMENTS, INITIAL_DECISIONS } from './constants';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import { MenuIcon, CloseIcon } from './components/Icons';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [documents, setDocuments] = useState<Document[]>(INITIAL_DOCUMENTS);
  const [decisions, setDecisions] = useState<Decision[]>(INITIAL_DECISIONS);
  const [isLoading, setIsLoading] = useState(false);
  const [adminTab, setAdminTab] = useState<'docs' | 'decisions'>('docs');

  // Load current session messages
  const currentSession = sessions.find(s => s.id === currentSessionId);
  const messages = currentSession?.messages || [];

  const handleSendMessage = async (text: string) => {
    let sid = currentSessionId;
    let updatedSessions = [...sessions];

    if (!sid) {
      sid = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sid,
        title: text.length > 30 ? text.substring(0, 30) + '...' : text,
        messages: [],
        createdAt: new Date().toISOString()
      };
      updatedSessions = [newSession, ...updatedSessions];
      setSessions(updatedSessions);
      setCurrentSessionId(sid);
    }

    // Add user message
    const userMsg = { role: 'user' as const, text };
    const sessionToUpdate = updatedSessions.find(s => s.id === sid);
    if (sessionToUpdate) {
      sessionToUpdate.messages.push(userMsg);
      setSessions([...updatedSessions]);
    }

    setIsLoading(true);
    try {
      const history = sessionToUpdate?.messages.slice(0, -1).map(m => ({ role: m.role, text: m.text })) || [];
      const aiResponse = await gemini.askQuestion(text, documents, decisions, history);

      const modelMsg = { 
        role: 'model' as const, 
        text: aiResponse || "Entschuldigung, ich konnte darauf keine Antwort finden.",
        sources: aiResponse?.match(/\[.*?\]/g)?.map(s => s.replace(/[\[\]]/g, ''))
      };

      if (sessionToUpdate) {
        sessionToUpdate.messages.push(modelMsg);
        setSessions([...updatedSessions]);
      }
    } catch (error) {
      console.error(error);
      if (sessionToUpdate) {
        sessionToUpdate.messages.push({ 
          role: 'model', 
          text: "Ein Fehler ist aufgetreten. Bitte versuche es später noch einmal." 
        });
        setSessions([...updatedSessions]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    switch (view) {
      case 'chat':
        return (
          <ChatView 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            onEnterVoice={() => setView('voice')}
            isLoading={isLoading}
          />
        );
      case 'voice':
        return <VoiceMode onClose={() => setView('chat')} />;
      case 'admin-docs':
      case 'admin-decisions':
        return (
          <AdminPanel 
            documents={documents}
            decisions={decisions}
            onAddDoc={(doc) => setDocuments([doc, ...documents])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onAddDecision={(dec) => setDecisions([dec, ...decisions])}
            activeTab={adminTab}
            setActiveTab={setAdminTab}
          />
        );
      case 'docs-view':
        return (
          <div className="max-w-4xl mx-auto py-10 px-6">
             <h1 className="text-3xl font-bold mb-8">Dokumentenarchiv</h1>
             <div className="space-y-4">
               {documents.map(doc => (
                 <div key={doc.id} className="flex items-center justify-between p-4 bg-white border border-gray-100 rounded-2xl">
                    <div className="flex items-center gap-4">
                      <div className="p-2 bg-gray-50 rounded-lg"><DocIcon className="w-5 h-5 text-gray-400" /></div>
                      <div>
                        <p className="font-medium">{doc.name}</p>
                        <p className="text-xs text-gray-400">{doc.category} • {doc.uploadDate}</p>
                      </div>
                    </div>
                    <button className="text-xs font-semibold text-green-600 hover:bg-green-50 px-3 py-1 rounded-full">Ansehen</button>
                 </div>
               ))}
             </div>
          </div>
        )
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-white flex">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentView={view}
        setView={setView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setView('chat');
        }}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden lg:pl-80">
        <header className="h-16 flex items-center justify-between px-6 border-b border-gray-100 lg:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 -ml-2 hover:bg-gray-100 rounded-full">
            <MenuIcon className="w-6 h-6" />
          </button>
          <span className="font-semibold tracking-tight">CoLivingGuide</span>
          <div className="w-10" /> {/* Spacer */}
        </header>

        <div className="flex-1 overflow-y-auto overflow-x-hidden">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

