import AdminPanel from './components/AdminPanel';
import LoginView from './components/LoginView';
import { MenuIcon, CloseIcon } from './components/Icons';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  // Authentication State
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('clg_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('clg_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [loginError, setLoginError] = useState<string>('');

  // UI State
  const [view, setView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [documents, setDocuments] = useState<Document[]>(INITIAL_DOCUMENTS);
  const [decisions, setDecisions] = useState<Decision[]>(INITIAL_DECISIONS);
  const [isLoading, setIsLoading] = useState(false);
  const [adminTab, setAdminTab] = useState<'docs' | 'decisions' | 'users'>('docs');

  // Persistence
  useEffect(() => {
    localStorage.setItem('clg_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('clg_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('clg_user');
    }
  }, [currentUser]);

  // Auth Handlers
  const handleLogin = (email: string) => {
    const foundUser = users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (foundUser) {
      if (foundUser.status === 'deaktiviert') {
        setLoginError('Dieser Account wurde deaktiviert.');
        return;
      }
      setCurrentUser(foundUser);
      setLoginError('');
    } else {
      setLoginError('Diese E-Mail ist uns nicht bekannt.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setView('chat');
  };

  // User Management
  const handleInviteUser = (email: string, role: Role) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      role,
      status: 'eingeladen',
      invitedAt: new Date().toISOString().split('T')[0]
    };
    setUsers([...users, newUser]);
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  // Load current session messages
  const currentSession = sessions.find(s => s.id === currentSessionId);
  const messages = currentSession?.messages || [];

  const handleSendMessage = async (text: string) => {
    let sid = currentSessionId;
    let updatedSessions = [...sessions];

    if (!sid) {
      sid = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sid,
        title: text.length > 30 ? text.substring(0, 30) + '...' : text,
        messages: [],
        createdAt: new Date().toISOString()
      };
      updatedSessions = [newSession, ...updatedSessions];
      setSessions(updatedSessions);
      setCurrentSessionId(sid);
    }

    // Add user message
    const userMsg = { role: 'user' as const, text };
    const sessionToUpdate = updatedSessions.find(s => s.id === sid);
    if (sessionToUpdate) {
      sessionToUpdate.messages.push(userMsg);
      setSessions([...updatedSessions]);
    }

    setIsLoading(true);
    try {
      const history = sessionToUpdate?.messages.slice(0, -1).map(m => ({ role: m.role, text: m.text })) || [];
      const aiResponse = await gemini.askQuestion(text, documents, decisions, history);

      const modelMsg = { 
        role: 'model' as const, 
        text: aiResponse || "Entschuldigung, ich konnte darauf keine Antwort finden.",
        sources: aiResponse?.match(/\[.*?\]/g)?.map(s => s.replace(/[\[\]]/g, ''))
      };

      if (sessionToUpdate) {
        sessionToUpdate.messages.push(modelMsg);
        setSessions([...updatedSessions]);
      }
    } catch (error) {
      console.error(error);
      if (sessionToUpdate) {
        sessionToUpdate.messages.push({ 
          role: 'model', 
          text: "Ein Fehler ist aufgetreten. Bitte versuche es später noch einmal." 
        });
        setSessions([...updatedSessions]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} error={loginError} />;
  }

  const renderContent = () => {
    switch (view) {
      case 'chat':
        return (
          <ChatView 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            onEnterVoice={() => setView('voice')}
            isLoading={isLoading}
          />
        );
      case 'voice':
        return <VoiceMode onClose={() => setView('chat')} />;
      case 'admin-docs':
      case 'admin-decisions':
      case 'admin-users':
        if (currentUser.role !== Role.ADMIN) {
          setView('chat');
          return null;
        }
        return (
          <AdminPanel 
            documents={documents}
            decisions={decisions}
            users={users}
            onAddDoc={(doc) => setDocuments([doc, ...documents])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onAddDecision={(dec) => setDecisions([dec, ...decisions])}
            onInviteUser={handleInviteUser}
            onRemoveUser={handleRemoveUser}
            activeTab={adminTab}
            setActiveTab={setAdminTab}
          />
        );
      case 'docs-view':
        return (
          <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in slide-in-from-bottom-4">
             <h1 className="text-4xl font-semibold tracking-tight mb-8">Dokumentenarchiv</h1>
             <div className="space-y-3">
               {documents.map(doc => (
                 <div key={doc.id} className="flex items-center justify-between p-5 bg-white border border-gray-100 rounded-3xl hover:shadow-sm transition-all group">
                    <div className="flex items-center gap-4">
                      <div className="p-3 bg-gray-50 rounded-2xl group-hover:bg-green-50 transition-colors">
                        <DocIcon className="w-6 h-6 text-gray-400 group-hover:text-green-600" />
                      </div>
                      <div>
                        <p className="font-semibold text-gray-900">{doc.name}</p>
                        <p className="text-xs text-gray-400 uppercase tracking-wider font-bold">{doc.category} • {doc.uploadDate}</p>
                      </div>
                    </div>
                    <button className="text-xs font-bold text-gray-400 hover:text-black uppercase tracking-widest px-4 py-2 bg-gray-50 rounded-xl transition-all">Öffnen</button>
                 </div>
               ))}
             </div>
          </div>
        )
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-white flex">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentView={view}
        setView={setView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setView('chat');
        }}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden lg:pl-80">
        <header className="h-20 flex items-center justify-between px-6 border-b border-gray-50 bg-white/80 backdrop-blur-xl sticky top-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 -ml-2 hover:bg-gray-100 rounded-full lg:hidden transition-colors">
              <MenuIcon className="w-6 h-6" />
            </button>
            <div className="hidden lg:flex flex-col">
              <span className="font-semibold tracking-tight text-lg">CoLivingGuide</span>
              <span className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">{currentUser.role === Role.ADMIN ? 'Admin Modus' : 'Bewohner Zugang'}</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden sm:flex flex-col items-end">
              <span className="text-sm font-medium text-gray-900">{currentUser.email}</span>
              <button onClick={handleLogout} className="text-[10px] text-gray-400 hover:text-red-500 uppercase tracking-widest font-bold transition-colors">Abmelden</button>
            </div>
            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-sm font-bold ${currentUser.role === Role.ADMIN ? 'bg-black text-white' : 'bg-gray-100 text-gray-600'}`}>
              {currentUser.email.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto overflow-x-hidden bg-[#FAFAFA]/50">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

const DocIcon = ({ className }: { className: string }) => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className={className}>
    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" />
  </svg>
);

export default App;

import React, { useState, useEffect } from 'react';
import { Document, Decision, User, Role } from '../types';
import { PlusIcon, TrashIcon, DocIcon, ArrowRightIcon, CloseIcon, InfoIcon } from './Icons';

interface AdminPanelProps {
  documents: Document[];
  decisions: Decision[];
  users: User[];
  onAddDoc: (doc: Document) => void;
  onRemoveDoc: (id: string) => void;
  onAddDecision: (dec: Decision) => void;
  onInviteUser: (email: string, role: Role) => void;
  onRemoveUser: (id: string) => void;
  activeTab: 'docs' | 'decisions' | 'users';
  setActiveTab: (tab: 'docs' | 'decisions' | 'users') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, decisions, users, onAddDoc, onRemoveDoc, onAddDecision, onInviteUser, onRemoveUser, activeTab, setActiveTab 
}) => {
  const [showDocUpload, setShowDocUpload] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);

  // Upload State
  const [uploadStep, setUploadStep] = useState<'idle' | 'processing' | 'ready'>('idle');
  const [uploadProgress, setUploadProgress] = useState(0);
  const [newDoc, setNewDoc] = useState({ name: '', category: 'Hausordnung' as any, content: '' });
  const [newInvite, setNewInvite] = useState({ email: '', role: Role.USER });

  const handleStartUpload = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.name || !newDoc.content) return;

    setUploadStep('processing');
    setUploadProgress(0);

    // Simulate processing/indexing
    const interval = setInterval(() => {
      setUploadProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setUploadStep('ready');
          return 100;
        }
        return prev + 5;
      });
    }, 50);
  };

  const handleFinalizeDoc = () => {
    onAddDoc({
      id: Math.random().toString(36).substr(2, 9),
      name: newDoc.name,
      category: newDoc.category,
      uploadDate: new Date().toISOString().split('T')[0],
      content: newDoc.content,
      status: 'aktiv'
    });
    resetUpload();
  };

  const resetUpload = () => {
    setShowDocUpload(false);
    setUploadStep('idle');
    setUploadProgress(0);
    setNewDoc({ name: '', category: 'Hausordnung', content: '' });
  };

  const handleInvite = () => {
    if (newInvite.email) {
      onInviteUser(newInvite.email, newInvite.role);
      setShowInviteModal(false);
      setNewInvite({ email: '', role: Role.USER });
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="mb-10">
        <h1 className="text-4xl font-semibold tracking-tight mb-2 text-gray-900">Kuratierte Wahrheit</h1>
        <p className="text-gray-500">Verwalte Dokumente, Beschlüsse und Nutzer für dein Co-Living.</p>
      </header>

      <div className="flex gap-8 border-b border-gray-100 mb-8 overflow-x-auto no-scrollbar">
        {[
          { id: 'docs', label: 'Dokumente' },
          { id: 'decisions', label: 'Beschlüsse' },
          { id: 'users', label: 'Nutzer' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`pb-4 text-sm font-medium transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-black' : 'text-gray-400 hover:text-black'}`}
          >
            {tab.label}
            {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black" />}
          </button>
        ))}
      </div>

      {activeTab === 'docs' && (
        <div className="space-y-6">
          {!showDocUpload ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <button 
                onClick={() => setShowDocUpload(true)}
                className="border-2 border-dashed border-gray-100 rounded-3xl p-8 flex flex-col items-center justify-center text-gray-400 hover:border-black hover:text-black transition-all group min-h-[220px] bg-white hover:bg-gray-50/50"
              >
                <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 group-hover:bg-black transition-all duration-500">
                  <PlusIcon className="w-8 h-8 group-hover:text-white transition-colors" />
                </div>
                <span className="text-sm font-semibold tracking-tight">Neues Dokument hinzufügen</span>
                <span className="text-xs text-gray-300 mt-1">PDF, DOCX oder Text</span>
              </button>
              {documents.map(doc => (
                <div key={doc.id} className="bg-white border border-gray-100 rounded-3xl p-6 shadow-sm group hover:shadow-md transition-all flex flex-col justify-between">
                  <div className="flex items-start justify-between mb-4">
                    <div className="p-3 bg-gray-50 rounded-2xl group-hover:bg-green-50 transition-colors">
                      <DocIcon className="w-6 h-6 text-gray-400 group-hover:text-green-600" />
                    </div>
                    <button onClick={() => onRemoveDoc(doc.id)} className="p-2 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                      <TrashIcon className="w-4 h-4" />
                    </button>
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900 mb-1 truncate">{doc.name}</h3>
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-3">{doc.category} • {doc.uploadDate}</p>
                    <div className="px-2 py-1 bg-green-50 text-green-700 text-[9px] font-black uppercase tracking-widest rounded-md inline-block">
                      {doc.status}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="bg-white border border-gray-100 rounded-[2.5rem] p-10 animate-in zoom-in-95 duration-300 shadow-sm relative">
              <button 
                onClick={resetUpload}
                className="absolute top-6 right-6 p-2 text-gray-300 hover:text-black hover:bg-gray-50 rounded-full transition-all"
              >
                <CloseIcon className="w-5 h-5" />
              </button>

              <div className="max-w-xl mx-auto">
                <div className="text-center mb-10">
                  <div className="w-20 h-20 bg-black rounded-[2rem] mx-auto flex items-center justify-center mb-6 shadow-xl shadow-black/10">
                    <DocIcon className="w-10 h-10 text-white" />
                  </div>
                  <h2 className="text-3xl font-semibold tracking-tight text-gray-900">Dokument indizieren</h2>
                  <p className="text-gray-400 mt-2">Wähle eine Kategorie und füge den Inhalt ein.</p>
                </div>

                {uploadStep === 'idle' && (
                  <form onSubmit={handleStartUpload} className="space-y-6">
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1.5">
                        <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 ml-2">Dateiname</label>
                        <input 
                          type="text" 
                          required
                          value={newDoc.name}
                          onChange={e => setNewDoc({...newDoc, name: e.target.value})}
                          placeholder="z.B. Hausordnung_2024"
                          className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3.5 focus:outline-none focus:ring-2 focus:ring-black/5 transition-all"
                        />
                      </div>
                      <div className="space-y-1.5">
                        <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 ml-2">Kategorie</label>
                        <select 
                          value={newDoc.category}
                          onChange={e => setNewDoc({...newDoc, category: e.target.value as any})}
                          className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3.5 focus:outline-none focus:ring-2 focus:ring-black/5 appearance-none cursor-pointer"
                        >
                          <option>Hausordnung</option>
                          <option>Verträge</option>
                          <option>Protokolle</option>
                          <option>Leitlinien</option>
                          <option>How-tos</option>
                        </select>
                      </div>
                    </div>

                    <div className="space-y-1.5">
                      <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 ml-2">Inhalt (Text aus PDF/Doc)</label>
                      <textarea 
                        required
                        value={newDoc.content}
                        onChange={e => setNewDoc({...newDoc, content: e.target.value})}
                        placeholder="Kopiere den Text aus dem Dokument hier hinein..."
                        className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-5 py-4 min-h-[160px] focus:outline-none focus:ring-2 focus:ring-black/5 transition-all text-sm leading-relaxed"
                      />
                    </div>

                    <button 
                      type="submit"
                      className="w-full bg-black text-white rounded-2xl py-4 font-semibold text-lg hover:bg-gray-900 active:scale-[0.98] transition-all shadow-xl shadow-black/5 flex items-center justify-center gap-3"
                    >
                      <span>Verarbeiten & Hochladen</span>
                      <ArrowRightIcon className="w-5 h-5" />
                    </button>
                  </form>
                )}

                {uploadStep === 'processing' && (
                  <div className="py-12 flex flex-col items-center text-center animate-in fade-in zoom-in-95">
                    <div className="w-full max-w-sm bg-gray-50 h-3 rounded-full overflow-hidden mb-6">
                      <div 
                        className="h-full bg-black transition-all duration-300 ease-out"
                        style={{ width: `${uploadProgress}%` }}
                      />
                    </div>
                    <p className="text-xl font-medium text-gray-900">Analysiere Dokument...</p>
                    <p className="text-gray-400 mt-1">KI bereitet Inhalte für Abfragen vor ({uploadProgress}%)</p>
                  </div>
                )}

                {uploadStep === 'ready' && (
                  <div className="animate-in fade-in slide-in-from-bottom-4">
                    <div className="bg-green-50 border border-green-100 rounded-3xl p-6 mb-8 flex items-center gap-5">
                      <div className="w-12 h-12 bg-green-500 rounded-2xl flex items-center justify-center shrink-0 shadow-lg shadow-green-200">
                        <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="3">
                          <polyline points="20 6 9 17 4 12" />
                        </svg>
                      </div>
                      <div>
                        <h4 className="font-semibold text-green-900">Verarbeitung abgeschlossen</h4>
                        <p className="text-sm text-green-700/70">"{newDoc.name}" ist bereit für die Veröffentlichung.</p>
                      </div>
                    </div>

                    <div className="flex gap-4">
                      <button 
                        onClick={resetUpload}
                        className="flex-1 px-6 py-4 bg-gray-100 hover:bg-gray-200 rounded-2xl font-semibold transition-colors text-gray-600"
                      >
                        Verwerfen
                      </button>
                      <button 
                        onClick={handleFinalizeDoc}
                        className="flex-1 px-6 py-4 bg-black text-white hover:bg-gray-900 rounded-2xl font-semibold transition-all shadow-xl shadow-black/5"
                      >
                        Veröffentlichen
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'decisions' && (
        <div className="space-y-4">
          {decisions.map(dec => (
            <div key={dec.id} className="bg-white border border-gray-100 rounded-3xl p-6 shadow-sm">
              <div className="flex justify-between items-start mb-2">
                <h3 className="text-lg font-semibold">{dec.title}</h3>
                <span className="text-xs text-gray-400">{dec.date}</span>
              </div>
              <p className="text-sm text-gray-600 mb-4">{dec.reason}</p>
              <div className="flex items-center gap-3 text-xs text-gray-400">
                <span className="px-2 py-1 bg-gray-50 rounded-md">Von: {dec.decidedBy}</span>
                <span className="px-2 py-1 bg-gray-50 rounded-md">Quelle: {dec.source}</span>
              </div>
            </div>
          ))}
          <button className="w-full border-2 border-dashed border-gray-100 rounded-3xl p-6 text-gray-400 hover:border-black hover:text-black transition-all flex items-center justify-center gap-2">
            <PlusIcon className="w-5 h-5" />
            <span>Beschluss hinzufügen</span>
          </button>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="space-y-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-semibold text-gray-900">Aktive Bewohner & Admins</h2>
            <button 
              onClick={() => setShowInviteModal(true)}
              className="flex items-center gap-2 px-5 py-2.5 bg-black text-white rounded-2xl hover:bg-gray-900 transition-all active:scale-95 shadow-lg shadow-black/5"
            >
              <PlusIcon className="w-4 h-4" />
              <span>Einladen</span>
            </button>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {users.map(user => (
              <div key={user.id} className="bg-white border border-gray-100 rounded-3xl p-5 flex items-center justify-between group hover:shadow-sm transition-all">
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-medium ${user.role === Role.ADMIN ? 'bg-black text-white' : 'bg-gray-100 text-gray-600'}`}>
                    {user.email.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <p className="font-semibold text-gray-900">{user.email}</p>
                    <p className="text-xs text-gray-400 uppercase tracking-wider font-bold">
                      {user.role === Role.ADMIN ? 'Administrator' : 'Bewohner'} • {user.status}
                    </p>
                  </div>
                </div>
                <button 
                  onClick={() => onRemoveUser(user.id)}
                  className="p-3 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all rounded-full hover:bg-red-50"
                >
                  <TrashIcon className="w-5 h-5" />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Invite Modal */}
      {showInviteModal && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[200] flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl w-full max-w-sm p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-bold mb-2">Nutzer einladen</h2>
            <p className="text-gray-500 mb-6 text-sm">Eingeladene Personen können sich mit ihrer E-Mail anmelden.</p>

            <div className="space-y-4 mb-8">
              <div>
                <label className="block text-sm font-medium text-gray-400 mb-1 uppercase tracking-wider text-[10px]">E-Mail Adresse</label>
                <input 
                  type="email" 
                  value={newInvite.email}
                  onChange={e => setNewInvite({...newInvite, email: e.target.value})}
                  className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-black/5"
                  placeholder="name@email.com"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-400 mb-1 uppercase tracking-wider text-[10px]">Rolle</label>
                <div className="grid grid-cols-2 gap-2">
                  <button 
