export const SYSTEM_INSTRUCTION = `
Du bist der CoLivingGuide, ein freundlicher und hilfreicher Assistent für eine Wohngemeinschaft.
Beantworte Fragen der Bewohner ausschließlich basierend auf den bereitgestellten Dokumenten und Beschlüssen.

REGELN:
1. Antworte in einfachem, klarem Deutsch.
2. Sei erklärend und orientierungsorientiert.
3. Extrahiere für jede Aussage relevante Textabschnitte (Paragraphen) aus den Dokumenten als Zitate.
4. Gib deine Antwort IMMER im JSON-Format zurück, das ein 'answer' Feld (deine Erklärung) und ein 'citations' Feld (Array von Objekten mit 'source' und 'text') enthält.
5. Wenn keine Information vorliegt, erkläre dies höflich und lass das 'citations' Array leer.
6. Du bist KEINE Rechtsberatung.

BEISPIEL AUSGABE:
{
  "answer": "Gäste dürfen bei uns bis zu zwei Wochen bleiben.",
  "citations": [
    { "source": "Hausordnung 2024", "text": "Gäste dürfen maximal 2 Wochen am Stück bleiben." }
  ]
}
`;

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Decision, Citation } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async askQuestion(
    question: string, 
    documents: Document[], 
    decisions: Decision[],
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    const context = `
Hier sind die aktuellen Hausdokumente:
${documents.map(d => `[DOKUMENT: ${d.name}] Content: ${d.content}`).join('\n')}

Hier sind die aktuellen Beschlüsse:
${decisions.map(d => `[BESCHLUSS: ${d.title}] Datum: ${d.date}, Wer: ${d.decidedBy}, Grund: ${d.reason}`).join('\n')}
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `${context}\n\nFrage: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.2,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { 
                type: Type.STRING,
                description: "Die hilfreiche Antwort für den Nutzer."
              },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING },
                    text: { type: Type.STRING }
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const data = JSON.parse(response.text || '{}');
      return {
        text: data.answer || "Entschuldigung, ich konnte die Antwort nicht richtig formatieren.",
        citations: data.citations || []
      };
    } catch (error) {
      console.error("Gemini API Error:", error);
      return {
        text: "Es gab ein Problem bei der Kommunikation mit der KI. Bitte versuche es später erneut.",
        citations: []
      };
    }
  }
}

export const gemini = new GeminiService();

