import React, { useState, useEffect } from 'react';
import { View, ChatSession, Document, Decision, Role, User, Message } from './types';
import { INITIAL_DOCUMENTS, INITIAL_DECISIONS, INITIAL_USERS } from './constants';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import LoginView from './components/LoginView';
import { MenuIcon, CloseIcon, DocIcon } from './components/Icons';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  // Authentication State
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('clg_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('clg_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [loginError, setLoginError] = useState<string>('');

  // UI State
  const [view, setView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [documents, setDocuments] = useState<Document[]>(() => {
    const saved = localStorage.getItem('clg_docs');
    return saved ? JSON.parse(saved) : INITIAL_DOCUMENTS;
  });
  const [decisions, setDecisions] = useState<Decision[]>(INITIAL_DECISIONS);
  const [isLoading, setIsLoading] = useState(false);
  const [adminTab, setAdminTab] = useState<'docs' | 'decisions' | 'users'>('docs');
  const [viewingDoc, setViewingDoc] = useState<Document | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('clg_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('clg_docs', JSON.stringify(documents));
  }, [documents]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('clg_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('clg_user');
    }
  }, [currentUser]);

  // Auth Handlers
  const handleLogin = (email: string) => {
    const foundUser = users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (foundUser) {
      if (foundUser.status === 'deaktiviert') {
        setLoginError('Dieser Account wurde deaktiviert.');
        return;
      }
      setCurrentUser(foundUser);
      setLoginError('');
    } else {
      setLoginError('Diese E-Mail ist uns nicht bekannt.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setView('chat');
  };

  // User Management
  const handleInviteUser = (email: string, role: Role) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      role,
      status: 'eingeladen',
      invitedAt: new Date().toISOString().split('T')[0]
    };
    setUsers([...users, newUser]);
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  const handleViewDocumentByName = (name: string) => {
    const cleanName = name.replace(/^\[DOKUMENT:\s*/, '').replace(/\]$/, '').trim();
    const doc = documents.find(d => d.name.toLowerCase().includes(cleanName.toLowerCase()) || cleanName.toLowerCase().includes(d.name.toLowerCase()));
    if (doc) setViewingDoc(doc);
  };

  // Load current session messages
  const currentSession = sessions.find(s => s.id === currentSessionId);
  const messages = currentSession?.messages || [];

  const handleSendMessage = async (text: string) => {
    let sid = currentSessionId;
    let updatedSessions = [...sessions];

    if (!sid) {
      sid = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sid,
        title: text.length > 30 ? text.substring(0, 30) + '...' : text,
        messages: [],
        createdAt: new Date().toISOString()
      };
      updatedSessions = [newSession, ...updatedSessions];
      setSessions(updatedSessions);
      setCurrentSessionId(sid);
    }

    const userMsg: Message = { role: 'user', text };
    const sessionToUpdate = updatedSessions.find(s => s.id === sid);
    if (sessionToUpdate) {
      sessionToUpdate.messages.push(userMsg);
      setSessions([...updatedSessions]);
    }

    setIsLoading(true);
    try {
      const history = sessionToUpdate?.messages.slice(0, -1).map(m => ({ role: m.role, text: m.text })) || [];
      const aiResult = await gemini.askQuestion(text, documents, decisions, history);

      const modelMsg: Message = { 
        role: 'model', 
        text: aiResult.text,
        citations: aiResult.citations
      };

      if (sessionToUpdate) {
        sessionToUpdate.messages.push(modelMsg);
        setSessions([...updatedSessions]);
      }
    } catch (error) {
      console.error(error);
      if (sessionToUpdate) {
        sessionToUpdate.messages.push({ 
          role: 'model', 
          text: "Ein Fehler ist aufgetreten. Bitte versuche es später noch einmal." 
        });
        setSessions([...updatedSessions]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} error={loginError} />;
  }

  const renderContent = () => {
    switch (view) {
      case 'chat':
        return (
          <ChatView 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            onEnterVoice={() => setView('voice')}
            onViewDocument={handleViewDocumentByName}
            isLoading={isLoading}
          />
        );
      case 'voice':
        return <VoiceMode onClose={() => setView('chat')} />;
      case 'admin-docs':
      case 'admin-decisions':
      case 'admin-users':
        if (currentUser.role !== Role.ADMIN) {
          setView('chat');
          return null;
        }
        return (
          <AdminPanel 
            documents={documents}
            decisions={decisions}
            users={users}
            onAddDoc={(doc) => setDocuments([doc, ...documents])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onAddDecision={(dec) => setDecisions([dec, ...decisions])}
            onInviteUser={handleInviteUser}
            onRemoveUser={handleRemoveUser}
            activeTab={adminTab}
            setActiveTab={setAdminTab}
          />
        );
      case 'docs-view':
        return (
          <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in slide-in-from-bottom-4">
             <h1 className="text-4xl font-semibold tracking-tight mb-8">Dokumentenarchiv</h1>
             <div className="grid grid-cols-1 gap-3">
               {documents.map(doc => (
                 <div key={doc.id} className="flex items-center justify-between p-5 bg-white border border-gray-100 rounded-3xl hover:shadow-sm transition-all group">
                    <div className="flex items-center gap-4">
                      <div className="p-3 bg-gray-50 rounded-2xl group-hover:bg-green-50 transition-colors">
                        <DocIcon className="w-6 h-6 text-gray-400 group-hover:text-green-600" />
                      </div>
                      <div>
                        <p className="font-semibold text-gray-900">{doc.name}</p>
                        <p className="text-xs text-gray-400 uppercase tracking-wider font-bold">{doc.category} • {doc.uploadDate}</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => setViewingDoc(doc)}
                      className="text-xs font-bold text-gray-400 hover:text-black uppercase tracking-widest px-4 py-2 bg-gray-50 rounded-xl transition-all"
                    >
                      Öffnen
                    </button>
                 </div>
               ))}
             </div>
          </div>
        )
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-white flex">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentView={view}
        setView={setView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setView('chat');
        }}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden lg:pl-80">
        <header className="h-20 flex items-center justify-between px-6 border-b border-gray-50 bg-white/80 backdrop-blur-xl sticky top-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 -ml-2 hover:bg-gray-100 rounded-full lg:hidden transition-colors">
              <MenuIcon className="w-6 h-6" />
            </button>
            <div className="hidden lg:flex flex-col">
              <span className="font-semibold tracking-tight text-lg">CoLivingGuide</span>
              <span className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">{currentUser.role === Role.ADMIN ? 'Admin Modus' : 'Bewohner Zugang'}</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden sm:flex flex-col items-end">
              <span className="text-sm font-medium text-gray-900">{currentUser.email}</span>
              <button onClick={handleLogout} className="text-[10px] text-gray-400 hover:text-red-500 uppercase tracking-widest font-bold transition-colors">Abmelden</button>
            </div>
            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-sm font-bold ${currentUser.role === Role.ADMIN ? 'bg-black text-white' : 'bg-gray-100 text-gray-600'}`}>
              {currentUser.email.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto overflow-x-hidden bg-[#FAFAFA]/50">
          {renderContent()}
        </div>
      </main>

      {/* Document Viewer Modal */}
      {viewingDoc && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-md flex items-center justify-center p-4 sm:p-10 animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-5xl h-full rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl relative">
            <button 
              onClick={() => setViewingDoc(null)}
              className="absolute top-6 right-6 z-10 p-3 bg-white/80 backdrop-blur shadow-sm rounded-full hover:bg-black hover:text-white transition-all group"
            >
              <CloseIcon className="w-6 h-6" />
            </button>

            <div className="h-20 border-b border-gray-100 px-8 flex items-center gap-4 shrink-0 bg-white/50 backdrop-blur">
              <div className="p-2 bg-black rounded-xl">
                <DocIcon className="w-5 h-5 text-white" />
              </div>
              <div>
                <h2 className="font-bold text-xl truncate max-w-md">{viewingDoc.name}</h2>
                <p className="text-[10px] uppercase tracking-widest font-black text-gray-400">{viewingDoc.category}</p>
              </div>
            </div>

            <div className="flex-1 bg-gray-100/50 flex flex-col">
              {viewingDoc.fileUrl ? (
                <iframe 
                  src={viewingDoc.fileUrl} 
                  className="w-full h-full border-none"
                  title={viewingDoc.name}
                />
              ) : (
                <div className="flex-1 overflow-y-auto p-12 flex justify-center">
                  <div className="max-w-2xl w-full bg-white p-12 shadow-sm rounded-3xl min-h-[1000px]">
                    <div className="prose prose-sm max-w-none">
                      <p className="whitespace-pre-wrap leading-relaxed text-gray-700 font-serif text-lg">
                        {viewingDoc.content}
                      </p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Decision, Citation } from "../types";

export class GeminiService {
  async askQuestion(
    question: string, 
    documents: Document[], 
    decisions: Decision[],
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    // Late initialization to ensure we always have the latest API key context
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const context = `
Hier sind die aktuellen Hausdokumente als Wissensbasis:
${documents.map(d => `[DOKUMENT ID: ${d.id} NAME: ${d.name}]
Inhalt: ${d.content}`).join('\n\n')}

Hier sind die aktuellen Beschlüsse:
${decisions.map(d => `[BESCHLUSS: ${d.title}] Datum: ${d.date}, Wer: ${d.decidedBy}, Grund: ${d.reason}`).join('\n')}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `${context}\n\nFrage des Bewohners: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.1, // Low temperature for factual accuracy
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { 
                type: Type.STRING,
                description: "Die hilfreiche, erklärende Antwort in einfachem Deutsch."
              },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING, description: "Der Name des Originaldokuments." },
                    text: { type: Type.STRING, description: "Der exakte Textabschnitt aus dem Dokument." },
                    documentId: { type: Type.STRING, description: "Die ID des Dokuments falls bekannt." }
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const text = response.text;
      if (!text) throw new Error("Empty response from AI");

      const data = JSON.parse(text);
      return {
        text: data.answer || "Ich konnte leider keine Information dazu finden.",
        citations: data.citations || []
      };
    } catch (error) {
      console.error("Gemini API Error:", error);
      return {
        text: "Es gab ein technisches Problem beim Zugriff auf das Hauswissen. Bitte versuche es gleich noch einmal.",
        citations: []
      };
    }
  }
}

