              <div className="w-1.5 h-1.5 bg-blue-500 rounded-full" />
              <span className="text-[10px] text-gray-400 uppercase tracking-[0.15em] font-bold">Privat</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-purple-500 rounded-full" />
              <span className="text-[10px] text-gray-400 uppercase tracking-[0.15em] font-bold">KI-Unterstützt</span>
            </div>
