import React, { useState, useEffect } from 'react';
import { View, ChatSession, Document, Decision, Role, User, Message } from './types';
import { INITIAL_DOCUMENTS, INITIAL_DECISIONS, INITIAL_USERS } from './constants';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import LoginView from './components/LoginView';
import { MenuIcon, CloseIcon, DocIcon } from './components/Icons';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  // Authentication State
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('clg_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('clg_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [loginError, setLoginError] = useState<string>('');

  // UI State
  const [view, setView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [documents, setDocuments] = useState<Document[]>(() => {
    const saved = localStorage.getItem('clg_docs');
    return saved ? JSON.parse(saved) : INITIAL_DOCUMENTS;
  });
  const [decisions, setDecisions] = useState<Decision[]>(INITIAL_DECISIONS);
  const [isLoading, setIsLoading] = useState(false);
  const [adminTab, setAdminTab] = useState<'docs' | 'decisions' | 'users'>('docs');
  const [viewingDoc, setViewingDoc] = useState<Document | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('clg_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('clg_docs', JSON.stringify(documents));
  }, [documents]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('clg_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('clg_user');
    }
  }, [currentUser]);

  // Auth Handlers
  const handleLogin = (email: string) => {
    const foundUser = users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (foundUser) {
      if (foundUser.status === 'deaktiviert') {
        setLoginError('Dieser Account wurde deaktiviert.');
        return;
      }
      setCurrentUser(foundUser);
      setLoginError('');
    } else {
      setLoginError('Diese E-Mail ist uns nicht bekannt.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setView('chat');
  };

  // User Management
  const handleInviteUser = (email: string, role: Role) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      role,
      status: 'eingeladen',
      invitedAt: new Date().toISOString().split('T')[0]
    };
    setUsers([...users, newUser]);
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  const handleViewDocumentByName = (name: string) => {
    // Robust matching logic to find documents even with loose naming from AI
    const cleanName = name
      .replace(/^\[DOKUMENT:\s*/i, '')
      .replace(/\]$/i, '')
      .replace(/\.pdf$/i, '')
      .trim()
      .toLowerCase();

    const doc = documents.find(d => {
      const docName = d.name.toLowerCase();
      return docName.includes(cleanName) || cleanName.includes(docName.replace(/\.pdf$/i, ''));
    });

    if (doc) {
      setViewingDoc(doc);
    } else {
      console.warn(`Could not find document for source: ${name}`);
    }
  };

  // Load current session messages
  const currentSession = sessions.find(s => s.id === currentSessionId);
  const messages = currentSession?.messages || [];

  const handleSendMessage = async (text: string) => {
    let sid = currentSessionId;
    let updatedSessions = [...sessions];

    if (!sid) {
      sid = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sid,
        title: text.length > 30 ? text.substring(0, 30) + '...' : text,
        messages: [],
        createdAt: new Date().toISOString()
      };
      updatedSessions = [newSession, ...updatedSessions];
      setSessions(updatedSessions);
      setCurrentSessionId(sid);
    }

    const userMsg: Message = { role: 'user', text };
    const sessionToUpdate = updatedSessions.find(s => s.id === sid);
    if (sessionToUpdate) {
      sessionToUpdate.messages.push(userMsg);
      setSessions([...updatedSessions]);
    }

    setIsLoading(true);
    try {
      const history = sessionToUpdate?.messages.slice(0, -1).map(m => ({ role: m.role, text: m.text })) || [];
      const aiResult = await gemini.askQuestion(text, documents, decisions, history);

      const modelMsg: Message = { 
        role: 'model', 
        text: aiResult.text,
        citations: aiResult.citations
      };

      if (sessionToUpdate) {
        sessionToUpdate.messages.push(modelMsg);
        setSessions([...updatedSessions]);
      }
    } catch (error) {
      console.error(error);
      if (sessionToUpdate) {
        sessionToUpdate.messages.push({ 
          role: 'model', 
          text: "Ein Fehler ist aufgetreten. Bitte versuche es später noch einmal." 
        });
        setSessions([...updatedSessions]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} error={loginError} />;
  }

  const renderContent = () => {
    switch (view) {
      case 'chat':
        return (
          <ChatView 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            onEnterVoice={() => setView('voice')}
            onViewDocument={handleViewDocumentByName}
            isLoading={isLoading}
          />
        );
      case 'voice':
        return <VoiceMode onClose={() => setView('chat')} />;
      case 'admin-docs':
      case 'admin-decisions':
      case 'admin-users':
        if (currentUser.role !== Role.ADMIN) {
          setView('chat');
          return null;
        }
        return (
          <AdminPanel 
            documents={documents}
            decisions={decisions}
            users={users}
            onAddDoc={(doc) => setDocuments([doc, ...documents])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onAddDecision={(dec) => setDecisions([dec, ...decisions])}
            onInviteUser={handleInviteUser}
            onRemoveUser={handleRemoveUser}
            activeTab={adminTab}
            setActiveTab={setAdminTab}
          />
        );
      case 'docs-view':
        return (
          <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in slide-in-from-bottom-4">
             <header className="mb-10">
               <h1 className="text-4xl font-semibold tracking-tight mb-2 text-gray-900 text-center lg:text-left">Dokumentenarchiv</h1>
               <p className="text-gray-400 text-center lg:text-left leading-relaxed">Alle Verträge und Hausordnungen an einem sicheren Ort.</p>
             </header>
             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               {documents.map(doc => (
                 <div key={doc.id} className="flex flex-col p-6 bg-white border border-gray-100 rounded-[2rem] hover:shadow-xl hover:border-black transition-all group relative overflow-hidden">
                    <div className="flex items-start justify-between mb-6">
                      <div className="p-4 bg-gray-50 rounded-2xl group-hover:bg-green-50 transition-colors">
                        <DocIcon className="w-8 h-8 text-gray-400 group-hover:text-green-600" />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-gray-300 group-hover:text-gray-900 transition-colors">{doc.uploadDate}</span>
                    </div>
                    <div>
                      <p className="font-bold text-lg text-gray-900 mb-1 truncate">{doc.name}</p>
                      <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] font-black mb-6">{doc.category}</p>
                    </div>
                    <button 
                      onClick={() => setViewingDoc(doc)}
                      className="mt-auto w-full py-3 bg-gray-50 hover:bg-black hover:text-white text-gray-500 font-bold text-xs uppercase tracking-widest rounded-xl transition-all"
                    >
                      Dokument öffnen
                    </button>
                 </div>
               ))}
             </div>
          </div>
        )
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-white flex">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentView={view}
        setView={setView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setView('chat');
        }}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden lg:pl-80">
        <header className="h-20 flex items-center justify-between px-6 border-b border-gray-50 bg-white/80 backdrop-blur-xl sticky top-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 -ml-2 hover:bg-gray-100 rounded-full lg:hidden transition-colors">
              <MenuIcon className="w-6 h-6" />
            </button>
            <div className="hidden lg:flex flex-col">
              <span className="font-semibold tracking-tight text-lg text-gray-900">CoLivingGuide</span>
              <span className="text-[10px] text-gray-400 uppercase tracking-widest font-black leading-none mt-0.5">{currentUser.role === Role.ADMIN ? 'Admin Modus' : 'Bewohner Zugang'}</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden sm:flex flex-col items-end">
              <span className="text-sm font-bold text-gray-900">{currentUser.email}</span>
              <button onClick={handleLogout} className="text-[10px] text-gray-400 hover:text-red-500 uppercase tracking-widest font-black transition-colors">Abmelden</button>
            </div>
            <div className={`w-11 h-11 rounded-2xl flex items-center justify-center text-sm font-bold shadow-sm ${currentUser.role === Role.ADMIN ? 'bg-black text-white' : 'bg-gray-100 text-gray-600'}`}>
              {currentUser.email.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto overflow-x-hidden bg-[#FAFAFA]/50 scroll-smooth">
          {renderContent()}
        </div>
      </main>

      {/* Document Viewer Modal */}
      {viewingDoc && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-md flex items-center justify-center p-4 sm:p-10 animate-in fade-in duration-500">
          <div className="bg-white w-full max-w-5xl h-full rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl relative animate-in zoom-in-95 duration-300">
            <button 
              onClick={() => setViewingDoc(null)}
              className="absolute top-6 right-6 z-10 p-4 bg-white/80 backdrop-blur shadow-xl rounded-full hover:bg-black hover:text-white transition-all group active:scale-90"
            >
              <CloseIcon className="w-6 h-6" />
            </button>

            <div className="h-24 border-b border-gray-100 px-10 flex items-center gap-6 shrink-0 bg-white/50 backdrop-blur">
              <div className="p-4 bg-black rounded-[1.2rem] shadow-xl shadow-black/10">
                <DocIcon className="w-6 h-6 text-white" />
              </div>
              <div>
                <h2 className="font-bold text-2xl text-gray-900 truncate max-w-md">{viewingDoc.name}</h2>
                <div className="flex items-center gap-3">
                  <span className="text-[10px] uppercase tracking-widest font-black text-gray-400 bg-gray-50 px-2 py-1 rounded">{viewingDoc.category}</span>
                  <span className="text-[10px] uppercase tracking-widest font-black text-green-600 bg-green-50 px-2 py-1 rounded">Verifiziert</span>
                </div>
              </div>
            </div>

            <div className="flex-1 bg-gray-50 flex flex-col overflow-hidden">
              {viewingDoc.fileUrl ? (
                <iframe 
                  src={viewingDoc.fileUrl} 
                  className="w-full h-full border-none"
                  title={viewingDoc.name}
                />
              ) : (
                <div className="flex-1 overflow-y-auto p-8 sm:p-16 flex justify-center">
                  <div className="max-w-3xl w-full bg-white p-12 sm:p-20 shadow-sm rounded-[3rem] min-h-screen">
                    <div className="prose prose-lg max-w-none">
                      <p className="whitespace-pre-wrap leading-relaxed text-gray-700 font-serif text-xl selection:bg-black selection:text-white">
                        {viewingDoc.content}
                      </p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Document, Decision, User, Role } from '../types';
import { PlusIcon, TrashIcon, DocIcon, ArrowRightIcon, CloseIcon } from './Icons';

// Use pdfjs-dist from esm.sh for client-side PDF text extraction
import * as pdfjsLib from 'https://esm.sh/pdfjs-dist@4.10.38';

// Set worker source
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.10.38/build/pdf.worker.mjs`;

interface AdminPanelProps {
  documents: Document[];
  decisions: Decision[];
  users: User[];
  onAddDoc: (doc: Document) => void;
  onRemoveDoc: (id: string) => void;
  onAddDecision: (dec: Decision) => void;
  onInviteUser: (email: string, role: Role) => void;
  onRemoveUser: (id: string) => void;
  activeTab: 'docs' | 'decisions' | 'users';
  setActiveTab: (tab: 'docs' | 'decisions' | 'users') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, decisions, users, onAddDoc, onRemoveDoc, onAddDecision, onInviteUser, onRemoveUser, activeTab, setActiveTab 
}) => {
  const [showDocUpload, setShowDocUpload] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Upload State
  const [uploadStep, setUploadStep] = useState<'idle' | 'processing' | 'ready'>('idle');
  const [uploadProgress, setUploadProgress] = useState(0);
  const [newDoc, setNewDoc] = useState<{ name: string; category: any; content: string; fileUrl?: string; file?: File }>({ name: '', category: 'Hausordnung', content: '' });
  const [newInvite, setNewInvite] = useState({ email: '', role: Role.USER });
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setError(null);
      const reader = new FileReader();
      reader.onload = (event) => {
        setNewDoc(prev => ({ 
          ...prev, 
          name: file.name.replace(/\.[^/.]+$/, ""), // Default name without extension
          fileUrl: event.target?.result as string,
          file: file
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const extractTextFromPDF = async (file: File) => {
    try {
      const arrayBuffer = await file.arrayBuffer();
      const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
      const pdf = await loadingTask.promise;
      let fullText = '';

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const textContent = await page.getTextContent();
        const pageText = textContent.items
          .map((item: any) => item.str)
          .join(' ');
        fullText += pageText + '\n';
        setUploadProgress(Math.floor((i / pdf.numPages) * 100));
      }

      return fullText.trim();
    } catch (err) {
      console.error("PDF Extraction Error:", err);
      throw new Error("Text konnte nicht aus der PDF extrahiert werden.");
    }
  };

  const handleStartUpload = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.file) {
      setError("Bitte wähle eine PDF-Datei aus.");
      return;
    }

    setUploadStep('processing');
    setUploadProgress(0);
    setError(null);

    try {
      let content = '';
      if (newDoc.file.type === 'application/pdf') {
        content = await extractTextFromPDF(newDoc.file);
      } else {
        content = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsText(newDoc.file!);
        });
      }

      if (!content || content.length < 10) {
        throw new Error("Das Dokument scheint leer zu sein oder der Text konnte nicht gelesen werden.");
      }

      setNewDoc(prev => ({ ...prev, content }));
      setUploadStep('ready');
      setUploadProgress(100);
    } catch (err: any) {
      setError(err.message || "Fehler beim Verarbeiten der Datei.");
      setUploadStep('idle');
    }
  };

  const handleFinalizeDoc = () => {
    onAddDoc({
      id: Math.random().toString(36).substr(2, 9),
      name: newDoc.name,
      category: newDoc.category,
      uploadDate: new Date().toISOString().split('T')[0],
      content: newDoc.content,
      status: 'aktiv',
      fileUrl: newDoc.fileUrl
    });
    resetUpload();
  };

  const resetUpload = () => {
    setShowDocUpload(false);
    setUploadStep('idle');
    setUploadProgress(0);
    setNewDoc({ name: '', category: 'Hausordnung', content: '' });
    setError(null);
  };

  const handleInvite = () => {
    if (newInvite.email) {
      onInviteUser(newInvite.email, newInvite.role);
      setShowInviteModal(false);
      setNewInvite({ email: '', role: Role.USER });
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="mb-10">
        <h1 className="text-4xl font-semibold tracking-tight mb-2 text-gray-900">Kuratierte Wahrheit</h1>
        <p className="text-gray-500">Verwalte Dokumente, Beschlüsse und Nutzer für dein Co-Living.</p>
      </header>

      <div className="flex gap-8 border-b border-gray-100 mb-8 overflow-x-auto no-scrollbar">
        {[
          { id: 'docs', label: 'Dokumente' },
          { id: 'decisions', label: 'Beschlüsse' },
          { id: 'users', label: 'Nutzer' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`pb-4 text-sm font-medium transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-black' : 'text-gray-400 hover:text-black'}`}
          >
            {tab.label}
            {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black" />}
          </button>
        ))}
      </div>

      {activeTab === 'docs' && (
        <div className="space-y-6">
          {!showDocUpload ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <button 
                onClick={() => setShowDocUpload(true)}
                className="border-2 border-dashed border-gray-100 rounded-3xl p-8 flex flex-col items-center justify-center text-gray-400 hover:border-black hover:text-black transition-all group min-h-[220px] bg-white hover:bg-gray-50/50"
              >
                <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 group-hover:bg-black transition-all duration-500">
                  <PlusIcon className="w-8 h-8 group-hover:text-white transition-colors" />
                </div>
                <span className="text-sm font-semibold tracking-tight">Neues Dokument hinzufügen</span>
                <span className="text-xs text-gray-300 mt-1">PDF hochladen & automatisch indizieren</span>
              </button>
              {documents.map(doc => (
                <div key={doc.id} className="bg-white border border-gray-100 rounded-3xl p-6 shadow-sm group hover:shadow-md transition-all flex flex-col justify-between">
                  <div className="flex items-start justify-between mb-4">
                    <div className="p-3 bg-gray-50 rounded-2xl group-hover:bg-green-50 transition-colors">
                      <DocIcon className="w-6 h-6 text-gray-400 group-hover:text-green-600" />
                    </div>
                    <button onClick={() => onRemoveDoc(doc.id)} className="p-2 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                      <TrashIcon className="w-4 h-4" />
                    </button>
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900 mb-1 truncate">{doc.name}</h3>
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-3">{doc.category} • {doc.uploadDate}</p>
                    <div className="px-2 py-1 bg-green-50 text-green-700 text-[9px] font-black uppercase tracking-widest rounded-md inline-block">
                      {doc.status}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="bg-white border border-gray-100 rounded-[2.5rem] p-10 animate-in zoom-in-95 duration-300 shadow-sm relative">
              <button 
                onClick={resetUpload}
                className="absolute top-6 right-6 p-2 text-gray-300 hover:text-black hover:bg-gray-50 rounded-full transition-all"
              >
                <CloseIcon className="w-5 h-5" />
              </button>

              <div className="max-w-xl mx-auto">
                <div className="text-center mb-10">
                  <div className="w-20 h-20 bg-black rounded-[2rem] mx-auto flex items-center justify-center mb-6 shadow-xl shadow-black/10">
                    <DocIcon className="w-10 h-10 text-white" />
                  </div>
                  <h2 className="text-3xl font-semibold tracking-tight text-gray-900">Dokument indizieren</h2>
                  <p className="text-gray-400 mt-2">Lade eine PDF hoch. Die KI extrahiert den Text automatisch.</p>
                </div>

                {uploadStep === 'idle' && (
                  <form onSubmit={handleStartUpload} className="space-y-6">
                    <div 
                      className={`bg-gray-50 border-2 border-dashed ${newDoc.file ? 'border-green-500 bg-green-50/30' : 'border-gray-200'} rounded-3xl p-10 text-center cursor-pointer hover:border-black transition-all group`} 
                      onClick={() => fileInputRef.current?.click()}
                    >
                      <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleFileChange} 
                        className="hidden" 
                        accept=".pdf,.txt" 
                        required
                      />
                      <DocIcon className={`w-12 h-12 ${newDoc.file ? 'text-green-600' : 'text-gray-300'} mx-auto mb-4 group-hover:text-black transition-colors`} />
                      <p className={`text-base font-semibold ${newDoc.file ? 'text-green-900' : 'text-gray-500'} group-hover:text-black transition-colors`}>
                        {newDoc.file ? `${newDoc.file.name}` : 'PDF auswählen'}
                      </p>
                      <p className="text-xs text-gray-400 mt-2">Klicke zum Auswählen oder Drag & Drop</p>
                    </div>

                    {error && (
                      <div className="bg-red-50 border border-red-100 text-red-600 text-sm p-4 rounded-2xl text-center">
                        {error}
                      </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1.5">
                        <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 ml-2">Anzeigename</label>
                        <input 
                          type="text" 
                          required
                          value={newDoc.name}
