import React, { useEffect, useState, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { CloseIcon, MicIcon } from './Icons';
import { Document, Decision } from '../types';

interface VoiceModeProps {
  onClose: () => void;
  documents: Document[];
  decisions: Decision[];
}

const VoiceMode: React.FC<VoiceModeProps> = ({ onClose, documents, decisions }) => {
  const [status, setStatus] = useState<'connecting' | 'active' | 'error' | 'idle'>('connecting');
  const [userTranscript, setUserTranscript] = useState('');
  const [modelTranscript, setModelTranscript] = useState('');

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<{
    input: AudioContext;
    output: AudioContext;
  } | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Helper: Decode Base64
  const decodeBase64 = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  // Helper: Encode to Base64
  const encodeBase64 = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  // Helper: Decode Raw PCM to AudioBuffer
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, sampleRate);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  };

  useEffect(() => {
    let isMounted = true;

    const startSession = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioContextRef.current = { input: inputCtx, output: outputCtx };

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

        const contextString = `
        BASIS-WISSEN FÜR DIESES HAUS:
        Dokumente: ${documents.map(d => `${d.name}: ${d.content}`).join(' | ')}
        Beschlüsse: ${decisions.map(d => `${d.title} (${d.date}): ${d.reason}`).join(' | ')}
        `;

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-09-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
            },
            systemInstruction: `Du bist der CoLivingGuide. Antworte kurz, freundlich und präzise über Sprache. Nutze NUR das folgende Wissen: ${contextString}. Wenn du etwas nicht weißt, sag es offen.`,
            outputAudioTranscription: {},
            inputAudioTranscription: {},
          },
          callbacks: {
            onopen: () => {
              if (!isMounted) return;
              setStatus('active');

              const source = inputCtx.createMediaStreamSource(stream);
              const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) {
                  int16[i] = inputData[i] * 32768;
                }
                const pcmBlob = {
                  data: encodeBase64(new Uint8Array(int16.buffer)),
                  mimeType: 'audio/pcm;rate=16000',
                };

                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(scriptProcessor);
              scriptProcessor.connect(inputCtx.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
              if (!isMounted) return;

              // Handle Transcription
              if (message.serverContent?.inputTranscription) {
                setUserTranscript(prev => prev + ' ' + message.serverContent?.inputTranscription?.text);
              }
              if (message.serverContent?.outputTranscription) {
                setModelTranscript(prev => prev + ' ' + message.serverContent?.outputTranscription?.text);
              }
              if (message.serverContent?.turnComplete) {
                setUserTranscript('');
                setModelTranscript('');
              }

              // Handle Audio Output
              const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
              if (audioData) {
                const buffer = await decodeAudioData(decodeBase64(audioData), outputCtx, 24000);
                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputCtx.destination);

                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
                source.onended = () => sourcesRef.current.delete(source);
              }

              if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
              }
            },
            onerror: (e) => {
              console.error('Live API Error:', e);
              setStatus('error');
            },
            onclose: () => {
              if (isMounted) setStatus('idle');
            }
          }
        });

        sessionRef.current = await sessionPromise;
      } catch (err) {
        console.error('Failed to start voice session:', err);
        setStatus('error');
      }
    };

    startSession();

    return () => {
      isMounted = false;
      if (sessionRef.current) sessionRef.current.close();
      if (audioContextRef.current) {
        audioContextRef.current.input.close();
        audioContextRef.current.output.close();
      }
    };
  }, [documents, decisions]);

  return (
    <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-center p-6 animate-in fade-in duration-500 overflow-hidden">
      <div className="absolute top-0 left-0 right-0 h-1 bg-gray-50 overflow-hidden">
        {status === 'connecting' && (
          <div className="h-full bg-black animate-[shimmer_2s_infinite] w-1/3" />
        )}
      </div>

      <button 
        onClick={onClose}
        className="absolute top-8 right-8 p-4 hover:bg-gray-100 rounded-full transition-all active:scale-90 z-20"
      >
        <CloseIcon className="w-8 h-8 text-gray-900" />
      </button>

      <div className="flex-1 flex flex-col items-center justify-center space-y-16 w-full max-w-lg">
        <div className="text-center space-y-4 animate-in fade-in slide-in-from-top-4 duration-700">
          <h2 className="text-4xl font-semibold tracking-tight text-gray-900">
            {status === 'connecting' ? 'Verbindung wird aufgebaut...' : 'Ich höre zu'}
          </h2>
          <p className="text-gray-400 font-medium tracking-wide uppercase text-[10px]">
            {status === 'active' ? 'Live Verbindung aktiv' : 'KI-Guide wird geladen'}
          </p>
        </div>

        <div className="relative group">
          {/* Breathing Visualizer */}
          <div className={`absolute inset-0 bg-green-200 rounded-full scale-150 blur-[100px] opacity-20 transition-all duration-1000 ${status === 'active' ? 'scale-[2.5] animate-pulse' : 'scale-100'}`} />

          <div className={`relative w-48 h-48 bg-white shadow-[0_32px_64px_-16px_rgba(0,0,0,0.1)] rounded-full flex items-center justify-center border border-gray-50 transition-all duration-700 ${status === 'active' ? 'scale-110' : 'scale-100'}`}>
            <div className={`w-40 h-40 rounded-full flex items-center justify-center transition-all duration-500 ${status === 'active' ? 'bg-black' : 'bg-gray-50'}`}>
              <MicIcon className={`w-16 h-16 transition-all duration-500 ${status === 'active' ? 'text-white' : 'text-gray-200'}`} />
            </div>

            {/* Pulsing ring */}
            {status === 'active' && (
              <div className="absolute inset-0 rounded-full border-4 border-black animate-[ping_3s_infinite] opacity-10" />
            )}
          </div>

          {/* Modern Waveform */}
          {status === 'active' && (
            <div className="absolute -bottom-20 left-1/2 -translate-x-1/2 flex items-end gap-2 h-12">
              {[...Array(8)].map((_, i) => (
                <div 
                  key={i}
                  className="w-1.5 bg-black rounded-full animate-waveform shadow-sm"
                  style={{ 
                    animationDelay: `${i * 0.15}s`,
                    height: `${20 + Math.random() * 80}%`
                  }}
                />
              ))}
            </div>
          )}
        </div>

        <div className="w-full space-y-6 px-4 min-h-[120px] flex flex-col items-center justify-center">
          {userTranscript && (
            <div className="text-center animate-in fade-in slide-in-from-bottom-2 duration-300">
              <p className="text-gray-400 text-sm font-bold uppercase tracking-widest mb-2">Du</p>
              <p className="text-xl text-gray-900 font-medium leading-relaxed italic">
                "{userTranscript}"
              </p>
            </div>
          )}

          {modelTranscript && (
            <div className="text-center animate-in fade-in slide-in-from-bottom-2 duration-300">
              <p className="text-green-500 text-sm font-bold uppercase tracking-widest mb-2">Guide</p>
              <p className="text-2xl text-gray-900 font-semibold leading-tight">
                {modelTranscript}
              </p>
            </div>
          )}

          {status === 'connecting' && (
            <div className="flex items-center gap-2 px-6 py-3 bg-gray-50 rounded-full animate-pulse">
              <div className="w-2 h-2 bg-gray-300 rounded-full" />
              <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Initialisierung...</span>
            </div>
          )}

          {status === 'error' && (
            <div className="text-center space-y-4">
              <p className="text-red-500 font-bold">Verbindungsfehler</p>
              <button 
                onClick={() => window.location.reload()}
                className="px-6 py-2 bg-black text-white rounded-xl text-sm font-bold uppercase tracking-widest"
              >
                Erneut versuchen
              </button>
            </div>
          )}
        </div>
      </div>

      <style>{`
        @keyframes waveform {
          0%, 100% { height: 20%; transform: scaleY(1); }
          50% { height: 100%; transform: scaleY(1.2); }
        }
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(300%); }
        }
        .animate-waveform {
          animation: waveform 0.6s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

