  useEffect(() => {
    if (modelTranscript) {
      const sourceMatches = modelTranscript.match(/\[Quelle:\s*([^\]]+)\]/gi);
      if (sourceMatches) {
        // Take the last match to show the "most current" source
        const lastMatch = sourceMatches[sourceMatches.length - 1];
        const sourceName = lastMatch.replace(/\[Quelle:\s*/i, '').replace(/\]$/, '').trim().toLowerCase();

        const doc = documents.find(d => 
          d.name.toLowerCase().includes(sourceName) || 
          sourceName.includes(d.name.toLowerCase().replace(/\.pdf$/i, ''))
        );

        if (doc) {
          setActiveCitation(doc);
        }
      }
    }
  }, [modelTranscript, documents]);

  useEffect(() => {
    let isMounted = true;

    const startSession = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioContextRef.current = { input: inputCtx, output: outputCtx };

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

        const contextString = `
        BASIS-WISSEN FÜR DIESES HAUS:
        Dokumente: ${documents.map(d => `${d.name}: ${d.content}`).join(' | ')}
        Beschlüsse: ${decisions.map(d => `${d.title} (${d.date}): ${d.reason}`).join(' | ')}
        `;

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-09-2025',
