          {activeCitation ? 'Verifizierte Belege Aktiv' : 'Ich höre zu'}
        </div>

        {/* Citation Card - Clickable to exit */}
        <div className="h-16 flex items-center justify-center">
          {activeCitation && (
            <button 
              onClick={onClose}
              className="bg-white border border-gray-100 rounded-2xl p-3 pr-6 flex items-center gap-3 shadow-[0_8px_24px_-8px_rgba(0,0,0,0.1)] animate-in zoom-in-95 duration-500 hover:scale-105 active:scale-95 transition-all"
            >
              <div className="p-2 bg-[#EBF9F1] rounded-xl">
                <DocIcon className="w-5 h-5 text-[#34A853]" />
              </div>
              <div className="flex flex-col items-start">
                <span className="text-sm font-bold text-gray-900 truncate max-w-[140px]">{activeCitation.name}</span>
              </div>
            </button>
          )}
        </div>

        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-0 right-0 p-3 hover:bg-gray-100 rounded-full transition-all active:scale-90"
        >
          <CloseIcon className="w-6 h-6 text-gray-400" />
        </button>

        <div className="mt-2 text-[10px] text-gray-300 font-black uppercase tracking-widest">
          Live Verbindung Aktiv
        </div>
      </div>

      {/* Main Interactive Sphere */}
      <div className="flex-1 flex flex-col items-center justify-center w-full max-w-lg space-y-16">

        <div className="relative">
          {/* Subtle glow background */}
          <div className={`absolute inset-0 bg-[#34A853]/5 rounded-full blur-[80px] scale-[2.5] transition-opacity duration-1000 ${status === 'active' ? 'opacity-100' : 'opacity-0'}`} />

          <div className={`relative w-64 h-64 rounded-full border border-gray-50 bg-white shadow-[0_48px_80px_-24px_rgba(0,0,0,0.08)] flex items-center justify-center transition-all duration-700 ${status === 'active' ? 'scale-105' : 'scale-100'}`}>
            <div className={`w-52 h-52 rounded-full flex items-center justify-center transition-all duration-500 ${status === 'active' ? 'bg-black shadow-2xl' : 'bg-gray-50'}`}>
              <MicIcon className={`w-20 h-20 transition-all duration-500 ${status === 'active' ? 'text-white' : 'text-gray-200'}`} />
            </div>
            {status === 'active' && (
              <div className="absolute inset-0 rounded-full border border-black/5 animate-[ping_3s_infinite]" />
            )}
          </div>
        </div>

        {/* Dynamic Waveform */}
        <div className="h-12 flex items-center justify-center gap-2">
          {status === 'active' ? (
            [...Array(12)].map((_, i) => (
              <div 
                key={i}
                className="w-1.5 bg-black rounded-full animate-waveform"
                style={{ 
                  animationDelay: `${i * 0.08}s`,
                  height: `${30 + Math.random() * 70}%`
                }}
              />
            ))
          ) : (
             <div className="w-1.5 h-6 bg-gray-100 rounded-full" />
          )}
        </div>

        {/* Transcripts */}
        <div className="w-full space-y-10 flex flex-col items-center text-center px-4">
          {userTranscript && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-sm">
              <p className="text-[#8E8E93] text-lg font-medium italic leading-relaxed">
                " {userTranscript} "
              </p>
            </div>
          )}

          {displayModelTranscript && (
            <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
              <p className="text-[#34A853] text-[10px] font-black uppercase tracking-[0.3em] mb-4">Guide Antwortet</p>
              <p className="text-2xl sm:text-3xl text-gray-900 font-semibold leading-[1.2] max-w-md mx-auto">
                {displayModelTranscript}
              </p>
