          <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${status === 'active' ? 'bg-black' : 'bg-gray-100'}`} />
          <div className="w-2 h-2 rounded-full bg-gray-100" />
          <div className="w-2 h-2 rounded-full bg-gray-100" />
        </div>
      </div>

      <style>{`
        @keyframes waveform {
          0%, 100% { height: 20%; transform: scaleY(1); }
          50% { height: 100%; transform: scaleY(1.3); }
        }
        .animate-waveform {
          animation: waveform 0.8s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

