              }

              // Capture Model Transcript
              if (message.serverContent?.outputTranscription) {
                const text = message.serverContent.outputTranscription.text;
                currentModelTurnText.current += text;

                // Extract citations from the model's transcription stream
                const sourceMatches = currentModelTurnText.current.match(/\[Quelle:\s*([^\]]+)\]/gi);
                if (sourceMatches) {
                  const lastMatch = sourceMatches[sourceMatches.length - 1];
                  const sourceName = lastMatch.replace(/\[Quelle:\s*/i, '').replace(/\]$/, '').trim().toLowerCase();
                  const doc = documents.find(d => 
                    d.name.toLowerCase().includes(sourceName) || 
                    sourceName.includes(d.name.toLowerCase().replace(/\.pdf$/i, ''))
                  );
                  if (doc) {
                    // Find the actual text chunk that led to this source
                    const sentences = currentModelTurnText.current.split(/[.!?]/);
                    const relevantSentence = sentences[sentences.length - 2] || sentences[sentences.length - 1] || "";
                    setActiveCitation({ 
                      doc, 
                      text: relevantSentence.replace(/\[Quelle:[^\]]+\]/gi, '').trim() 
                    });
                  }
                }
              }

              // Turn Complete: Save to internal history
              if (message.serverContent?.turnComplete) {
                if (currentUserTurnText.current.trim()) {
