            >
              <div className="p-3 bg-green-50 rounded-2xl group-hover:bg-green-600 group-hover:text-white transition-all">
                <DocIcon className="w-6 h-6 text-green-600 group-hover:text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-black text-gray-900 truncate mb-1">{activeCitation.doc.name}</p>
                <p className="text-[11px] text-gray-400 line-clamp-2 leading-relaxed italic">
                  "{activeCitation.text}"
                </p>
              </div>
            </button>
          )}
        </div>

        {/* Minimal Close */}
        <button 
          onClick={handleExit}
          className="absolute top-0 right-0 p-3 hover:bg-gray-50 rounded-full transition-all active:scale-90 text-gray-300 hover:text-gray-900"
        >
          <CloseIcon className="w-6 h-6" />
        </button>
      </div>

      {/* Center Interaction Area */}
      <div className="flex-1 flex flex-col items-center justify-center w-full max-w-lg space-y-16">

        <div className="relative">
          {/* Pulsing Aura */}
          <div className={`absolute inset-0 bg-green-200/20 rounded-full blur-[100px] scale-[2.5] transition-opacity duration-1000 ${status === 'active' ? 'opacity-100' : 'opacity-0'}`} />

