import React, { useEffect, useState, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { CloseIcon, MicIcon, DocIcon } from './Icons';
import { Document, Decision, Message } from '../types';

interface VoiceModeProps {
  onClose: (transcript?: Message[]) => void;
  onViewDocument: (name: string) => void;
  documents: Document[];
  decisions: Decision[];
}

const VoiceMode: React.FC<VoiceModeProps> = ({ onClose, onViewDocument, documents, decisions }) => {
  const [status, setStatus] = useState<'connecting' | 'active' | 'error' | 'idle'>('connecting');
  const [activeCitation, setActiveCitation] = useState<{ doc: Document; text: string } | null>(null);

  // Internal tracking for history
  const sessionTranscriptRef = useRef<Message[]>([]);
  const currentModelTurnText = useRef('');
  const currentUserTurnText = useRef('');

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<{
    input: AudioContext;
    output: AudioContext;
  } | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Helper: Decode Base64
  const decodeBase64 = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  // Helper: Encode to Base64
  const encodeBase64 = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  // Helper: Decode Raw PCM to AudioBuffer
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, sampleRate);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  };

  useEffect(() => {
    let isMounted = true;

    const startSession = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioContextRef.current = { input: inputCtx, output: outputCtx };

        // Initialize inside to catch latest key state
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

        const contextString = `
        BASIS-WISSEN:
        Dokumente: ${documents.map(d => `${d.name}: ${d.content}`).join(' | ')}
        Beschlüsse: ${decisions.map(d => `${d.title}: ${d.reason}`).join(' | ')}
        `;

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-09-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
            },
            systemInstruction: `Du bist der CoLivingGuide. Antworte kurz und präzise. 
            WICHTIG: Wenn du Wissen aus Dokumenten nutzt, nenne die Quelle IMMER exakt am Ende des Satzes in eckigen Klammern, z.B. [Quelle: Hausordnung].
            Wissen: ${contextString}`,
            outputAudioTranscription: {},
            inputAudioTranscription: {},
          },
          callbacks: {
            onopen: () => {
              if (!isMounted) return;
              setStatus('active');

              const source = inputCtx.createMediaStreamSource(stream);
              const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) {
                  int16[i] = inputData[i] * 32768;
                }
                const pcmBlob = {
                  data: encodeBase64(new Uint8Array(int16.buffer)),
                  mimeType: 'audio/pcm;rate=16000',
                };

                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(scriptProcessor);
              scriptProcessor.connect(inputCtx.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
              if (!isMounted) return;

              // Store user voice transcript internally
              if (message.serverContent?.inputTranscription) {
                currentUserTurnText.current += message.serverContent.inputTranscription.text;
              }

              // Store model voice transcript and extract citation
              if (message.serverContent?.outputTranscription) {
                const text = message.serverContent.outputTranscription.text;
                currentModelTurnText.current += text;

                const sourceMatch = currentModelTurnText.current.match(/\[Quelle:\s*([^\]]+)\]/i);
                if (sourceMatch) {
                  const sourceName = sourceMatch[1].trim().toLowerCase();
                  const doc = documents.find(d => d.name.toLowerCase().includes(sourceName));
                  if (doc) {
                    // Extract relevant context before the bracket
                    const parts = currentModelTurnText.current.split(/\[Quelle:/i);
                    const context = parts[parts.length - 2]?.split(/[.!?]/).pop()?.trim() || "";
                    setActiveCitation({ doc, text: context });
                  }
                }
              }

              // Turn finished, save to history
              if (message.serverContent?.turnComplete) {
                if (currentUserTurnText.current.trim()) {
                  sessionTranscriptRef.current.push({ role: 'user', text: currentUserTurnText.current.trim() });
                }
                if (currentModelTurnText.current.trim()) {
                  sessionTranscriptRef.current.push({ 
                    role: 'model', 
                    text: currentModelTurnText.current.replace(/\[Quelle:[^\]]+\]/gi, '').trim() 
                  });
                }
                currentUserTurnText.current = '';
                currentModelTurnText.current = '';
              }

              const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
              if (audioData) {
                const buffer = await decodeAudioData(decodeBase64(audioData), outputCtx, 24000);
                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputCtx.destination);
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
                source.onended = () => sourcesRef.current.delete(source);
              }

              if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setActiveCitation(null);
              }
            },
            onerror: (e) => {
              console.error('Live API Error:', e);
              setStatus('error');
            },
            onclose: () => {
              if (isMounted) setStatus('idle');
            }
          }
        });

        sessionRef.current = await sessionPromise;
      } catch (err) {
        console.error('Voice Connection Error:', err);
        setStatus('error');
      }
    };

    startSession();

    return () => {
      isMounted = false;
      if (sessionRef.current) sessionRef.current.close();
      if (audioContextRef.current) {
        audioContextRef.current.input.close();
        audioContextRef.current.output.close();
      }
    };
  }, [documents, decisions]);

  const handleCitationClick = () => {
    if (activeCitation) {
      onViewDocument(activeCitation.doc.name);
      onClose(sessionTranscriptRef.current);
    }
  };

  const handleClose = () => {
    onClose(sessionTranscriptRef.current);
  };

  return (
    <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-start py-16 px-8 animate-in fade-in duration-500 overflow-hidden">

      {/* Header Info */}
      <div className="w-full flex flex-col items-center relative mb-12">
        <div className={`mb-6 px-5 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.25em] transition-all duration-700 ${activeCitation ? 'bg-[#EBF9F1] text-[#34A853]' : 'bg-gray-50 text-gray-400'}`}>
          {activeCitation ? 'Beleg gefunden' : 'Ich höre zu'}
        </div>

        {/* Single Citation Card - Clickable to Exit/Jump */}
        <div className="h-28 flex items-center justify-center w-full max-w-sm">
          {activeCitation && (
            <button 
              onClick={handleCitationClick}
              className="bg-white border border-gray-100 rounded-[2.5rem] p-5 pr-10 flex items-center gap-5 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.08)] animate-in slide-in-from-top-4 zoom-in-95 duration-500 hover:border-[#34A853] group active:scale-95 transition-all text-left"
            >
              <div className="p-4 bg-[#EBF9F1] rounded-[1.5rem] group-hover:bg-[#34A853] transition-colors">
                <DocIcon className="w-6 h-6 text-[#34A853] group-hover:text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-black text-gray-900 truncate mb-1">{activeCitation.doc.name}</p>
                <p className="text-[11px] text-gray-400 line-clamp-2 leading-relaxed italic">
                  "{activeCitation.text}..."
                </p>
              </div>
            </button>
          )}
        </div>

        <button 
          onClick={handleClose}
          className="absolute top-0 right-0 p-3 hover:bg-gray-50 rounded-full transition-all text-gray-300 hover:text-gray-900"
        >
          <CloseIcon className="w-7 h-7" />
        </button>

        <div className="mt-4 text-[10px] text-gray-300 font-bold uppercase tracking-[0.2em]">
          Live Verbindung Aktiv
        </div>
      </div>

      {/* Sphere Interaction Area */}
      <div className="flex-1 flex flex-col items-center justify-center w-full max-w-lg space-y-16">
        <div className="relative">
          <div className={`absolute inset-0 bg-[#34A853]/5 rounded-full blur-[100px] scale-[2.5] transition-opacity duration-1000 ${status === 'active' ? 'opacity-100' : 'opacity-0'}`} />

          <div className={`relative w-64 h-64 rounded-full border border-gray-50 bg-white shadow-[0_48px_96px_-24px_rgba(0,0,0,0.12)] flex items-center justify-center transition-all duration-1000 ${status === 'active' ? 'scale-110 shadow-2xl' : 'scale-100'}`}>
            <div className={`w-52 h-52 rounded-full flex items-center justify-center transition-all duration-700 ${status === 'active' ? 'bg-black shadow-[0_0_60px_rgba(0,0,0,0.2)]' : 'bg-gray-50'}`}>
              <MicIcon className={`w-24 h-24 transition-all duration-700 ${status === 'active' ? 'text-white' : 'text-gray-200'}`} />
            </div>
            {status === 'active' && (
              <div className="absolute inset-0 rounded-full border-2 border-black/5 animate-[ping_4s_infinite]" />
            )}
          </div>
        </div>

        {/* Minimal Waveform */}
        <div className="h-16 flex items-center justify-center gap-3">
          {status === 'active' ? (
            [...Array(10)].map((_, i) => (
              <div 
                key={i}
                className="w-2 bg-black rounded-full animate-waveform shadow-sm"
                style={{ 
                  animationDelay: `${i * 0.1}s`,
                  height: `${30 + Math.random() * 70}%`
                }}
              />
            ))
          ) : (
             <div className="flex gap-2">
               <div className="w-2 h-2 bg-gray-100 rounded-full animate-pulse" />
               <div className="w-2 h-2 bg-gray-100 rounded-full animate-pulse [animation-delay:0.2s]" />
               <div className="w-2 h-2 bg-gray-100 rounded-full animate-pulse [animation-delay:0.4s]" />
             </div>
          )}
        </div>
      </div>

      <div className="mt-auto pb-8 flex flex-col items-center gap-6">
        <p className="text-[10px] text-gray-300 uppercase tracking-[0.5em] font-black">CoLiving Intelligence</p>
        <div className="flex gap-4">
          <div className={`w-3 h-3 rounded-full transition-all duration-1000 ${status === 'active' ? 'bg-black scale-125' : 'bg-gray-100'}`} />
          <div className="w-3 h-3 rounded-full bg-gray-100" />
          <div className="w-3 h-3 rounded-full bg-gray-100" />
        </div>
      </div>

      <style>{`
        @keyframes waveform {
          0%, 100% { height: 25%; transform: scaleY(1); opacity: 0.8; }
          50% { height: 100%; transform: scaleY(1.5); opacity: 0.4; }
        }
        .animate-waveform {
          animation: waveform 0.75s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default VoiceMode;

import React, { useState, useEffect } from 'react';
import { View, ChatSession, Document, Decision, Role, User, Message } from './types';
import { INITIAL_DOCUMENTS, INITIAL_DECISIONS, INITIAL_USERS } from './constants';
import LoginView from './components/LoginView';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // App State
  const [documents, setDocuments] = useState<Document[]>(INITIAL_DOCUMENTS);
  const [decisions, setDecisions] = useState<Decision[]>(INITIAL_DECISIONS);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // Authentication
  const handleLogin = (email: string) => {
    const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.status === 'aktiv');
    if (user) {
      setCurrentUser(user);
    } else {
      alert("Zugang verweigert. Du wurdest noch nicht in dieses Co-Living eingeladen.");
    }
  };

  // Chat Actions
  const activeSession = sessions.find(s => s.id === currentSessionId);

  const sendMessage = async (text: string) => {
    let sessionId = currentSessionId;
    let currentSessions = [...sessions];

    if (!sessionId) {
      sessionId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sessionId,
        title: text.length > 30 ? text.substring(0, 30) + '...' : text,
        messages: [],
        createdAt: new Date().toISOString()
      };
      currentSessions = [newSession, ...currentSessions];
      setSessions(currentSessions);
      setCurrentSessionId(sessionId);
    }

    const updatedSessions = currentSessions.map(s => {
      if (s.id === sessionId) {
        return { ...s, messages: [...s.messages, { role: 'user' as const, text }] };
      }
      return s;
    });
    setSessions(updatedSessions);
    setIsLoading(true);

    const history = updatedSessions.find(s => s.id === sessionId)?.messages.map(m => ({ 
      role: m.role, 
      text: m.text 
    })) || [];

    const response = await gemini.askQuestion(text, documents, decisions, history.slice(0, -1));

    setSessions(prev => prev.map(s => {
      if (s.id === sessionId) {
        return { 
          ...s, 
          messages: [...s.messages, { 
            role: 'model' as const, 
            text: response.text, 
            citations: response.citations 
          }] 
        };
      }
      return s;
    }));
    setIsLoading(false);
  };

  const handleVoiceClose = (transcript?: Message[]) => {
    if (transcript && transcript.length > 0) {
      const sessionId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sessionId,
        title: `Gespräch: ${transcript[0].text.substring(0, 20)}...`,
        messages: transcript,
        createdAt: new Date().toISOString()
      };
      setSessions(prev => [newSession, ...prev]);
      setCurrentSessionId(sessionId);
    }
    setCurrentView('chat');
  };

  const handleViewDocument = (sourceName: string) => {
    setCurrentView('docs-view');
    // In a real app, this would scroll to the specific doc card
  };

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-white">
      <Sidebar 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        sessions={sessions}
        currentView={currentView}
        setView={setCurrentView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setCurrentView('chat');
        }}
      />

      <main className="flex-1 h-full relative overflow-hidden flex flex-col pt-4 lg:pt-0">
        <header className="flex items-center justify-between px-6 py-4 lg:hidden border-b border-gray-50">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-gray-50 rounded-full">
            <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="3" y1="12" x2="21" y2="12" /><line x1="3" y1="6" x2="21" y2="6" /><line x1="3" y1="18" x2="21" y2="18" />
            </svg>
          </button>
          <span className="font-semibold text-gray-900">CoLivingGuide</span>
          <div className="w-10" />
        </header>

        {currentView === 'chat' && (
          <ChatView 
            messages={activeSession?.messages || []}
            onSendMessage={sendMessage}
            onEnterVoice={() => setCurrentView('voice')}
            onViewDocument={handleViewDocument}
            isLoading={isLoading}
          />
        )}

        {currentView === 'voice' && (
          <VoiceMode 
            onClose={handleVoiceClose}
            onViewDocument={handleViewDocument}
            documents={documents}
            decisions={decisions}
          />
        )}

        {(currentView === 'admin-docs' || currentView === 'admin-decisions' || currentView === 'admin-users') && (
          <AdminPanel 
            documents={documents}
            decisions={decisions}
            users={users}
            activeTab={currentView.split('-')[1] as any}
            setActiveTab={(tab) => setCurrentView(`admin-${tab}` as View)}
            onAddDoc={(doc) => setDocuments([...documents, doc])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onAddDecision={(dec) => setDecisions([...decisions, dec])}
            onInviteUser={(email, role) => setUsers([...users, { id: Math.random().toString(), email, role, status: 'aktiv', invitedAt: new Date().toISOString() }])}
            onRemoveUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        )}

        {currentView === 'docs-view' && (
          <div className="max-w-4xl mx-auto py-10 px-6 w-full animate-in fade-in duration-500 overflow-y-auto">
            <h1 className="text-4xl font-semibold mb-8">Hauswissen</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {documents.map(doc => (
                <div key={doc.id} className="bg-white border border-gray-100 rounded-[2.2rem] p-8 shadow-sm hover:shadow-xl transition-all group">
                   <div className="p-4 bg-gray-50 rounded-2xl w-14 h-14 flex items-center justify-center mb-6 group-hover:bg-green-50 transition-colors">
                     <svg className="w-7 h-7 text-gray-400 group-hover:text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
                       <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" />
                     </svg>
                   </div>
                   <h3 className="text-xl font-bold text-gray-900 mb-2">{doc.name}</h3>
                   <p className="text-sm text-gray-500 leading-relaxed line-clamp-4">{doc.content}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Document, Decision, User, Role } from '../types';
import { PlusIcon, TrashIcon, DocIcon, ArrowRightIcon, CloseIcon } from './Icons';

// Use pdfjs-dist from esm.sh for client-side PDF text extraction
import * as pdfjsLib from 'https://esm.sh/pdfjs-dist@4.10.38';

// Set worker source
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.10.38/build/pdf.worker.mjs`;

interface AdminPanelProps {
  documents: Document[];
  decisions: Decision[];
  users: User[];
  onAddDoc: (doc: Document) => void;
  onRemoveDoc: (id: string) => void;
  onAddDecision: (dec: Decision) => void;
  onInviteUser: (email: string, role: Role) => void;
  onRemoveUser: (id: string) => void;
  activeTab: 'docs' | 'decisions' | 'users';
  setActiveTab: (tab: 'docs' | 'decisions' | 'users') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, decisions, users, onAddDoc, onRemoveDoc, onAddDecision, onInviteUser, onRemoveUser, activeTab, setActiveTab 
}) => {
  const [showDocUpload, setShowDocUpload] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Upload State
  const [uploadStep, setUploadStep] = useState<'idle' | 'processing' | 'ready'>('idle');
  const [uploadProgress, setUploadProgress] = useState(0);
  const [newDoc, setNewDoc] = useState<{ name: string; category: any; content: string; fileUrl?: string; file?: File }>({ name: '', category: 'Hausordnung', content: '' });
  const [newInvite, setNewInvite] = useState({ email: '', role: Role.USER });
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setError(null);
      const reader = new FileReader();
      reader.onload = (event) => {
        setNewDoc(prev => ({ 
          ...prev, 
          name: file.name.replace(/\.[^/.]+$/, ""),
          fileUrl: event.target?.result as string,
          file: file
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const extractTextFromPDF = async (file: File) => {
    try {
      const arrayBuffer = await file.arrayBuffer();
      const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
      const pdf = await loadingTask.promise;
      let fullText = '';

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const textContent = await page.getTextContent();
        const pageText = textContent.items
          .map((item: any) => item.str)
          .join(' ');
        fullText += pageText + '\n';
        setUploadProgress(Math.floor((i / pdf.numPages) * 100));
      }

      return fullText.trim();
    } catch (err) {
      console.error("PDF Extraction Error:", err);
      throw new Error("Text konnte nicht aus der PDF extrahiert werden.");
    }
  };

  const handleStartUpload = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.file) {
      setError("Bitte wähle eine PDF-Datei aus.");
      return;
    }

    setUploadStep('processing');
    setUploadProgress(0);
    setError(null);

    try {
      let content = '';
      if (newDoc.file.type === 'application/pdf') {
        content = await extractTextFromPDF(newDoc.file);
      } else {
        content = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = (ev) => resolve(ev.target?.result as string);
          reader.readAsText(newDoc.file!);
        });
      }

      if (!content || content.length < 10) {
        throw new Error("Das Dokument scheint leer zu sein.");
      }

      setNewDoc(prev => ({ ...prev, content }));
      setUploadStep('ready');
      setUploadProgress(100);
    } catch (err: any) {
      setError(err.message || "Fehler beim Verarbeiten.");
      setUploadStep('idle');
    }
  };

  const handleFinalizeDoc = () => {
    onAddDoc({
      id: Math.random().toString(36).substr(2, 9),
      name: newDoc.name,
      category: newDoc.category,
      uploadDate: new Date().toISOString().split('T')[0],
      content: newDoc.content,
      status: 'aktiv',
      fileUrl: newDoc.fileUrl
    });
    resetUpload();
  };

  const resetUpload = () => {
    setShowDocUpload(false);
    setUploadStep('idle');
    setUploadProgress(0);
    setNewDoc({ name: '', category: 'Hausordnung', content: '' });
    setError(null);
  };

  const handleInvite = () => {
