import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Citation } from "../types";

export class GeminiService {
  async askQuestion(
    question: string, 
    documents: Document[], 
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    // Late initialization to ensure we always have the latest API key context
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const context = `
Hier sind die aktuellen Hausdokumente als Wissensbasis:
${documents.map(d => `[DOKUMENT ID: ${d.id} NAME: ${d.name}]
Inhalt: ${d.content}`).join('\n\n')}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `${context}\n\nFrage des Bewohners: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.1, // Low temperature for factual accuracy
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { 
                type: Type.STRING,
                description: "Die hilfreiche, erklärende Antwort in einfachem Deutsch."
              },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING, description: "Der Name des Originaldokuments." },
                    text: { type: Type.STRING, description: "Der exakte Textabschnitt aus dem Dokument." },
                    documentId: { type: Type.STRING, description: "Die ID des Dokuments falls bekannt." }
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const text = response.text;
      if (!text) throw new Error("Empty response from AI");

      const data = JSON.parse(text);
      return {
        text: data.answer || "Ich konnte leider keine Information dazu finden.",
        citations: data.citations || []
      };
    } catch (error) {
      console.error("Gemini API Error:", error);
      return {
        text: "Es gab ein technisches Problem beim Zugriff auf das Hauswissen. Bitte versuche es gleich noch einmal.",
        citations: []
      };
    }
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect } from 'react';
import { View, ChatSession, Document, Role, User, Message } from './types';
import { INITIAL_DOCUMENTS, INITIAL_USERS } from './constants';
import LoginView from './components/LoginView';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // App State
  const [documents, setDocuments] = useState<Document[]>(INITIAL_DOCUMENTS);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // Authentication
  const handleLogin = (email: string) => {
    const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.status === 'aktiv');
    if (user) {
      setCurrentUser(user);
    } else {
      alert("Zugang verweigert. Du wurdest noch nicht in dieses Co-Living eingeladen.");
    }
  };

  // Chat Actions
  const activeSession = sessions.find(s => s.id === currentSessionId);

  const sendMessage = async (text: string) => {
    let sessionId = currentSessionId;
    let currentSessions = [...sessions];

    if (!sessionId) {
      sessionId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sessionId,
        title: text.length > 30 ? text.substring(0, 30) + '...' : text,
        messages: [],
        createdAt: new Date().toISOString()
      };
      currentSessions = [newSession, ...currentSessions];
      setSessions(currentSessions);
      setCurrentSessionId(sessionId);
    }

    const updatedSessions = currentSessions.map(s => {
      if (s.id === sessionId) {
        return { ...s, messages: [...s.messages, { role: 'user' as const, text }] };
      }
      return s;
    });
    setSessions(updatedSessions);
    setIsLoading(true);

    const history = updatedSessions.find(s => s.id === sessionId)?.messages.map(m => ({ 
      role: m.role, 
      text: m.text 
    })) || [];

    const response = await gemini.askQuestion(text, documents, history.slice(0, -1));

    setSessions(prev => prev.map(s => {
      if (s.id === sessionId) {
        return { 
          ...s, 
          messages: [...s.messages, { 
            role: 'model' as const, 
            text: response.text, 
            citations: response.citations 
          }] 
        };
      }
      return s;
    }));
    setIsLoading(false);
  };

  const handleVoiceClose = (transcript?: Message[]) => {
    if (transcript && transcript.length > 0) {
      const sessionId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sessionId,
        title: `Gespräch: ${transcript[0].text.substring(0, 20)}...`,
        messages: transcript,
        createdAt: new Date().toISOString()
      };
      setSessions(prev => [newSession, ...prev]);
      setCurrentSessionId(sessionId);
    }
    setCurrentView('chat');
  };

  const handleViewDocument = (sourceName: string) => {
    setCurrentView('docs-view');
  };

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-white">
      <Sidebar 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        sessions={sessions}
        currentView={currentView}
        setView={setCurrentView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setCurrentView('chat');
        }}
      />

      <main className="flex-1 h-full relative overflow-hidden flex flex-col pt-4 lg:pt-0">
        <header className="flex items-center justify-between px-6 py-4 lg:hidden border-b border-gray-50">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-gray-50 rounded-full">
            <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="3" y1="12" x2="21" y2="12" /><line x1="3" y1="6" x2="21" y2="6" /><line x1="3" y1="18" x2="21" y2="18" />
            </svg>
          </button>
          <span className="font-semibold text-gray-900">CoLivingGuide</span>
          <div className="w-10" />
        </header>

        {currentView === 'chat' && (
          <ChatView 
            messages={activeSession?.messages || []}
            onSendMessage={sendMessage}
            onEnterVoice={() => setCurrentView('voice')}
            onViewDocument={handleViewDocument}
            isLoading={isLoading}
          />
        )}

        {currentView === 'voice' && (
          <VoiceMode 
            onClose={handleVoiceClose}
            onViewDocument={handleViewDocument}
            documents={documents}
          />
        )}

        {(currentView === 'admin-docs' || currentView === 'admin-users') && (
          <AdminPanel 
            documents={documents}
            users={users}
            activeTab={currentView.split('-')[1] as any}
            setActiveTab={(tab) => setCurrentView(`admin-${tab}` as View)}
            onAddDoc={(doc) => setDocuments([...documents, doc])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onInviteUser={(email, role) => setUsers([...users, { id: Math.random().toString(), email, role, status: 'aktiv', invitedAt: new Date().toISOString() }])}
            onRemoveUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        )}

        {currentView === 'docs-view' && (
          <div className="max-w-4xl mx-auto py-10 px-6 w-full animate-in fade-in duration-500 overflow-y-auto">
            <h1 className="text-4xl font-semibold mb-8">Hauswissen</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {documents.map(doc => (
                <div key={doc.id} className="bg-white border border-gray-100 rounded-[2.2rem] p-8 shadow-sm hover:shadow-xl transition-all group">
                   <div className="p-4 bg-gray-50 rounded-2xl w-14 h-14 flex items-center justify-center mb-6 group-hover:bg-green-50 transition-colors">
                     <svg className="w-7 h-7 text-gray-400 group-hover:text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
                       <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" />
                     </svg>
                   </div>
                   <h3 className="text-xl font-bold text-gray-900 mb-2">{doc.name}</h3>
                   <p className="text-sm text-gray-500 leading-relaxed line-clamp-4">{doc.content}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Document, User, Role } from '../types';
import { PlusIcon, TrashIcon, DocIcon, CloseIcon } from './Icons';

// Use pdfjs-dist from esm.sh for client-side PDF text extraction
import * as pdfjsLib from 'https://esm.sh/pdfjs-dist@4.10.38';

// Set worker source
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.10.38/build/pdf.worker.mjs`;

interface AdminPanelProps {
  documents: Document[];
  users: User[];
  onAddDoc: (doc: Document) => void;
  onRemoveDoc: (id: string) => void;
  onInviteUser: (email: string, role: Role) => void;
  onRemoveUser: (id: string) => void;
  activeTab: 'docs' | 'users';
  setActiveTab: (tab: 'docs' | 'users') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, users, onAddDoc, onRemoveDoc, onInviteUser, onRemoveUser, activeTab, setActiveTab 
}) => {
  const [showDocUpload, setShowDocUpload] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Upload State
  const [uploadStep, setUploadStep] = useState<'idle' | 'processing' | 'ready'>('idle');
  const [uploadProgress, setUploadProgress] = useState(0);
  const [newDoc, setNewDoc] = useState<{ name: string; category: any; content: string; fileUrl?: string; file?: File }>({ name: '', category: 'Hausordnung', content: '' });
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setError(null);
      const reader = new FileReader();
      reader.onload = (event) => {
        setNewDoc(prev => ({ 
          ...prev, 
          name: file.name.replace(/\.[^/.]+$/, ""),
          fileUrl: event.target?.result as string,
          file: file
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const extractTextFromPDF = async (file: File) => {
    try {
      const arrayBuffer = await file.arrayBuffer();
      const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
      const pdf = await loadingTask.promise;
      let fullText = '';

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const textContent = await page.getTextContent();
        const pageText = textContent.items
          .map((item: any) => item.str)
          .join(' ');
        fullText += pageText + '\n';
        setUploadProgress(Math.floor((i / pdf.numPages) * 100));
      }

      return fullText.trim();
    } catch (err) {
      console.error("PDF Extraction Error:", err);
      throw new Error("Text konnte nicht aus der PDF extrahiert werden.");
    }
  };

  const handleStartUpload = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.file) {
      setError("Bitte wähle eine PDF-Datei aus.");
      return;
    }

    setUploadStep('processing');
    setUploadProgress(0);
    setError(null);

    try {
      let content = '';
      if (newDoc.file.type === 'application/pdf') {
        content = await extractTextFromPDF(newDoc.file);
      } else {
        content = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = (ev) => resolve(ev.target?.result as string);
          reader.readAsText(newDoc.file!);
        });
      }

      if (!content || content.length < 10) {
        throw new Error("Das Dokument scheint leer zu sein.");
      }

      setNewDoc(prev => ({ ...prev, content }));
      setUploadStep('ready');
      setUploadProgress(100);
    } catch (err: any) {
      setError(err.message || "Fehler beim Verarbeiten.");
      setUploadStep('idle');
    }
  };

  const handleFinalizeDoc = () => {
    onAddDoc({
      id: Math.random().toString(36).substr(2, 9),
      name: newDoc.name,
      category: newDoc.category,
      uploadDate: new Date().toISOString().split('T')[0],
      content: newDoc.content,
      status: 'aktiv',
      fileUrl: newDoc.fileUrl
    });
    resetUpload();
  };

  const resetUpload = () => {
    setShowDocUpload(false);
    setUploadStep('idle');
    setUploadProgress(0);
    setNewDoc({ name: '', category: 'Hausordnung', content: '' });
    setError(null);
  };

  return (
    <div className="flex-1 h-full overflow-y-auto no-scrollbar scroll-smooth">
      <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in duration-500">
        <div className="flex gap-8 border-b border-gray-100 mb-10 overflow-x-auto no-scrollbar">
          {[
            { id: 'docs', label: 'Dokumente' },
            { id: 'users', label: 'Nutzer' }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`pb-4 text-sm font-black uppercase tracking-[0.2em] transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-black' : 'text-gray-300 hover:text-black'}`}
            >
              {tab.label}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black" />}
            </button>
          ))}
        </div>

        {activeTab === 'docs' && (
          <div className="space-y-6">
            {!showDocUpload ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                <button 
                  onClick={() => setShowDocUpload(true)}
                  className="border-2 border-dashed border-gray-100 rounded-[2rem] p-8 flex flex-col items-center justify-center text-gray-400 hover:border-black hover:text-black transition-all group min-h-[220px] bg-white hover:bg-gray-50/50"
                >
                  <div className="w-14 h-14 bg-gray-50 rounded-2xl flex items-center justify-center mb-4 group-hover:bg-black transition-all">
                    <PlusIcon className="w-6 h-6 group-hover:text-white transition-colors" />
                  </div>
                  <span className="text-sm font-bold tracking-tight">Hochladen</span>
                </button>
                {documents.map(doc => (
                  <div key={doc.id} className="bg-white border border-gray-100 rounded-[2rem] p-7 shadow-sm group hover:shadow-xl transition-all flex flex-col justify-between">
                    <div className="flex items-start justify-between mb-4">
                      <div className="p-3 bg-gray-50 rounded-xl group-hover:bg-green-50 transition-colors">
                        <DocIcon className="w-5 h-5 text-gray-400 group-hover:text-green-600" />
                      </div>
                      <button onClick={() => onRemoveDoc(doc.id)} className="p-2 text-gray-200 hover:text-red-500 transition-colors">
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </div>
                    <div>
                      <h3 className="font-bold text-gray-900 mb-1 truncate">{doc.name}</h3>
                      <p className="text-[9px] text-gray-400 uppercase tracking-widest font-black">{doc.category} • {doc.uploadDate}</p>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="bg-white border border-gray-100 rounded-[2.5rem] p-10 shadow-xl animate-in zoom-in-95 duration-300 relative">
                <button onClick={resetUpload} className="absolute top-8 right-8 p-2 text-gray-300 hover:text-black rounded-full transition-all">
                  <CloseIcon className="w-6 h-6" />
                </button>
                <div className="max-w-md mx-auto">
                  {uploadStep === 'idle' && (
                    <div className="space-y-8">
                      <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="bg-gray-50 border-2 border-dashed border-gray-100 rounded-[2rem] p-12 text-center cursor-pointer hover:border-black transition-all group"
                      >
                        <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".pdf" />
                        <DocIcon className="w-12 h-12 text-gray-200 mx-auto mb-4 group-hover:text-black" />
                        <p className="text-sm font-bold text-gray-400">{newDoc.file ? newDoc.file.name : "Klicke zum Auswählen"}</p>
                      </div>
                      <button 
                        onClick={handleStartUpload}
                        disabled={!newDoc.file}
                        className="w-full bg-black text-white rounded-2xl py-4 font-bold disabled:bg-gray-100 disabled:text-gray-300 transition-all"
                      >
                        Verarbeiten
                      </button>
                    </div>
                  )}
                  {uploadStep === 'processing' && (
                    <div className="text-center py-12">
                      <div className="w-full bg-gray-100 h-1 rounded-full mb-6 overflow-hidden">
                        <div className="bg-black h-full transition-all" style={{ width: `${uploadProgress}%` }} />
                      </div>
                      <p className="text-xs font-black uppercase tracking-widest animate-pulse">Lese Dokument...</p>
                    </div>
                  )}
                  {uploadStep === 'ready' && (
                    <div className="space-y-8">
                      <input 
                        type="text" 
                        value={newDoc.name} 
                        onChange={(e) => setNewDoc({...newDoc, name: e.target.value})}
                        className="w-full bg-gray-50 border border-gray-100 rounded-xl px-6 py-4 font-bold focus:outline-none"
                        placeholder="Name des Dokuments"
                      />
                      <button 
                        onClick={handleFinalizeDoc}
                        className="w-full bg-black text-white rounded-2xl py-4 font-bold shadow-lg shadow-black/10"
                      >
                        In Hauswissen speichern
                      </button>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'users' && (
          <div className="bg-white border border-gray-100 rounded-[2.5rem] overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead>
                <tr className="border-b border-gray-50">
                  <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-400">Nutzer</th>
                  <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-400">Rolle</th>
                  <th className="px-8 py-6 text-[10px] font-black uppercase tracking-widest text-gray-400">Status</th>
                  <th className="px-8 py-6 text-right"></th>
                </tr>
              </thead>
              <tbody>
                {users.map(user => (
                  <tr key={user.id} className="border-b border-gray-50 last:border-0 hover:bg-gray-50/50 transition-colors">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center font-bold text-gray-400 text-xs">
                          {user.email[0].toUpperCase()}
                        </div>
                        <span className="text-sm font-bold text-gray-900">{user.email}</span>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className={`text-[10px] font-black uppercase tracking-widest ${user.role === Role.ADMIN ? 'text-purple-600' : 'text-gray-400'}`}>
                        {user.role}
                      </span>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-[10px] font-black uppercase tracking-widest text-green-600 bg-green-50 px-2 py-1 rounded-md">
                        {user.status}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <button onClick={() => onRemoveUser(user.id)} className="p-2 text-gray-200 hover:text-red-500">
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

