import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Citation } from "../types";

export class GeminiService {
  async askQuestion(
    question: string, 
    documents: Document[], 
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const context = `
Hier sind die aktuellen Hausdokumente als Wissensbasis:
${documents.map(d => `[DOKUMENT ID: ${d.id} NAME: ${d.name}]
Inhalt: ${d.content}`).join('\n\n')}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `${context}\n\nFrage des Bewohners: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.1,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { 
                type: Type.STRING,
                description: "Die hilfreiche Antwort."
              },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING },
                    text: { type: Type.STRING },
                    section: { type: Type.STRING, description: "Das Kapitel oder der Paragraph, z.B. 'Kapitel 1.3'." },
                    documentId: { type: Type.STRING }
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const text = response.text;
      if (!text) throw new Error("Empty response from AI");

      const data = JSON.parse(text);
      return {
        text: data.answer || "Ich konnte leider keine Information dazu finden.",
        citations: data.citations || []
      };
    } catch (error) {
      console.error("Gemini API Error:", error);
      return {
        text: "Es gab ein technisches Problem. Bitte versuche es noch einmal.",
        citations: []
      };
    }
  }
}

