    const updatedSessions = currentSessions.map(s => {
      if (s.id === sessionId) {
        return { ...s, messages: [...s.messages, { role: 'user' as const, text }] };
      }
      return s;
    });
    setSessions(updatedSessions);
    setIsLoading(true);

    const history = updatedSessions.find(s => s.id === sessionId)?.messages.map(m => ({ 
      role: m.role, 
      text: m.text 
    })) || [];

    const response = await gemini.askQuestion(text, documents, history.slice(0, -1));

    setSessions(prev => prev.map(s => {
      if (s.id === sessionId) {
        return { 
          ...s, 
          messages: [...s.messages, { 
            role: 'model' as const, 
            text: response.text, 
            citations: response.citations 
          }] 
        };
      }
      return s;
    }));
    setIsLoading(false);
  };

  const handleVoiceClose = (transcript?: Message[]) => {
    if (transcript && transcript.length > 0) {
      const sessionId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: sessionId,
        title: `Gespräch: ${transcript[0].text.substring(0, 20)}...`,
        messages: transcript,
        createdAt: new Date().toISOString()
      };
      setSessions(prev => [newSession, ...prev]);
      setCurrentSessionId(sessionId);
    }
    setCurrentView('chat');
  };

  const handleViewDocument = (sourceName: string, textToHighlight?: string) => {
    const doc = documents.find(d => d.name === sourceName);
    if (doc) {
      setSelectedDocId(doc.id);
      setHighlightText(textToHighlight || '');
      setCurrentView('doc-detail');
    }
  };

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  const selectedDocument = documents.find(d => d.id === selectedDocId);

  return (
    <div className="flex h-screen bg-white">
      <Sidebar 
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        sessions={sessions}
        currentView={currentView}
        setView={setCurrentView}
        onSelectSession={(id) => {
          setCurrentSessionId(id);
          setCurrentView('chat');
        }}
      />

      <main className="flex-1 h-full relative overflow-hidden flex flex-col pt-4 lg:pt-0">
        <header className="flex items-center justify-between px-6 py-4 lg:hidden border-b border-gray-50">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-gray-50 rounded-full">
            <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="3" y1="12" x2="21" y2="12" /><line x1="3" y1="6" x2="21" y2="6" /><line x1="3" y1="18" x2="21" y2="18" />
            </svg>
          </button>
          <span className="font-semibold text-gray-900">CoLivingGuide</span>
          <div className="w-10" />
        </header>

        {currentView === 'chat' && (
          <ChatView 
            messages={activeSession?.messages || []}
            onSendMessage={sendMessage}
            onEnterVoice={() => setCurrentView('voice')}
            onViewDocument={handleViewDocument}
            isLoading={isLoading}
          />
        )}

        {currentView === 'voice' && (
          <VoiceMode 
            onClose={handleVoiceClose}
            onViewDocument={handleViewDocument}
            documents={documents}
          />
        )}

        {(currentView === 'admin-docs' || currentView === 'admin-users') && (
          <AdminPanel 
            documents={documents}
            users={users}
            activeTab={currentView.split('-')[1] as any}
            setActiveTab={(tab) => setCurrentView(`admin-${tab}` as View)}
            onAddDoc={(doc) => setDocuments([...documents, doc])}
            onRemoveDoc={(id) => setDocuments(documents.filter(d => d.id !== id))}
            onInviteUser={(email, role) => setUsers([...users, { id: Math.random().toString(), email, role, status: 'aktiv', invitedAt: new Date().toISOString() }])}
            onRemoveUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        )}

        {currentView === 'docs-view' && (
          <div className="max-w-4xl mx-auto py-10 px-6 w-full animate-in fade-in duration-500 overflow-y-auto">
            <div className="flex items-end justify-between mb-12">
              <div>
                <p className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-400 mb-2">Wissensbasis</p>
                <h1 className="text-5xl font-black text-gray-900">Hauswissen</h1>
              </div>
              <div className="text-right">
                <p className="text-sm font-bold text-gray-900">{documents.length} Dokumente</p>
                <p className="text-xs text-gray-400">Alle Regelungen im Überblick</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {documents.map(doc => (
                <button 
                  key={doc.id} 
                  onClick={() => handleViewDocument(doc.name)}
                  className="bg-white border border-gray-100 rounded-[2.5rem] p-10 shadow-sm hover:shadow-2xl transition-all group text-left relative overflow-hidden active:scale-[0.98]"
                >
                   <div className="absolute top-0 right-0 p-8 opacity-0 group-hover:opacity-100 transition-all transform translate-x-4 group-hover:translate-x-0">
                     <svg className="w-6 h-6 text-black" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="3">
                        <path d="M5 12h14M12 5l7 7-7 7" />
                     </svg>
                   </div>
                   <div className="p-5 bg-gray-50 rounded-[1.5rem] w-16 h-16 flex items-center justify-center mb-8 group-hover:bg-black transition-colors">
                     <svg className="w-8 h-8 text-gray-400 group-hover:text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5">
                       <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" />
                     </svg>
                   </div>
                   <h3 className="text-2xl font-black text-gray-900 mb-3 leading-tight">{doc.name}</h3>
                   <div className="flex gap-3 items-center mb-4">
                     <span className="text-[10px] font-black uppercase tracking-widest text-gray-400 bg-gray-50 px-3 py-1 rounded-full">{doc.category}</span>
                   </div>
                   <p className="text-sm text-gray-400 leading-relaxed line-clamp-2 italic">
                     {doc.content.substring(0, 100)}...
                   </p>
                </button>
              ))}
            </div>
          </div>
        )}

        {currentView === 'doc-detail' && selectedDocument && (
          <DocumentDetail 
            document={selectedDocument}
            onClose={() => {
              setCurrentView('docs-view');
              setSelectedDocId(null);
              setHighlightText('');
            }}
            highlightText={highlightText}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
