import * as pdfjsLib from 'https://esm.sh/pdfjs-dist@4.10.38';
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.10.38/build/pdf.worker.mjs`;

interface AdminPanelProps {
  documents: Document[];
  users: User[];
  onAddDoc: (doc: Document) => void;
  onRemoveDoc: (id: string) => void;
  onInviteUser: (email: string, role: Role) => void;
  onRemoveUser: (id: string) => void;
  onUpdateUserStatus?: (id: string, status: UserStatus) => void;
  activeTab: 'docs' | 'users';
  setActiveTab: (tab: 'docs' | 'users') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, users, onAddDoc, onRemoveDoc, onInviteUser, onRemoveUser, onUpdateUserStatus, activeTab, setActiveTab 
}) => {
  const [showDocUpload, setShowDocUpload] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Doc Upload State
  const [uploadStep, setUploadStep] = useState<'idle' | 'processing' | 'ready'>('idle');
  const [uploadProgress, setUploadProgress] = useState(0);
  const [newDoc, setNewDoc] = useState<{ name: string; category: any; content: string; fileUrl?: string; file?: File }>({ name: '', category: 'Hausordnung', content: '' });

  // Invite State
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<Role>(Role.USER);
  const [isInviting, setIsInviting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Background Simulation: Auto-verify invited users after 8 seconds
  useEffect(() => {
    const invitedUsers = users.filter(u => u.status === 'eingeladen');
    if (invitedUsers.length > 0 && onUpdateUserStatus) {
      const timer = setTimeout(() => {
        onUpdateUserStatus(invitedUsers[0].id, 'aktiv');
      }, 8000);
      return () => clearTimeout(timer);
    }
  }, [users, onUpdateUserStatus]);

  const handleInvite = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Simple Background Check (Duplication & Formatting)
    if (!inviteEmail.includes('@')) {
      setError("Bitte gib eine gültige E-Mail Adresse ein.");
      return;
    }

    if (users.find(u => u.email.toLowerCase() === inviteEmail.toLowerCase())) {
      setError("Dieser Nutzer wurde bereits eingeladen.");
      return;
    }

    setIsInviting(true);

    // Simulate Background "Complexity" (Mail server handshake, verification token generation)
    setTimeout(() => {
      onInviteUser(inviteEmail, inviteRole);
      setInviteEmail('');
      setIsInviting(false);
      setShowInviteModal(false);
    }, 1500);
  };

  const getStatusIcon = (status: UserStatus) => {
    switch (status) {
      case 'aktiv': return <CheckCircleIcon className="w-5 h-5 text-green-500" />;
      case 'eingeladen': return <ClockIcon className="w-5 h-5 text-amber-400 animate-pulse" />;
      case 'deaktiviert': return <AlertIcon className="w-5 h-5 text-red-400" />;
      default: return null;
    }
  };

  const extractTextFromPDF = async (file: File) => {
    const arrayBuffer = await file.arrayBuffer();
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdf = await loadingTask.promise;
    let fullText = '';
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const pageText = textContent.items.map((item: any) => item.str).join(' ');
      fullText += pageText + '\n';
      setUploadProgress(Math.floor((i / pdf.numPages) * 100));
    }
    return fullText.trim();
  };

  return (
    <div className="flex-1 h-full overflow-y-auto no-scrollbar scroll-smooth bg-white">
      <div className="max-w-4xl mx-auto py-10 px-6 animate-in fade-in duration-500">

        {/* Navigation Tabs */}
        <div className="flex gap-8 border-b border-gray-100 mb-10">
          {[
            { id: 'docs', label: 'Dokumente' },
            { id: 'users', label: 'Bewohner' }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`pb-4 text-sm font-black uppercase tracking-[0.2em] transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-black' : 'text-gray-300 hover:text-black'}`}
            >
              {tab.label}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black" />}
            </button>
          ))}
        </div>

        {activeTab === 'docs' && (
          <div className="space-y-6">
            {!showDocUpload ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                <button 
                  onClick={() => setShowDocUpload(true)}
                  className="border-2 border-dashed border-gray-100 rounded-[2.5rem] p-8 flex flex-col items-center justify-center text-gray-400 hover:border-black hover:text-black transition-all group min-h-[220px] bg-white hover:bg-gray-50/50"
                >
                  <div className="w-14 h-14 bg-gray-50 rounded-2xl flex items-center justify-center mb-4 group-hover:bg-black transition-all">
                    <PlusIcon className="w-6 h-6 group-hover:text-white transition-colors" />
                  </div>
                  <span className="text-sm font-bold tracking-tight">Neues Dokument</span>
                </button>
                {documents.map(doc => (
                  <div key={doc.id} className="bg-white border border-gray-100 rounded-[2.5rem] p-7 shadow-sm group hover:shadow-xl transition-all flex flex-col justify-between">
                    <div className="flex items-start justify-between mb-4">
                      <div className="p-3 bg-gray-50 rounded-xl group-hover:bg-green-50 transition-colors">
                        <DocIcon className="w-5 h-5 text-gray-400 group-hover:text-green-600" />
                      </div>
                      <button onClick={() => onRemoveDoc(doc.id)} className="p-2 text-gray-200 hover:text-red-500 transition-colors">
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </div>
                    <div>
                      <h3 className="font-bold text-gray-900 mb-1 truncate">{doc.name}</h3>
                      <p className="text-[9px] text-gray-400 uppercase tracking-widest font-black">{doc.category} • {doc.uploadDate}</p>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="bg-white border border-gray-100 rounded-[2.5rem] p-10 shadow-xl relative animate-in zoom-in-95 duration-300">
                <button onClick={() => setShowDocUpload(false)} className="absolute top-8 right-8 p-2 text-gray-300 hover:text-black">
                  <CloseIcon className="w-6 h-6" />
                </button>
                {/* Upload Form (Simplified for brevity) */}
                <div className="max-w-md mx-auto py-10">
                   <p className="text-center font-bold text-gray-300 uppercase tracking-widest mb-4">Dokumenten-Import</p>
                   <div 
                      onClick={() => fileInputRef.current?.click()}
                      className="bg-gray-50 border-2 border-dashed border-gray-100 rounded-[2rem] p-12 text-center cursor-pointer hover:border-black transition-all"
                   >
                     <input type="file" ref={fileInputRef} onChange={(e) => {
                        const file = e.target.files?.[0];
                        if (file) {
                          setUploadStep('processing');
                          extractTextFromPDF(file).then(content => {
                            onAddDoc({
                              id: Math.random().toString(36).substr(2, 9),
                              name: file.name.replace(/\.[^/.]+$/, ""),
                              category: 'Hausordnung',
                              uploadDate: new Date().toISOString().split('T')[0],
                              content,
                              status: 'aktiv'
                            });
                            setShowDocUpload(false);
                            setUploadStep('idle');
                          });
                        }
                     }} className="hidden" accept=".pdf" />
                     <DocIcon className="w-12 h-12 text-gray-200 mx-auto mb-4" />
                     <p className="text-sm font-bold text-gray-400">PDF hier ablegen</p>
                   </div>
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'users' && (
          <div className="space-y-8 animate-in fade-in duration-500">
