                className="w-full bg-white border border-gray-100 rounded-[2.5rem] px-8 py-6 pr-40 shadow-2xl focus:outline-none focus:ring-4 focus:ring-black/5 transition-all text-lg placeholder:text-gray-300"
                disabled={isLoading}
