                      <h3 className="font-bold text-gray-900 truncate">{doc.name}</h3>
                      <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mt-1">{doc.category}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
