    setInviteStep('input');
    setInviteEmail('');
    setAiDraft('');
    setVerificationResult(null);
  };

  const getStatusIcon = (status: UserStatus) => {
    switch (status) {
      case 'aktiv': return <ShieldIcon className="w-5 h-5 text-blue-500" />;
