import React, { useEffect, useState, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { CloseIcon, MicIcon, DocIcon } from './Icons';
import { Document, Message } from '../types';

interface VoiceModeProps {
  onClose: (transcript?: Message[]) => void;
  onViewDocument: (name: string) => void;
  documents: Document[];
}

const VoiceMode: React.FC<VoiceModeProps> = ({ onClose, onViewDocument, documents }) => {
  const [status, setStatus] = useState<'connecting' | 'active' | 'error' | 'idle'>('connecting');
  const [activeCitation, setActiveCitation] = useState<{ doc: Document; text: string } | null>(null);
  const [audioLevels, setAudioLevels] = useState<number[]>(new Array(12).fill(10));

  // Track transcript for conversation history
  const sessionTranscriptRef = useRef<Message[]>([]);
  const currentModelTurnText = useRef('');
  const currentUserTurnText = useRef('');

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<{
    input: AudioContext;
    output: AudioContext;
    outputAnalyser: AnalyserNode;
    inputAnalyser: AnalyserNode;
  } | null>(null);

  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const rafIdRef = useRef<number | null>(null);

  // Helper: Decode Base64
  const decodeBase64 = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  // Helper: Encode to Base64
  const encodeBase64 = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  // Helper: Decode Raw PCM to AudioBuffer
  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, sampleRate);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  };

  useEffect(() => {
    let isMounted = true;

    const startSession = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

        const inputAnalyser = inputCtx.createAnalyser();
        const outputAnalyser = outputCtx.createAnalyser();
        inputAnalyser.fftSize = 64;
        outputAnalyser.fftSize = 64;

        audioContextRef.current = { 
          input: inputCtx, 
          output: outputCtx, 
          inputAnalyser, 
          outputAnalyser 
        };

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const contextString = documents.map(d => `[DOKUMENT ${d.name}]: ${d.content}`).join('\n');

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } },
            },
            systemInstruction: `Du bist der Wohnpro Guide mit einer tiefen, warmen männlichen Stimme.
            Du bist die Seele des Wohnprojekts und erklärst mit Ruhe und Herzlichkeit das Zusammenleben.

            DEIN FOKUS:
            - Erkläre die rechtliche Struktur so, dass man sich geborgen fühlt.
            - Beschreibe Entscheidungsprozesse und das Miteinander.
            - Vermittle das echte Lebensgefühl.

            REGELN:
            - Sei kurz, menschlich und fachlich versiert.
            - Nutze NUR das bereitgestellte Wissen.
            - Nenne Quellen am Ende: [Quelle: Name].

            Wissen:
            ${contextString}`,
            outputAudioTranscription: {},
            inputAudioTranscription: {},
          },
          callbacks: {
            onopen: () => {
              if (!isMounted) return;
              setStatus('active');

              const source = inputCtx.createMediaStreamSource(stream);
              const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) {
                  int16[i] = inputData[i] * 32768;
                }
                const pcmBlob = {
                  data: encodeBase64(new Uint8Array(int16.buffer)),
                  mimeType: 'audio/pcm;rate=16000',
                };

                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(inputAnalyser);
              source.connect(scriptProcessor);
              scriptProcessor.connect(inputCtx.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
              if (!isMounted) return;

              if (message.serverContent?.inputTranscription) {
                currentUserTurnText.current += message.serverContent.inputTranscription.text;
              }

              if (message.serverContent?.outputTranscription) {
                const text = message.serverContent.outputTranscription.text;
                currentModelTurnText.current += text;

                const match = currentModelTurnText.current.match(/\[Quelle:\s*([^\]]+)\]/i);
                if (match) {
                  const sourceName = match[1].trim().toLowerCase();
                  const doc = documents.find(d => d.name.toLowerCase().includes(sourceName));
                  if (doc) {
                    const parts = currentModelTurnText.current.split(/\[Quelle:/i);
                    const relevantSentence = parts[parts.length - 2]?.split(/[.!?]/).pop()?.trim() || "Information gefunden";
                    setActiveCitation({ doc, text: relevantSentence });
                  }
                }
              }

              if (message.serverContent?.turnComplete) {
                if (currentUserTurnText.current.trim()) {
                  sessionTranscriptRef.current.push({ role: 'user', text: currentUserTurnText.current.trim() });
                }
                if (currentModelTurnText.current.trim()) {
                  sessionTranscriptRef.current.push({ 
                    role: 'model', 
                    text: currentModelTurnText.current.replace(/\[Quelle:[^\]]+\]/gi, '').trim() 
                  });
                }
                currentUserTurnText.current = '';
                currentModelTurnText.current = '';
              }

              const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
              if (audioData) {
                const buffer = await decodeAudioData(decodeBase64(audioData), outputCtx, 24000);
                const source = outputCtx.createBufferSource();
                source.buffer = buffer;
                source.connect(outputAnalyser);
                outputAnalyser.connect(outputCtx.destination);

                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
                source.onended = () => sourcesRef.current.delete(source);
              }

              if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setActiveCitation(null);
                currentModelTurnText.current = '';
              }
            },
            onerror: () => setStatus('error'),
            onclose: () => isMounted && setStatus('idle')
          }
        });

        // Start animation loop for waveform
        const updateWaveform = () => {
          if (!audioContextRef.current) return;
          const { inputAnalyser, outputAnalyser } = audioContextRef.current;

          const inputData = new Uint8Array(inputAnalyser.frequencyBinCount);
          const outputData = new Uint8Array(outputAnalyser.frequencyBinCount);
          inputAnalyser.getByteFrequencyData(inputData);
          outputAnalyser.getByteFrequencyData(outputData);

          // Combine data and map to 12 bars
          const levels = [];
          for (let i = 0; i < 12; i++) {
            const idx = Math.floor(i * (inputData.length / 12));
            const val = Math.max(inputData[idx], outputData[idx]);
            levels.push(10 + (val / 255) * 90); // Scale 10% to 100%
          }
          setAudioLevels(levels);
          rafIdRef.current = requestAnimationFrame(updateWaveform);
        };
        updateWaveform();

        sessionRef.current = await sessionPromise;
      } catch (err) {
        setStatus('error');
      }
    };

    startSession();

    return () => {
      isMounted = false;
      if (sessionRef.current) sessionRef.current.close();
      if (audioContextRef.current) {
        audioContextRef.current.input.close();
        audioContextRef.current.output.close();
      }
      if (rafIdRef.current) cancelAnimationFrame(rafIdRef.current);
    };
  }, [documents]);

  const handleCitationClick = () => {
    if (activeCitation) {
      onViewDocument(activeCitation.doc.name);
      onClose(sessionTranscriptRef.current);
    }
  };

  return (
    <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-start py-16 px-8 animate-in fade-in duration-700 overflow-hidden">

      {/* Header Info */}
      <div className="w-full flex flex-col items-center relative mb-12">
        <div className={`mb-6 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.3em] transition-all duration-700 ${activeCitation ? 'bg-green-600 text-white shadow-lg shadow-green-200' : 'bg-gray-50 text-gray-300'}`}>
          {activeCitation ? 'Wohnpro Beleg gefunden' : 'Wohnpro Guide hört zu'}
        </div>

        {/* Actionable Citation Card */}
        <div className="h-40 flex items-center justify-center w-full max-w-sm">
          {activeCitation && (
            <button 
              onClick={handleCitationClick}
              className="bg-white border-2 border-green-500 rounded-[2.5rem] p-6 pr-12 flex items-center gap-6 shadow-[0_32px_64px_-16px_rgba(22,163,74,0.15)] animate-in slide-in-from-bottom-8 duration-700 hover:scale-105 group active:scale-95 transition-all text-left relative overflow-hidden"
            >
              <div className="absolute top-0 right-0 p-2">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-ping" />
              </div>
              <div className="p-4 bg-green-50 rounded-2xl group-hover:bg-green-600 transition-colors shrink-0">
                <DocIcon className="w-6 h-6 text-green-600 group-hover:text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <span className="text-[9px] font-black uppercase tracking-widest text-green-600 mb-1 block">Wohnpro Wissen</span>
                <p className="text-sm font-bold text-gray-900 truncate mb-1">{activeCitation.doc.name}</p>
                <p className="text-[11px] text-gray-500 line-clamp-2 leading-relaxed italic">
                  "{activeCitation.text}..."
                </p>
              </div>
            </button>
          )}
        </div>

        <button 
          onClick={() => onClose(sessionTranscriptRef.current)}
          className="absolute top-0 right-0 p-3 hover:bg-gray-50 rounded-full transition-all text-gray-300 hover:text-black"
        >
          <CloseIcon className="w-8 h-8" />
        </button>
      </div>

      {/* Main Sphere Area */}
      <div className="flex-1 flex flex-col items-center justify-center w-full max-w-lg space-y-16">
        <div className="relative">
          <div className={`absolute inset-0 bg-black/5 rounded-full blur-[100px] scale-[2.5] transition-opacity duration-1000 ${status === 'active' ? 'opacity-100' : 'opacity-0'}`} />

          <div className={`relative w-64 h-64 rounded-full border border-gray-100 bg-white shadow-[0_48px_96px_-24px_rgba(0,0,0,0.1)] flex items-center justify-center transition-all duration-700 ${status === 'active' ? 'scale-110' : 'scale-100'}`}>
            <div 
              className={`w-52 h-52 rounded-full flex items-center justify-center transition-all duration-500 ${status === 'active' ? 'bg-black shadow-[0_0_40px_rgba(0,0,0,0.3)]' : 'bg-gray-50'}`}
              style={{ transform: `scale(${1 + (audioLevels.reduce((a, b) => a + b, 0) / 1200) * 0.1})` }}
            >
              <MicIcon className={`w-24 h-24 transition-all duration-500 ${status === 'active' ? 'text-white' : 'text-gray-200'}`} />
            </div>
          </div>
        </div>

        {/* Dynamic Waveform Visualization */}
        <div className="h-24 flex items-center justify-center gap-2 px-8 w-full max-w-md">
          {audioLevels.map((level, i) => (
            <div 
              key={i}
              className={`w-2 rounded-full transition-all duration-75 shadow-sm ${status === 'active' ? 'bg-black' : 'bg-gray-100'}`}
              style={{ 
                height: `${level}%`,
                opacity: 0.2 + (level / 100) * 0.8
              }}
            />
          ))}
        </div>
      </div>

      {/* Footer Branding */}
      <div className="mt-auto pb-10 flex flex-col items-center gap-6">
        <p className="text-[10px] text-gray-300 uppercase tracking-[0.5em] font-black">Wohnpro Guide Live AI</p>
        <div className="flex gap-4">
          <div className={`w-2 h-2 rounded-full transition-all duration-1000 ${status === 'active' ? 'bg-black scale-125' : 'bg-gray-100'}`} />
          <div className="w-2 h-2 rounded-full bg-gray-100" />
          <div className="w-2 h-2 rounded-full bg-gray-100" />
        </div>
      </div>
    </div>
  );
};

