                <p className="text-base font-black text-gray-900 truncate mb-1">{activeCitations[0].doc.name.replace(/\.(pdf|docx)$/i, '')}</p>
                <p className="text-[11px] text-gray-400 line-clamp-1 leading-relaxed italic">
