             ctx.lineCap = 'round';
             ctx.lineJoin = 'round';

             for (let x = 0; x <= width; x += 3) {
                 // Normalized x (-1 to 1) for attenuation logic
                 const nx = (x / width) * 2 - 1;

                 // Attenuation: Parabola that is 1 in center and 0 at edges
                 const attenuation = Math.pow(1 - Math.pow(nx, 2), 2);

                 // Base wave motion
                 const sine = Math.sin(x * 0.01 * line.count + time * line.speed + line.phase);

                 // Amplitude modulated by volume and attenuation
                 // Minimum amplitude 5px so it's visible when idle
                 const amplitude = (15 + vol * 100) * attenuation;

                 const y = centerY + sine * amplitude;

                 if (x === 0) ctx.moveTo(x, y);
                 else ctx.lineTo(x, y);
             }
             ctx.stroke();
          });

          rafIdRef.current = requestAnimationFrame(renderFrame);
        };
        renderFrame();

        sessionRef.current = await sessionPromise;
      } catch (err) {
        setStatus('error');
      }
    };

    startSession();

    return () => {
      isMounted = false;
      if (sessionRef.current) sessionRef.current.close();
      if (audioContextRef.current) {
        audioContextRef.current.input.close();
        audioContextRef.current.output.close();
      }
      if (rafIdRef.current) cancelAnimationFrame(rafIdRef.current);
    };
  }, [documents]);

  const handleCitationClick = (doc: Document) => {
    onViewDocument(doc.name);
    onClose(sessionTranscriptRef.current);
  };

  return (
    <div className="fixed inset-0 bg-white z-[100] flex flex-col items-center justify-start py-12 px-8 animate-in fade-in duration-700 overflow-hidden">

