export enum Role {
  USER = 'USER',
  ADMIN = 'ADMIN'
}

export type UserStatus = 'aktiv' | 'eingeladen' | 'deaktiviert';

export interface User {
  id: string;
  email: string;
  role: Role;
  status: UserStatus;
  invitedAt: string;
