}

export interface FAQItem {
  id: string;
  question: string;
  answer: string;
  category: string;
  sourceDocId: string;
  sourceDocName: string;
}

export interface Citation {
  source: string;
  text: string;
  section?: string;
  documentId?: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  citations?: Citation[];
}

