import express from 'express';
import { createClient, AuthType } from 'webdav';
import mammoth from 'mammoth';
import pdf from 'pdf-parse';

// --- Configuration ---
const PORT = process.env.PORT || 3001;
const NC_URL = process.env.NEXTCLOUD_URL?.replace(/\/$/, '');
const NC_USER = process.env.NEXTCLOUD_USER;
const NC_PASS = process.env.NEXTCLOUD_PASSWORD;
const NC_ROOT = process.env.NEXTCLOUD_ROOT_FOLDER || 'FAQ-Bot-Project';
const WEBHOOK_SECRET = process.env.WEBHOOK_SECRET;

if (!NC_URL || !NC_USER || !NC_PASS) {
  console.error("Missing NEXTCLOUD configuration in environment variables.");
  process.exit(1);
}

// --- WebDAV Client ---
const client = createClient(
  `${NC_URL}/remote.php/dav/files/${NC_USER}/`,
  {
    authType: AuthType.Password,
    username: NC_USER,
    password: NC_PASS
  }
);

const app = express();
app.use(express.json() as express.RequestHandler);

// --- Helper Functions ---

const convertPdfToText = async (buffer: Buffer): Promise<string> => {
  const data = await (pdf as any)(buffer);
  return data.text;
};

const convertDocxToText = async (buffer: Buffer): Promise<string> => {
  const result = await mammoth.extractRawText({ buffer });
  return result.value;
};

const processFile = async (filePath: string, fileName: string) => {
  console.log(`Processing: ${fileName}`);

  try {
    // 1. Download
    const fileContents = await client.getFileContents(filePath, { format: 'binary' }) as Buffer;

    // 2. Convert
    let text = '';
    const ext = fileName.split('.').pop()?.toLowerCase();

    if (ext === 'pdf') {
      text = await convertPdfToText(fileContents);
    } else if (ext === 'docx') {
      text = await convertDocxToText(fileContents);
    } else {
      console.log(`Skipping unsupported file type: ${ext}`);
      return;
    }

    // 3. Clean Text (Basic)
    text = text.replace(/\n\s*\n/g, '\n\n').trim();

    // 4. Upload to Bot Memory
    const targetName = fileName.replace(/\.(pdf|docx)$/i, '.txt');
    const targetPath = `${NC_ROOT}/02-Bot-Memory/${targetName}`;

    await client.putFileContents(targetPath, text);
    console.log(`Success: Saved extracted text to ${targetPath}`);

  } catch (err) {
    console.error(`Error processing ${fileName}:`, err);
  }
};

// --- Webhook Endpoint ---
app.post('/nextcloud-webhook', async (req, res) => {
  // 1. Verify Secret (Optional but recommended)
  // Nextcloud webhooks often send the secret in a header or query param depending on the app used (Flow, etc.)
  // Here we assume a simple query param ?secret=XYZ for simplicity
  if (WEBHOOK_SECRET && req.query.secret !== WEBHOOK_SECRET) {
    res.status(403).send('Invalid Secret');
    return;
  }

  const payload = req.body;
  console.log('Webhook received:', JSON.stringify(payload));

  /**
   * Payload parsing depends on the Nextcloud Webhook App configuration.
   * Assuming standard format: { "file": "path/to/file.pdf", "event": "create" }
   * Adjust parsing logic based on your specific Nextcloud plugin.
   */

  const rawPath = payload.file || payload.path; // Adjust based on your webhook payload structure

  if (!rawPath) {
    res.status(400).send('No file path in payload');
    return;
  }

  // 2. Security/Logic Check: Only process files in 01-Upload-Here
  const watchedFolder = `${NC_ROOT}/01-Upload-Here`;
  if (!rawPath.includes(watchedFolder)) {
    console.log(`Ignored file outside watched folder: ${rawPath}`);
    res.status(200).send('Ignored');
    return;
  }

  const fileName = rawPath.split('/').pop();

  // 3. Process
  // We don't await this so the webhook request returns immediately (Nextcloud likes fast responses)
  processFile(rawPath, fileName);

  res.status(200).send('Processing started');
});

app.listen(PORT, () => {
  console.log(`Middleware Server listening on port ${PORT}`);
  console.log(`Watched Folder: ${NC_ROOT}/01-Upload-Here`);
});

export enum Role {
  USER = 'USER',
  ADMIN = 'ADMIN'
}

export type UserStatus = 'aktiv' | 'eingeladen' | 'deaktiviert';

/**
 * Represents a registered user or a pending invitation.
 * Database Mapping: Table `users`
 */
export interface User {
  id: string; // UUID
  email: string;
  role: Role;
  status: UserStatus;
  invitedAt: string; // ISO Date string
  inviteEmailContent?: string; // AI-generated content stored for preview/history
}

/**
 * Represents a knowledge source. 
 * NOTE: 'content' stores the raw text extracted from PDF/DOCX.
 * Database Mapping: Table `documents`
 */
export interface Document {
  id: string; // UUID
  name: string;
  category: 'Recht & Struktur' | 'Selbstverständnis & Vision' | 'Teilnahme & Mitwirkung' | 'Entscheidungen & Prozesse' | 'Regeln & Hausordnung';
  uploadDate: string;
  content: string; // TEXT column in DB - used for RAG context window
  status: 'aktiv' | 'archiviert';
  fileUrl?: string; // Optional URL to original file storage (S3/GCS)
  etag?: string; // WebDAV ETag for sync optimization
}

/**
 * Defines a target audience for FAQ generation.
 * This instructs the AI on the tone, complexity, and focus of questions.
 * Database Mapping: Table `personas`
 */
export interface Persona {
  id: string; // UUID
  name: string; // e.g. "The Critic", "The Newcomer"
  description: string; // The "Meta-Dynamic" prompt instruction for the AI
  role: 'beginner' | 'expert'; // UI hint for icon/color coding
}

/**
 * AI-generated FAQ entries linked to specific documents and personas.
 * Database Mapping: Table `faqs`
 */
export interface FAQItem {
  id: string; // UUID
  question: string;
  answer: string;
  category: string;
  sourceDocId: string; // Foreign Key to Document
  sourceDocName: string; // Denormalized name for display
  personaId: string; // Foreign Key to Persona
  feedback?: 'like' | 'dislike'; // User feedback for pattern recognition
  userComment?: string; // specific comments for refining the prompt
}

/**
 * Represents a citation within a chat response.
 * JSON Structure stored within Message content if using a relational DB, 
 * or as a nested object in NoSQL.
 */
export interface Citation {
  source: string; // Document Name
  text: string; // The specific snippet quoted
  section?: string;
  documentId?: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  citations?: Citation[];
}

/**
 * Represents a conversation history.
 * Database Mapping: Table `chat_sessions`
 */
export interface ChatSession {
  id: string;
  title: string;
  messages: Message[]; // Stored as JSONB in SQL or Array in NoSQL
  createdAt: string;
}

export type View = 'chat' | 'voice' | 'admin-docs' | 'admin-users' | 'admin-personas' | 'docs-view' | 'doc-detail' | 'faq';

