                    : 'bg-gray-50 text-gray-300 cursor-not-allowed'
                  }`}
                >
                  <ArrowRightIcon className="w-7 h-7" />
                </button>
              </div>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

