    // 2. Convert
    let text = '';
    const ext = fileName.split('.').pop()?.toLowerCase();

    if (ext === 'pdf') {
      text = await convertPdfToText(fileContents);
    } else if (ext === 'docx') {
      text = await convertDocxToText(fileContents);
    } else {
      console.log(`Skipping unsupported file type: ${ext}`);
      return;
    }

    // 3. Clean Text (Basic)
    text = text.replace(/\n\s*\n/g, '\n\n').trim();

    // 4. Upload to Bot Memory
    const targetName = fileName.replace(/\.(pdf|docx)$/i, '.txt');
    const targetPath = `${NC_ROOT}/02-Bot-Memory/${targetName}`;

    await client.putFileContents(targetPath, text);
    console.log(`Success: Saved extracted text to ${targetPath}`);

  } catch (err) {
    console.error(`Error processing ${fileName}:`, err);
  }
};

// --- Webhook Endpoint ---
app.post('/nextcloud-webhook', async (req, res) => {
  // 1. Verify Secret (Optional but recommended)
  // Nextcloud webhooks often send the secret in a header or query param depending on the app used (Flow, etc.)
  // Here we assume a simple query param ?secret=XYZ for simplicity
  if (WEBHOOK_SECRET && req.query.secret !== WEBHOOK_SECRET) {
    res.status(403).send('Invalid Secret');
    return;
  }

  const payload = req.body;
  console.log('Webhook received:', JSON.stringify(payload));

  /**
   * Payload parsing depends on the Nextcloud Webhook App configuration.
   * Assuming standard format: { "file": "path/to/file.pdf", "event": "create" }
   * Adjust parsing logic based on your specific Nextcloud plugin.
   */

  const rawPath = payload.file || payload.path; // Adjust based on your webhook payload structure

  if (!rawPath) {
    res.status(400).send('No file path in payload');
    return;
  }

  // 2. Security/Logic Check: Only process files in 01-Upload-Here
  const watchedFolder = `${NC_ROOT}/01-Upload-Here`;
  if (!rawPath.includes(watchedFolder)) {
    console.log(`Ignored file outside watched folder: ${rawPath}`);
    res.status(200).send('Ignored');
    return;
  }

  const fileName = rawPath.split('/').pop();

  // 3. Process
  // We don't await this so the webhook request returns immediately (Nextcloud likes fast responses)
  processFile(rawPath, fileName);

  res.status(200).send('Processing started');
});

app.listen(PORT, () => {
  console.log(`Middleware Server listening on port ${PORT}`);
  console.log(`Watched Folder: ${NC_ROOT}/01-Upload-Here`);
});

export enum Role {
  USER = 'USER',
  ADMIN = 'ADMIN'
}

export type UserStatus = 'aktiv' | 'eingeladen' | 'deaktiviert';

/**
 * Represents a registered user or a pending invitation.
 */
export interface User {
  id: string; // UUID
  email: string;
  role: Role;
  status: UserStatus;
  invitedAt: string; // ISO Date string
  inviteEmailContent?: string;
}

/**
 * Represents a knowledge source. 
 */
export interface Document {
  id: string; // UUID
  name: string;
  category: 'Recht & Struktur' | 'Selbstverständnis & Vision' | 'Teilnahme & Mitwirkung' | 'Entscheidungen & Prozesse' | 'Regeln & Hausordnung';
  uploadDate: string;
  content: string;
  status: 'aktiv' | 'archiviert';
  fileUrl?: string;
  etag?: string;
}

/**
 * Defines a target audience for FAQ generation.
 */
export interface Persona {
  id: string; // UUID
  name: string;
  description: string;
  role: 'beginner' | 'expert';
}

/**
 * AI-generated FAQ entries linked to specific documents and personas.
 */
export interface FAQItem {
  id: string; // UUID
  question: string;
  answer: string;
  category: string;
  sourceDocId: string;
  sourceDocName: string;
  personaId: string;
  feedback?: 'like' | 'dislike';
  userComment?: string;
}

/**
 * Proposed FAQ items from the AI Agent evaluating chat history.
 */
export interface FAQSuggestion extends Partial<FAQItem> {
  id: string;
  suggestedAt: string;
  originalSessionId: string;
}

export interface Citation {
  source: string;
  text: string;
  section?: string;
  documentId?: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  citations?: Citation[];
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: string;
}

export type View = 'chat' | 'voice' | 'admin-docs' | 'admin-users' | 'admin-personas' | 'docs-view' | 'doc-detail' | 'faq';

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Citation, Role, FAQItem, Persona, ChatSession, FAQSuggestion } from "../types";

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async askQuestion(
    question: string, 
    documents: Document[], 
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    const ai = this.getAI();
    const context = documents.map(d => `[DOC: ${d.name}] ${d.content}`).join('\n\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `Wissensbasis:\n${context}\n\nFrage: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.1,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { type: Type.STRING },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING },
                    text: { type: Type.STRING },
                    section: { type: Type.STRING },
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const data = JSON.parse(response.text || '{}');
      return {
        text: data.answer || "Fehler beim Laden.",
        citations: data.citations || []
      };
    } catch (e) {
      return { text: "API Error", citations: [] };
    }
  }

  async generateFAQs(doc: Document, persona: Persona): Promise<Partial<FAQItem>[]> {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analysiere das folgende Dokument des Wohnprojekts.

        DEINE PERSONA / ZIELGRUPPE:
        Name: ${persona.name}
        Beschreibung: ${persona.description}

        AUFGABE:
        Extrahiere basierend auf deiner Persona-Beschreibung 2 bis 4 Fragen, die genau DIESE Person an das Dokument stellen würde.

        DOKUMENT:
        Name: ${doc.name}
        Inhalt: ${doc.content.substring(0, 15000)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                answer: { type: Type.STRING },
                category: { type: Type.STRING }
              },
              required: ["question", "answer", "category"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return [];
    }
  }

  async analyzeDiscussions(session: ChatSession, persona: Persona, documents: Document[]): Promise<Partial<FAQSuggestion>[]> {
    const ai = this.getAI();
    const transcript = session.messages.map(m => `${m.role.toUpperCase()}: ${m.text}`).join('\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Du bist der Kurator des Wohnpro Guides. Analysiere das folgende Gesprächsprotokoll zwischen einem Bewohner und der KI.

        PERSONA FÜR DIE FAQ:
        ${persona.name}: ${persona.description}

        TRANSKRIPT:
        ${transcript}

        AUFGABE:
        Identifiziere, ob im Gespräch wertvolle, neue Fragen gestellt wurden, die noch nicht in den Standard-FAQs enthalten sind, aber für die Persona "${persona.name}" extrem wichtig sind. 
        Die Antwort MUSS auf dem Wissen der Dokumente basieren.
        Erzeuge 1 bis 2 neue FAQ-Vorschläge.

        WISSENSBASIS:
        ${documents.slice(0, 5).map(d => `[${d.name}]: ${d.content.substring(0, 2000)}`).join('\n')}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                answer: { type: Type.STRING },
                category: { type: Type.STRING },
                sourceDocName: { type: Type.STRING, description: "Der Name des Dokuments, auf dem die Antwort basiert" }
              },
              required: ["question", "answer", "category", "sourceDocName"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return [];
    }
  }

  async generateInvitation(email: string, role: Role, documents: Document[]): Promise<string> {
    const ai = this.getAI();
    const houseContext = documents.slice(0, 2).map(d => d.content).join(' ');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Erstelle eine Einladung für Bewohner ${email} mit Rolle ${role}. Kontext: ${houseContext}`,
      config: {
        systemInstruction: "Du bist ein professioneller Verwalter eines modernen Wohnpro.",
      }
    });
    return response.text || "Willkommen im Wohnpro!";
  }

  async verifyUser(email: string): Promise<{ success: boolean; reason: string }> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Prüfe die E-Mail "${email}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            success: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["success", "reason"]
        }
      }
    });
    return JSON.parse(response.text || '{"success":true, "reason": "Verifiziert"}');
  }
}

