import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Citation, Role, FAQItem, Persona, ChatSession, FAQSuggestion } from "../types";

const ALLOWED_CATEGORIES = [
  "Bau",
  "Gemeinsames leben",
  "Nachhaltigkeit",
  "Rechtsform & Finanzen",
  "Solidarität & Bezahlbarkeit",
  "Und sonst",
  "Vielfalt & Inklusion"
];

const CATEGORY_INSTRUCTION = `
Ordne jede Frage STRENG einer dieser Kategorien zu:
- Bau
- Gemeinsames leben
- Nachhaltigkeit
- Rechtsform & Finanzen
- Solidarität & Bezahlbarkeit
- Und sonst
- Vielfalt & Inklusion
`;

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async askQuestion(
    question: string, 
    documents: Document[], 
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    const ai = this.getAI();
    const context = documents.map(d => `[DOC: ${d.name}] ${d.content}`).join('\n\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `Wissensbasis:\n${context}\n\nFrage: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.1,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { type: Type.STRING },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING },
                    text: { type: Type.STRING },
                    section: { type: Type.STRING },
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const data = JSON.parse(response.text || '{}');
      return {
        text: data.answer || "Fehler beim Laden.",
        citations: data.citations || []
      };
    } catch (e) {
      return { text: "API Error", citations: [] };
    }
  }

  async generateFAQs(doc: Document, persona: Persona): Promise<Partial<FAQItem>[]> {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analysiere das folgende Dokument des Wohnprojekts.

        DEINE PERSONA / ZIELGRUPPE:
        Name: ${persona.name}
        Beschreibung: ${persona.description}

        AUFGABE:
        Extrahiere basierend auf deiner Persona-Beschreibung 2 bis 4 Fragen, die genau DIESE Person an das Dokument stellen würde.

        ${CATEGORY_INSTRUCTION}

        DOKUMENT:
        Name: ${doc.name}
        Inhalt: ${doc.content.substring(0, 15000)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                answer: { type: Type.STRING },
                category: { type: Type.STRING, enum: ALLOWED_CATEGORIES }
              },
              required: ["question", "answer", "category"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      console.error(e);
      return [];
    }
  }

  async analyzeDiscussions(session: ChatSession, persona: Persona, documents: Document[], existingFaqs: FAQItem[]): Promise<Partial<FAQSuggestion>[]> {
    const ai = this.getAI();
    const transcript = session.messages.map(m => `${m.role.toUpperCase()}: ${m.text}`).join('\n');

    // Build list of existing questions to avoid duplicates
    const existingQuestionsList = existingFaqs
      .filter(f => f.personaId === persona.id)
      .map(f => `- ${f.question} (Kategorie: ${f.category})`)
      .join('\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Du bist der Kurator des Wohnpro Guides. Analysiere das folgende Gesprächsprotokoll zwischen einem Bewohner und der KI.

        PERSONA FÜR DIE FAQ:
        ${persona.name}: ${persona.description}

        BEREITS EXISTIERENDE FAQs (NICHT WIEDERHOLEN!):
        ${existingQuestionsList.substring(0, 8000)}

        TRANSKRIPT:
        ${transcript}

        AUFGABE:
        1. Identifiziere Fragen aus dem Transkript, die für die Persona wichtig sind.
        2. PRÜFE: Wurde diese Frage in der Liste "BEREITS EXISTIERENDE FAQs" schon beantwortet? Wenn JA, ignoriere sie. Erstelle KEINE Duplikate.
        3. Wenn die Frage NEU ist, erstelle einen FAQ-Eintrag.
        4. Die Antwort MUSS auf dem Wissen der Dokumente basieren.

        ${CATEGORY_INSTRUCTION}

        WISSENSBASIS:
        ${documents.slice(0, 5).map(d => `[${d.name}]: ${d.content.substring(0, 2000)}`).join('\n')}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                answer: { type: Type.STRING },
                category: { type: Type.STRING, enum: ALLOWED_CATEGORIES },
                sourceDocName: { type: Type.STRING, description: "Der Name des Dokuments, auf dem die Antwort basiert" }
              },
              required: ["question", "answer", "category", "sourceDocName"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      return [];
    }
  }

  async generateInvitation(email: string, role: Role, documents: Document[]): Promise<string> {
    const ai = this.getAI();
    const houseContext = documents.slice(0, 2).map(d => d.content).join(' ');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Erstelle eine Einladung für Bewohner ${email} mit Rolle ${role}. Kontext: ${houseContext}`,
      config: {
        systemInstruction: "Du bist ein professioneller Verwalter eines modernen Wohnpro.",
      }
    });
    return response.text || "Willkommen im Wohnpro!";
  }

  async verifyUser(email: string): Promise<{ success: boolean; reason: string }> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Prüfe die E-Mail "${email}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            success: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["success", "reason"]
        }
      }
    });
    return JSON.parse(response.text || '{"success":true, "reason": "Verifiziert"}');
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useCallback } from 'react';
import { View, ChatSession, Document, User, Message, Role, UserStatus, FAQItem, Persona, FAQSuggestion } from './types';
import { INITIAL_DOCUMENTS, INITIAL_USERS, INITIAL_PERSONAS } from './constants';
import LoginView from './components/LoginView';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import DocumentDetail from './components/DocumentDetail';
import LandingPage from './components/LandingPage';
import FAQView from './components/FAQView';
import { gemini } from './services/geminiService';
import { isNextcloudConfigured, fetchNextcloudDocuments, fetchNextcloudUsers } from './services/nextcloudService';

const STORAGE_KEY = 'wohnprojekt_docs_cache';
const FAQ_STORAGE_KEY = 'wohnprojekt_faq_cache';
const PERSONA_STORAGE_KEY = 'wohnprojekt_persona_cache';
const SUGGESTION_STORAGE_KEY = 'wohnprojekt_faq_suggestions';
const SESSIONS_STORAGE_KEY = 'wohnprojekt_chat_sessions';

const App: React.FC = () => {
  const [showLanding, setShowLanding] = useState(true);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [documents, setDocuments] = useState<Document[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : INITIAL_DOCUMENTS;
  });

  const [faqs, setFaqs] = useState<FAQItem[]>(() => {
    const saved = localStorage.getItem(FAQ_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [suggestions, setSuggestions] = useState<FAQSuggestion[]>(() => {
    const saved = localStorage.getItem(SUGGESTION_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [personas, setPersonas] = useState<Persona[]>(() => {
    const saved = localStorage.getItem(PERSONA_STORAGE_KEY);
    return saved ? JSON.parse(saved) : INITIAL_PERSONAS;
  });

  const [sessions, setSessions] = useState<ChatSession[]>(() => {
    const saved = localStorage.getItem(SESSIONS_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [activeDoc, setActiveDoc] = useState<{ doc: Document, highlightText?: string, highlightSection?: string } | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(documents));
  }, [documents]);

  useEffect(() => {
    localStorage.setItem(FAQ_STORAGE_KEY, JSON.stringify(faqs));
  }, [faqs]);

  useEffect(() => {
    localStorage.setItem(PERSONA_STORAGE_KEY, JSON.stringify(personas));
  }, [personas]);

  useEffect(() => {
    localStorage.setItem(SUGGESTION_STORAGE_KEY, JSON.stringify(suggestions));
  }, [suggestions]);

  useEffect(() => {
    localStorage.setItem(SESSIONS_STORAGE_KEY, JSON.stringify(sessions));
  }, [sessions]);

  // Nextcloud Sync
  useEffect(() => {
    const syncNextcloud = async () => {
      if (isNextcloudConfigured()) {
        const ncDocs = await fetchNextcloudDocuments(documents);
        if (ncDocs.length > 0) setDocuments(ncDocs);

        const ncUsers = await fetchNextcloudUsers();
        if (ncUsers.length > 0) setUsers(ncUsers);
      }
    };
    syncNextcloud();
    const interval = setInterval(syncNextcloud, 60000); // Sync every minute
    return () => clearInterval(interval);
  }, []);

  const handleLogin = (email: string) => {
    const user = users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user && (user.status === 'aktiv' || user.status === 'eingeladen')) {
      setCurrentUser({ ...user, status: 'aktiv' });
    } else {
      alert("Zugriff verweigert. Bitte wende dich an die Wohnprojekt-Verwaltung.");
    }
  };

  const getActiveMessages = () => {
    if (!activeSessionId) return [];
    return sessions.find(s => s.id === activeSessionId)?.messages || [];
  };

  const analyzeLatestDiscussion = async (session: ChatSession) => {
    if (session.messages.length < 2) return;

    // Pick the most relevant persona for the user, or just the first one as default
    const persona = personas[0]; 
    if (!persona) return;

    try {
      // Pass existing FAQs to filtering logic
      const newSuggestions = await gemini.analyzeDiscussions(session, persona, documents, faqs);

      const suggestionsWithMeta: FAQSuggestion[] = newSuggestions.map(s => ({
        ...s,
        id: Math.random().toString(36).substr(2, 9),
        suggestedAt: new Date().toISOString(),
        originalSessionId: session.id,
        personaId: persona.id
      })) as FAQSuggestion[];

      setSuggestions(prev => {
        // Double check against existing suggestions in state as well
        const existingQuestions = new Set(prev.map(p => p.question));
        const uniqueNew = suggestionsWithMeta.filter(s => !existingQuestions.has(s.question));
        return [...prev, ...uniqueNew];
      });
    } catch (e) {
      console.error("Analysis Error:", e);
    }
  };

  const handleAddDocument = async (doc: Document) => {
    setDocuments(prev => [...prev, doc]);

    // Trigger automatic FAQ generation for all personas
    for (const persona of personas) {
      try {
        const generated = await gemini.generateFAQs(doc, persona);
        const newSuggestions: FAQSuggestion[] = generated.map(g => ({
          ...g,
          id: Math.random().toString(36).substr(2, 9),
          suggestedAt: new Date().toISOString(),
          sourceDocName: doc.name,
          personaId: persona.id,
          category: g.category || doc.category,
        }));
        setSuggestions(prev => [...prev, ...newSuggestions]);
      } catch (e) {
        console.error("Auto-FAQ Generation Error:", e);
      }
    }
  };

  const handleSendMessage = async (text: string) => {
    let currentId = activeSessionId;
    let currentSessions = [...sessions];

    if (!currentId) {
      currentId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: currentId,
        title: text.substring(0, 30) + '...',
        messages: [],
        createdAt: new Date().toISOString()
      };
      currentSessions = [newSession, ...currentSessions];
      setActiveSessionId(currentId);
      setSessions(currentSessions);
    }

    const userMsg: Message = { role: 'user', text };
    const sessionIndex = currentSessions.findIndex(s => s.id === currentId);
    currentSessions[sessionIndex].messages.push(userMsg);
    setSessions([...currentSessions]);

    setIsLoading(true);
    try {
      const history = currentSessions[sessionIndex].messages.map(m => ({ role: m.role, text: m.text }));
      const response = await gemini.askQuestion(text, documents, history);

      const aiMsg: Message = { 
        role: 'model', 
        text: response.text, 
        citations: response.citations 
      };

      currentSessions[sessionIndex].messages.push(aiMsg);
      setSessions([...currentSessions]);

      // Trigger background analysis
      analyzeLatestDiscussion(currentSessions[sessionIndex]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAcceptSuggestion = (suggestion: FAQSuggestion) => {
    const newFaq: FAQItem = {
      id: Math.random().toString(36).substr(2, 9),
      question: suggestion.question || '',
      answer: suggestion.answer || '',
      category: suggestion.category || 'Und sonst',
      sourceDocId: '', 
      sourceDocName: suggestion.sourceDocName || 'Gespräch',
      personaId: suggestion.personaId || personas[0].id
    };
    setFaqs(prev => [...prev, newFaq]);
    setSuggestions(prev => prev.filter(s => s.id !== suggestion.id));
  };

  const handleIgnoreSuggestion = (id: string) => {
    setSuggestions(prev => prev.filter(s => s.id !== id));
  };

  if (showLanding && !currentUser) {
    return <LandingPage onStart={() => setShowLanding(false)} />;
  }

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)}
        sessions={sessions}
        currentView={currentView}
        setView={(v) => { setCurrentView(v); setActiveDoc(null); if(v==='chat') setActiveSessionId(null); }}
        onSelectSession={(id) => { setActiveSessionId(id); setCurrentView('chat'); setActiveDoc(null); }}
      />

      <main className="flex-1 flex flex-col relative overflow-hidden h-full">
        {/* Header Mobile */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-gray-100 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2">
            <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/></svg>
          </button>
          <span className="font-bold text-gray-900">Wohnpro Guide</span>
          <div className="w-10" />
        </div>

        <div className="flex-1 relative overflow-hidden">
          {activeDoc ? (
            <DocumentDetail 
              document={activeDoc.doc} 
              onClose={() => setActiveDoc(null)} 
              highlightText={activeDoc.highlightText}
              highlightSection={activeDoc.highlightSection}
            />
          ) : currentView === 'chat' ? (
            <ChatView 
              messages={getActiveMessages()} 
              onSendMessage={handleSendMessage}
              onEnterVoice={() => setCurrentView('voice')}
              onViewDocument={(name, text, section) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc, highlightText: text, highlightSection: section });
              }}
              isLoading={isLoading}
            />
          ) : currentView === 'faq' ? (
            <FAQView 
              faqs={faqs}
              suggestions={suggestions}
              personas={personas}
              onViewSource={(name) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc });
              }}
              onUpdateFaq={(id, updates) => setFaqs(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f))}
              onExport={() => alert("CSV Export gestartet...")}
              onAcceptSuggestion={handleAcceptSuggestion}
              onIgnoreSuggestion={handleIgnoreSuggestion}
            />
          ) : currentView === 'voice' ? (
            <VoiceMode 
              documents={documents}
              onClose={(transcript) => {
                if (transcript && transcript.length > 0) {
                  const newId = Math.random().toString(36).substr(2, 9);
                  const newSession: ChatSession = {
                    id: newId,
                    title: 'Sprachgespräch ' + new Date().toLocaleTimeString(),
                    messages: transcript,
                    createdAt: new Date().toISOString()
                  };
                  setSessions(prev => [newSession, ...prev]);
                  analyzeLatestDiscussion(newSession);
                }
                setCurrentView('chat');
              }}
              onViewDocument={(name) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc });
              }}
            />
          ) : currentView === 'docs-view' ? (
            <div className="p-10 space-y-8 overflow-y-auto h-full no-scrollbar">
              <h1 className="text-4xl font-black mb-10">Dokumente</h1>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {documents.map(doc => (
                  <button 
                    key={doc.id} 
                    onClick={() => setActiveDoc({ doc })}
                    className="text-left bg-white p-8 rounded-[2.5rem] border border-gray-100 hover:shadow-2xl transition-all group"
                  >
                    <div className="p-4 bg-gray-50 rounded-2xl mb-6 group-hover:bg-black group-hover:text-white transition-all w-fit">
                      <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
                    </div>
                    <h3 className="font-bold text-lg mb-2 line-clamp-2">{doc.name}</h3>
                    <p className="text-xs text-gray-400 font-black uppercase tracking-widest">{doc.category}</p>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <AdminPanel 
              activeTab={currentView.startsWith('admin-users') ? 'users' : currentView.startsWith('admin-personas') ? 'personas' : 'docs'}
              setActiveTab={(tab) => setCurrentView(`admin-${tab}` as View)}
              documents={documents}
              users={users}
              personas={personas}
              onAddDoc={handleAddDocument}
              onRemoveDoc={(id) => setDocuments(prev => prev.filter(d => d.id !== id))}
              onInviteUser={(email, role, content) => setUsers(prev => [...prev, { id: Math.random().toString(), email, role, status: 'eingeladen', invitedAt: new Date().toISOString(), inviteEmailContent: content }])}
              onRemoveUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))}
              onAddPersona={(p) => setPersonas(prev => [...prev, p])}
              onUpdatePersona={(p) => setPersonas(prev => prev.map(old => old.id === p.id ? p : old))}
              onRemovePersona={(id) => setPersonas(prev => prev.filter(p => p.id !== id))}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

