import { Document, User, Role, UserStatus, Category } from '../types';

// These should be defined in your build environment (e.g. .env file)
const NC_URL = process.env.NEXTCLOUD_URL?.replace(/\/$/, '');
const NC_USER = process.env.NEXTCLOUD_USER;
const NC_PASS = process.env.NEXTCLOUD_PASSWORD;
const NC_ROOT = process.env.NEXTCLOUD_ROOT_FOLDER || 'FAQ-Bot-Project';

const getAuthHeaders = () => {
  return {
    'Authorization': 'Basic ' + btoa(`${NC_USER}:${NC_PASS}`),
  };
};

export const isNextcloudConfigured = (): boolean => {
  return !!(NC_URL && NC_USER && NC_PASS);
};

// Helper to determine category based on filename (mirrors logic in AdminPanel)
const determineCategory = (name: string): Category => {
  const n = name.toLowerCase();
  if (n.includes('bau') || n.includes('architektur') || n.includes('plan')) return 'Bau';
  if (n.includes('vision') || n.includes('leben') || n.includes('zusammen') || n.includes('gemein')) return 'Gemeinsames leben';
  if (n.includes('nachhaltig') || n.includes('energie') || n.includes('ökolog')) return 'Nachhaltigkeit';
  if (n.includes('recht') || n.includes('finanz') || n.includes('kosten') || n.includes('vertrag') || n.includes('satzung')) return 'Rechtsform & Finanzen';
  if (n.includes('solidar') || n.includes('sozial') || n.includes('miete') || n.includes('entgelt')) return 'Solidarität & Bezahlbarkeit';
  if (n.includes('vielfalt') || n.includes('inklusion') || n.includes('barriere')) return 'Vielfalt & Inklusion';
  return 'Und sonst';
};

export const fetchNextcloudUsers = async (): Promise<User[]> => {
  if (!isNextcloudConfigured()) return [];

  // WebDAV URL to the CSV file
  // Pattern: https://cloud.domain.com/remote.php/dav/files/USER/FOLDER/FILE
  const csvUrl = `${NC_URL}/remote.php/dav/files/${NC_USER}/${NC_ROOT}/99-Admin/users.csv`;

  try {
    const response = await fetch(csvUrl, {
      method: 'GET',
      headers: getAuthHeaders()
    });

    if (!response.ok) {
      if (response.status !== 404) {
         console.warn(`Nextcloud: Failed to fetch users.csv (${response.status})`);
      }
      return [];
    }

    const text = await response.text();
    const lines = text.split('\n').filter(l => l.trim().length > 0);
    const users: User[] = [];

    // Check for header
    const startRow = lines[0].toLowerCase().includes('email') ? 1 : 0;

    for (let i = startRow; i < lines.length; i++) {
      // CSV Format: email, role, status
      const cols = lines[i].split(',').map(c => c.trim());
      if (cols.length >= 2) {
        const email = cols[0];
        const role = cols[1].toUpperCase() === 'ADMIN' ? Role.ADMIN : Role.USER;
        const status = (cols[2]?.toLowerCase() as UserStatus) || 'aktiv';

        if (email.includes('@')) {
          users.push({
            id: `nc-user-${i}`,
            email,
            role,
            status,
            invitedAt: new Date().toISOString()
          });
        }
      }
    }

    console.log(`Nextcloud: Synced ${users.length} users.`);
    return users;

  } catch (e) {
    console.error("Nextcloud User Sync Error:", e);
    return [];
  }
};

/**
 * Fetches documents from Nextcloud.
 * Uses ETags to only download content if the file has changed on the server.
 * Returns the full list of valid documents currently on the server.
 */
export const fetchNextcloudDocuments = async (currentDocs: Document[] = []): Promise<Document[]> => {
  if (!isNextcloudConfigured()) return [];

  const folderUrl = `${NC_URL}/remote.php/dav/files/${NC_USER}/${NC_ROOT}/02-Bot-Memory/`;

  try {
    // PROPFIND to list files with their properties (getetag, getlastmodified)
    const response = await fetch(folderUrl, {
      method: 'PROPFIND',
      headers: {
        ...getAuthHeaders(),
        'Depth': '1', // Only immediate children
        'Content-Type': 'application/xml'
      },
      // Request specific properties
      body: `<?xml version="1.0"?>
        <d:propfind  xmlns:d="DAV:">
          <d:prop>
            <d:getlastmodified/>
            <d:getetag/>
            <d:resourcetype/>
          </d:prop>
        </d:propfind>`
    });

    if (!response.ok) {
      console.warn(`Nextcloud: Failed to access Bot Memory folder (${response.status})`);
      return currentDocs; // Return stale cache on error to prevent wiping UI
    }

    const xmlText = await response.text();
    const parser = new DOMParser();
    const xmlDoc = parser.parseFromString(xmlText, "text/xml");

    // Find all 'response' tags.
    const responses = xmlDoc.getElementsByTagNameNS("*", "response");
    const docs: Document[] = [];
    let downloadCount = 0;

    for (let i = 0; i < responses.length; i++) {
      const resp = responses[i];
      const hrefNode = resp.getElementsByTagNameNS("*", "href")[0];
      const propNode = resp.getElementsByTagNameNS("*", "prop")[0];

      let href = hrefNode?.textContent;
      if (!href) continue;

      href = decodeURIComponent(href);

      // Filter for .txt files
      if (!href.endsWith('.txt')) continue;

      // Check if it is a directory (shouldn't be based on .txt, but safe check)
      const resType = propNode?.getElementsByTagNameNS("*", "resourcetype")[0];
      if (resType && resType.getElementsByTagNameNS("*", "collection").length > 0) continue;

      // Extract ETag
      let etag = propNode?.getElementsByTagNameNS("*", "getetag")[0]?.textContent || '';
      // Sanitize ETag quotes
      etag = etag.replace(/^["']|["']$/g, '');

      // Extract filename
      const fileName = href.split('/').pop() || 'unknown';
      if (fileName.startsWith('.')) continue; // Skip hidden files

      const docId = `nc-doc-${fileName}`;
      const name = fileName.replace(/\.txt$/i, '');
      const downloadUrl = href.startsWith('http') ? href : `${NC_URL}${href}`;

      // SMART SYNC: Check if we already have this doc with the same ETag
      const existingDoc = currentDocs.find(d => d.id === docId);

      if (existingDoc && existingDoc.etag === etag) {
        // CONTENT UNCHANGED: Reuse existing document
        docs.push(existingDoc);
        continue;
      }

      // CONTENT CHANGED or NEW: Download content
      try {
        const fileRes = await fetch(downloadUrl, {
          method: 'GET',
          headers: getAuthHeaders()
        });

        if (fileRes.ok) {
          const content = await fileRes.text();
          downloadCount++;

          docs.push({
            id: docId,
            name: name,
            category: determineCategory(name),
            uploadDate: new Date().toLocaleDateString('de-DE'), 
            content: content,
            status: 'aktiv',
            fileUrl: downloadUrl,
            etag: etag // Store ETag for next sync
          });
        }
      } catch (err) {
        console.error(`Failed to download ${fileName}`, err);
      }
    }

    if (downloadCount > 0) {
      console.log(`Nextcloud: Synced ${docs.length} documents. (${downloadCount} downloaded, ${docs.length - downloadCount} cached)`);
    }

    return docs;

  } catch (e) {
    console.error("Nextcloud Doc Sync Error:", e);
    // Return currentDocs to ensure we don't wipe the UI if the network fails
    return currentDocs;
  }
};

import React, { useState, useCallback, useRef } from 'react';
import { Document as AppDocument, User, Role, UserStatus, Persona, Category } from '../types';
import { PlusIcon, TrashIcon, DocIcon, CloseIcon, UserPlusIcon, CheckCircleIcon, ClockIcon, AlertIcon, ShieldIcon, ArrowRightIcon, HelpIcon } from './Icons';
import { gemini } from '../services/geminiService';
import * as mammoth from 'mammoth';
import * as pdfjs from 'pdfjs-dist';

// Configure PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@4.0.379/build/pdf.worker.min.mjs`;

interface AdminPanelProps {
  documents: AppDocument[];
  users: User[];
  personas: Persona[];
  onAddDoc: (doc: AppDocument) => void;
  onRemoveDoc: (id: string) => void;
  onInviteUser: (email: string, role: Role, content: string) => void;
  onRemoveUser: (id: string) => void;
  onAddPersona: (persona: Persona) => void;
  onUpdatePersona: (persona: Persona) => void;
  onRemovePersona: (id: string) => void;
  activeTab: 'docs' | 'users' | 'personas';
  setActiveTab: (tab: 'docs' | 'users' | 'personas') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, users, personas, onAddDoc, onRemoveDoc, onInviteUser, onRemoveUser, onAddPersona, onUpdatePersona, onRemovePersona, activeTab, setActiveTab 
}) => {
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [showPersonaModal, setShowPersonaModal] = useState(false);
  const [editingPersona, setEditingPersona] = useState<Persona | null>(null);

  const [inviteStep, setInviteStep] = useState<'input' | 'preview' | 'verifying'>('input');
  const [isDragging, setIsDragging] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<string | null>(null);

  // Invite State
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<Role>(Role.USER);
  const [aiDraft, setAiDraft] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [verificationResult, setVerificationResult] = useState<{ success: boolean; reason: string } | null>(null);

  // Persona State
  const [personaName, setPersonaName] = useState('');
  const [personaDesc, setPersonaDesc] = useState('');
  const [personaRole, setPersonaRole] = useState<'beginner' | 'expert'>('beginner');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const parseDocx = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value;
  };

  const parsePdf = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;
    let fullText = '';
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const pageText = textContent.items.map((item: any) => item.str).join(' ');
      fullText += pageText + '\n';
    }
    return fullText;
  };

  const determineCategory = (name: string): Category => {
    const n = name.toLowerCase();
    if (n.includes('bau') || n.includes('architektur') || n.includes('plan')) return 'Bau';
    if (n.includes('vision') || n.includes('leben') || n.includes('zusammen') || n.includes('gemein')) return 'Gemeinsames leben';
    if (n.includes('nachhaltig') || n.includes('energie') || n.includes('ökolog')) return 'Nachhaltigkeit';
    if (n.includes('recht') || n.includes('finanz') || n.includes('kosten') || n.includes('vertrag') || n.includes('satzung')) return 'Rechtsform & Finanzen';
    if (n.includes('solidar') || n.includes('sozial') || n.includes('miete') || n.includes('entgelt')) return 'Solidarität & Bezahlbarkeit';
    if (n.includes('vielfalt') || n.includes('inklusion') || n.includes('barriere')) return 'Vielfalt & Inklusion';
    return 'Und sonst';
  };

  const handleFiles = async (files: FileList) => {
    setIsDragging(false);
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const type = file.name.split('.').pop()?.toLowerCase();

      if (type !== 'pdf' && type !== 'docx') {
        alert(`Dateityp .${type} wird nicht unterstützt. Bitte lade nur .pdf oder .docx hoch.`);
        continue;
      }

      setUploadProgress(`Lese ${file.name}...`);
      try {
        const text = type === 'pdf' ? await parsePdf(file) : await parseDocx(file);

        const newDoc: AppDocument = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          category: determineCategory(file.name),
          uploadDate: new Date().toLocaleDateString('de-DE'),
          content: text,
          status: 'aktiv'
        };

        onAddDoc(newDoc);
      } catch (err) {
        console.error("Fehler beim Verarbeiten:", err);
        alert(`Fehler beim Einlesen von ${file.name}`);
      }
    }
    setUploadProgress(null);
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files) {
      handleFiles(e.dataTransfer.files);
    }
  }, []);

  const handlePrepareInvitation = async () => {
    if (!inviteEmail.includes('@')) return;
    setIsProcessing(true);
    try {
      const draft = await gemini.generateInvitation(inviteEmail, inviteRole, documents);
      setAiDraft(draft);
      setInviteStep('preview');
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFinalizeInvite = async () => {
    setInviteStep('verifying');
    setIsProcessing(true);
    const verification = await gemini.verifyUser(inviteEmail);
    setVerificationResult(verification);
    setTimeout(() => {
      if (verification.success) {
        onInviteUser(inviteEmail, inviteRole, aiDraft);
        setShowInviteModal(false);
        resetInvite();
      }
      setIsProcessing(false);
    }, 2000);
  };

  const resetInvite = () => {
    setInviteStep('input');
    setInviteEmail('');
    setAiDraft('');
    setVerificationResult(null);
  };

  const handleSavePersona = () => {
    if (!personaName || !personaDesc) return;

    if (editingPersona) {
      onUpdatePersona({
        ...editingPersona,
        name: personaName,
        description: personaDesc,
        role: personaRole
      });
    } else {
      onAddPersona({
        id: Math.random().toString(36).substr(2, 9),
        name: personaName,
        description: personaDesc,
        role: personaRole
      });
    }
    setShowPersonaModal(false);
    setEditingPersona(null);
    setPersonaName('');
    setPersonaDesc('');
  };

  const openPersonaModal = (p?: Persona) => {
    if (p) {
      setEditingPersona(p);
      setPersonaName(p.name);
      setPersonaDesc(p.description);
      setPersonaRole(p.role);
    } else {
      setEditingPersona(null);
      setPersonaName('');
      setPersonaDesc('');
      setPersonaRole('beginner');
    }
    setShowPersonaModal(true);
  };

  const getStatusIcon = (status: UserStatus) => {
    switch (status) {
      case 'aktiv': return <ShieldIcon className="w-5 h-5 text-blue-500" />;
      case 'eingeladen': return <ClockIcon className="w-5 h-5 text-gray-300" />;
      case 'deaktiviert': return <AlertIcon className="w-5 h-5 text-red-400" />;
      default: return null;
    }
  };

  return (
    <div className="flex-1 flex flex-col h-full bg-white overflow-hidden">
      {/* Sticky Tab Header */}
      <div className="sticky top-0 z-20 bg-white/80 backdrop-blur-md border-b border-gray-100">
        <div className="max-w-4xl mx-auto px-6 pt-10">
