import React, { useState, useCallback, useRef } from 'react';
import { Document as AppDocument, User, Role, UserStatus, Persona, Category, Milestone } from '../types';
import { PlusIcon, TrashIcon, DocIcon, CloseIcon, UserPlusIcon, CheckCircleIcon, ClockIcon, AlertIcon, ShieldIcon, ArrowRightIcon, HelpIcon, CalendarIcon, DownloadIcon } from './Icons';
import { gemini } from '../services/geminiService';
import * as mammoth from 'mammoth';
import * as pdfjs from 'pdfjs-dist';
import * as XLSX from 'xlsx';

// Configure PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@4.0.379/build/pdf.worker.min.mjs`;

interface AdminPanelProps {
  documents: AppDocument[];
  users: User[];
  personas: Persona[];
  milestones?: Milestone[];
  onAddDoc: (doc: AppDocument) => void;
  onRemoveDoc: (id: string) => void;
  onInviteUser: (email: string, role: Role, content: string) => void;
  onRemoveUser: (id: string) => void;
  onAddPersona: (persona: Persona) => void;
  onUpdatePersona: (persona: Persona) => void;
  onRemovePersona: (id: string) => void;
  onUpdateMilestones: (milestones: Milestone[]) => void;
  activeTab: 'docs' | 'users' | 'personas' | 'timeline';
  setActiveTab: (tab: 'docs' | 'users' | 'personas' | 'timeline') => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  documents, users, personas, milestones = [], onAddDoc, onRemoveDoc, onInviteUser, onRemoveUser, onAddPersona, onUpdatePersona, onRemovePersona, onUpdateMilestones, activeTab, setActiveTab 
}) => {
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [showPersonaModal, setShowPersonaModal] = useState(false);
  const [showMilestoneModal, setShowMilestoneModal] = useState(false);
  const [editingPersona, setEditingPersona] = useState<Persona | null>(null);

  const [inviteStep, setInviteStep] = useState<'input' | 'preview' | 'verifying'>('input');
  const [isDragging, setIsDragging] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<string | null>(null);

  // Invite State
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<Role>(Role.USER);
  const [aiDraft, setAiDraft] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [verificationResult, setVerificationResult] = useState<{ success: boolean; reason: string } | null>(null);

  // Persona State
  const [personaName, setPersonaName] = useState('');
  const [personaDesc, setPersonaDesc] = useState('');
  const [personaRole, setPersonaRole] = useState<'beginner' | 'expert'>('beginner');

  // Milestone State (New)
  const [newMilestone, setNewMilestone] = useState<Partial<Milestone>>({
     title: '', startDate: '', endDate: '', owner: '', progress: 0, status: 'planned', description: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const parseDocx = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value;
  };

  const parsePdf = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;
    let fullText = '';
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const pageText = textContent.items.map((item: any) => item.str).join(' ');
      fullText += pageText + '\n';
    }
    return fullText;
  };

  const determineCategory = (name: string): Category => {
    const n = name.toLowerCase();
    if (n.includes('bau') || n.includes('architektur') || n.includes('plan')) return 'Bau';
    if (n.includes('vision') || n.includes('leben') || n.includes('zusammen') || n.includes('gemein')) return 'Gemeinsames leben';
    if (n.includes('nachhaltig') || n.includes('energie') || n.includes('ökolog')) return 'Nachhaltigkeit';
    if (n.includes('recht') || n.includes('finanz') || n.includes('kosten') || n.includes('vertrag') || n.includes('satzung')) return 'Rechtsform & Finanzen';
    if (n.includes('solidar') || n.includes('sozial') || n.includes('miete') || n.includes('entgelt')) return 'Solidarität & Bezahlbarkeit';
    if (n.includes('vielfalt') || n.includes('inklusion') || n.includes('barriere')) return 'Vielfalt & Inklusion';
    return 'Und sonst';
  };

  const handleFiles = async (files: FileList) => {
    setIsDragging(false);
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const type = file.name.split('.').pop()?.toLowerCase();

      if (type !== 'pdf' && type !== 'docx') {
        alert(`Dateityp .${type} wird nicht unterstützt. Bitte lade nur .pdf oder .docx hoch.`);
        continue;
      }

      setUploadProgress(`Lese ${file.name}...`);
      try {
        const text = type === 'pdf' ? await parsePdf(file) : await parseDocx(file);

        const newDoc: AppDocument = {
          id: Math.random().toString(36).substr(2, 9),
          name: file.name,
          category: determineCategory(file.name),
          uploadDate: new Date().toLocaleDateString('de-DE'),
          content: text,
          status: 'aktiv'
        };

        onAddDoc(newDoc);
      } catch (err) {
        console.error("Fehler beim Verarbeiten:", err);
        alert(`Fehler beim Einlesen von ${file.name}`);
      }
    }
    setUploadProgress(null);
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files) {
      handleFiles(e.dataTransfer.files);
    }
  }, []);

  const handlePrepareInvitation = async () => {
    if (!inviteEmail.includes('@')) return;
    setIsProcessing(true);
    try {
      const draft = await gemini.generateInvitation(inviteEmail, inviteRole, documents);
      setAiDraft(draft);
      setInviteStep('preview');
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFinalizeInvite = async () => {
    setInviteStep('verifying');
    setIsProcessing(true);
    const verification = await gemini.verifyUser(inviteEmail);
    setVerificationResult(verification);
    setTimeout(() => {
      if (verification.success) {
        onInviteUser(inviteEmail, inviteRole, aiDraft);
        setShowInviteModal(false);
        resetInvite();
      }
      setIsProcessing(false);
    }, 2000);
  };

  const resetInvite = () => {
    setInviteStep('input');
    setInviteEmail('');
    setAiDraft('');
    setVerificationResult(null);
  };

  const handleSavePersona = () => {
    if (!personaName || !personaDesc) return;

    if (editingPersona) {
      onUpdatePersona({
        ...editingPersona,
        name: personaName,
        description: personaDesc,
        role: personaRole
      });
    } else {
      onAddPersona({
        id: Math.random().toString(36).substr(2, 9),
        name: personaName,
        description: personaDesc,
        role: personaRole
      });
    }
    setShowPersonaModal(false);
    setEditingPersona(null);
    setPersonaName('');
    setPersonaDesc('');
  };

  const openPersonaModal = (p?: Persona) => {
    if (p) {
      setEditingPersona(p);
      setPersonaName(p.name);
      setPersonaDesc(p.description);
      setPersonaRole(p.role);
    } else {
      setEditingPersona(null);
      setPersonaName('');
      setPersonaDesc('');
      setPersonaRole('beginner');
    }
    setShowPersonaModal(true);
  };

  const handleAddMilestone = () => {
    if(!newMilestone.title || !newMilestone.startDate) return;
    const m: Milestone = {
        id: Math.random().toString(36).substr(2, 9),
        title: newMilestone.title,
        startDate: newMilestone.startDate,
        endDate: newMilestone.endDate || newMilestone.startDate,
        owner: newMilestone.owner || 'Unassigned',
        progress: newMilestone.progress || 0,
        status: newMilestone.status as any || 'planned',
        description: newMilestone.description || ''
    };
    onUpdateMilestones([...milestones, m]);
    setNewMilestone({ title: '', startDate: '', endDate: '', owner: '', progress: 0, status: 'planned', description: '' });
    setShowMilestoneModal(false);
  };

  const handleRemoveMilestone = (id: string) => {
      onUpdateMilestones(milestones.filter(m => m.id !== id));
  };

  const handleExportTimeline = () => {
    // Convert milestones to SheetJS format
    const rows = milestones.map(m => ({
        Titel: m.title,
        Start: m.startDate,
        Ende: m.endDate,
        Verantwortlich: m.owner,
        Fortschritt: m.progress,
        Status: m.status,
        Beschreibung: m.description
    }));

    const worksheet = XLSX.utils.json_to_sheet(rows);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Zeitplan");

    // Trigger download
    XLSX.writeFile(workbook, "timeline.xlsx");
  };

  const getStatusIcon = (status: UserStatus) => {
    switch (status) {
      case 'aktiv': return <ShieldIcon className="w-5 h-5 text-blue-500" />;
      case 'eingeladen': return <ClockIcon className="w-5 h-5 text-gray-300" />;
      case 'deaktiviert': return <AlertIcon className="w-5 h-5 text-red-400" />;
      default: return null;
    }
  };

  return (
    <div className="flex-1 flex flex-col h-full bg-white overflow-hidden">
      {/* Sticky Tab Header */}
      <div className="sticky top-0 z-20 bg-white/80 backdrop-blur-md border-b border-gray-100">
