export default Sidebar;

import React, { useState, useEffect, useCallback } from 'react';
import { View, ChatSession, Document, User, Message, Role, UserStatus, FAQItem, Persona, Milestone } from './types';
import { INITIAL_DOCUMENTS, INITIAL_USERS, INITIAL_PERSONAS, INITIAL_MILESTONES } from './constants';
import LoginView from './components/LoginView';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import DocumentDetail from './components/DocumentDetail';
import LandingPage from './components/LandingPage';
import FAQView from './components/FAQView';
import TimelineView from './components/TimelineView';
import { gemini } from './services/geminiService';
import { isNextcloudConfigured, fetchNextcloudDocuments, fetchNextcloudUsers, fetchNextcloudTimeline } from './services/nextcloudService';

const STORAGE_KEY = 'wohnprojekt_docs_cache';
const FAQ_STORAGE_KEY = 'wohnprojekt_faq_cache';
const PERSONA_STORAGE_KEY = 'wohnprojekt_persona_cache';
const SESSIONS_STORAGE_KEY = 'wohnprojekt_chat_sessions';
const MILESTONE_STORAGE_KEY = 'wohnprojekt_milestone_cache';

const App: React.FC = () => {
  const [showLanding, setShowLanding] = useState(true);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [documents, setDocuments] = useState<Document[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : INITIAL_DOCUMENTS;
  });

  const [faqs, setFaqs] = useState<FAQItem[]>(() => {
    const saved = localStorage.getItem(FAQ_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [personas, setPersonas] = useState<Persona[]>(() => {
    const saved = localStorage.getItem(PERSONA_STORAGE_KEY);
    return saved ? JSON.parse(saved) : INITIAL_PERSONAS;
  });

  const [milestones, setMilestones] = useState<Milestone[]>(() => {
      const saved = localStorage.getItem(MILESTONE_STORAGE_KEY);
      return saved ? JSON.parse(saved) : INITIAL_MILESTONES;
  });

  const [sessions, setSessions] = useState<ChatSession[]>(() => {
    const saved = localStorage.getItem(SESSIONS_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [activeDoc, setActiveDoc] = useState<{ doc: Document, highlightText?: string, highlightSection?: string } | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(documents));
  }, [documents]);

  useEffect(() => {
    localStorage.setItem(FAQ_STORAGE_KEY, JSON.stringify(faqs));
  }, [faqs]);

  useEffect(() => {
    localStorage.setItem(PERSONA_STORAGE_KEY, JSON.stringify(personas));
  }, [personas]);

  useEffect(() => {
      localStorage.setItem(MILESTONE_STORAGE_KEY, JSON.stringify(milestones));
  }, [milestones]);

  useEffect(() => {
    localStorage.setItem(SESSIONS_STORAGE_KEY, JSON.stringify(sessions));
  }, [sessions]);

  // Nextcloud Sync
  useEffect(() => {
    const syncNextcloud = async () => {
      if (isNextcloudConfigured()) {
        const ncDocs = await fetchNextcloudDocuments(documents);
        if (ncDocs.length > 0) setDocuments(ncDocs);

        const ncUsers = await fetchNextcloudUsers();
        if (ncUsers.length > 0) setUsers(ncUsers);

        const ncTimeline = await fetchNextcloudTimeline();
        if (ncTimeline.length > 0) setMilestones(ncTimeline);
      }
    };
    syncNextcloud();
    const interval = setInterval(syncNextcloud, 60000); // Sync every minute
    return () => clearInterval(interval);
  }, []);

  const handleLogin = (email: string) => {
    const user = users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user && (user.status === 'aktiv' || user.status === 'eingeladen')) {
      setCurrentUser({ ...user, status: 'aktiv' });
    } else {
      alert("Zugriff verweigert. Bitte wende dich an die Wohnprojekt-Verwaltung.");
    }
  };

  const getActiveMessages = () => {
    if (!activeSessionId) return [];
    return sessions.find(s => s.id === activeSessionId)?.messages || [];
  };

  const handleAddDocument = async (doc: Document) => {
    setDocuments(prev => [...prev, doc]);

    // Direct addition to FAQs without suggestion phase
    for (const persona of personas) {
      try {
        const generated = await gemini.generateFAQs(doc, persona);
        const newFaqs: FAQItem[] = generated.map(g => ({
          id: Math.random().toString(36).substr(2, 9),
          question: g.question || '',
          answer: g.answer || '',
          category: g.category || doc.category,
          sourceDocId: doc.id,
          sourceDocName: doc.name,
          personaId: persona.id,
          feedback: undefined,
          userComment: ''
        }));
        setFaqs(prev => [...prev, ...newFaqs]);
      } catch (e) {
        console.error("Auto-FAQ Generation Error:", e);
      }
    }
  };

  const handleSendMessage = async (text: string) => {
    let currentId = activeSessionId;
    let currentSessions = [...sessions];

    if (!currentId) {
      currentId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: currentId,
        title: text.substring(0, 30) + '...',
        messages: [],
        createdAt: new Date().toISOString()
      };
      currentSessions = [newSession, ...currentSessions];
      setActiveSessionId(currentId);
      setSessions(currentSessions);
    }

    const userMsg: Message = { role: 'user', text };
    const sessionIndex = currentSessions.findIndex(s => s.id === currentId);
    currentSessions[sessionIndex].messages.push(userMsg);
    setSessions([...currentSessions]);

    setIsLoading(true);
    try {
      const history = currentSessions[sessionIndex].messages.map(m => ({ role: m.role, text: m.text }));
      const response = await gemini.askQuestion(text, documents, history);

      const aiMsg: Message = { 
        role: 'model', 
        text: response.text, 
        citations: response.citations 
      };

      currentSessions[sessionIndex].messages.push(aiMsg);
      setSessions([...currentSessions]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleExportCSV = () => {
    const headers = ['Frage', 'Antwort', 'Kategorie', 'Quelle', 'Zielgruppe', 'Feedback', 'Kommentar'];
    const rows = faqs.map(f => [
        `"${f.question.replace(/"/g, '""')}"`,
        `"${f.answer.replace(/"/g, '""')}"`,
        `"${f.category}"`,
        `"${f.sourceDocName}"`,
        `"${personas.find(p => p.id === f.personaId)?.name || 'Unbekannt'}"`,
        `"${f.feedback || ''}"`,
        `"${f.userComment || ''}"`
    ]);
    const csvContent = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wohnpro_faq_export_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  if (showLanding && !currentUser) {
    return <LandingPage onStart={() => setShowLanding(false)} />;
  }

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)}
        sessions={sessions}
        currentView={currentView}
        setView={(v) => { setCurrentView(v); setActiveDoc(null); if(v==='chat') setActiveSessionId(null); }}
        onSelectSession={(id) => { setActiveSessionId(id); setCurrentView('chat'); setActiveDoc(null); }}
      />

      <main className="flex-1 flex flex-col relative overflow-hidden h-full">
        {/* Header Mobile */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-gray-100 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2">
            <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/></svg>
          </button>
          <span className="font-bold text-gray-900">Wohnpro Guide</span>
          <div className="w-10" />
        </div>

        <div className="flex-1 relative overflow-hidden">
          {activeDoc ? (
            <DocumentDetail 
              document={activeDoc.doc} 
              onClose={() => setActiveDoc(null)} 
              highlightText={activeDoc.highlightText}
              highlightSection={activeDoc.highlightSection}
            />
          ) : currentView === 'chat' ? (
            <ChatView 
              messages={getActiveMessages()} 
              onSendMessage={handleSendMessage}
              onEnterVoice={() => setCurrentView('voice')}
              onViewDocument={(name, text, section) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc, highlightText: text, highlightSection: section });
              }}
              isLoading={isLoading}
            />
          ) : currentView === 'faq' ? (
            <FAQView 
              faqs={faqs}
              personas={personas}
              onViewSource={(name) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc });
              }}
              onUpdateFaq={(id, updates) => setFaqs(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f))}
              onExport={handleExportCSV}
            />
          ) : currentView === 'timeline' ? (
              <TimelineView milestones={milestones} />
          ) : currentView === 'voice' ? (
            <VoiceMode 
              documents={documents}
              onClose={(transcript) => {
                if (transcript && transcript.length > 0) {
                  const newId = Math.random().toString(36).substr(2, 9);
                  const newSession: ChatSession = {
                    id: newId,
                    title: 'Sprachgespräch ' + new Date().toLocaleTimeString(),
                    messages: transcript,
                    createdAt: new Date().toISOString()
                  };
                  setSessions(prev => [newSession, ...prev]);
                }
                setCurrentView('chat');
              }}
              onViewDocument={(name) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc });
              }}
            />
          ) : currentView === 'docs-view' ? (
            <div className="p-10 space-y-8 overflow-y-auto h-full no-scrollbar">
              <h1 className="text-4xl font-black mb-10">Dokumente</h1>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {documents.map(doc => (
                  <button 
                    key={doc.id} 
                    onClick={() => setActiveDoc({ doc })}
                    className="text-left bg-white p-8 rounded-[2.5rem] border border-gray-100 hover:shadow-2xl transition-all group"
                  >
                    <div className="p-4 bg-gray-50 rounded-2xl mb-6 group-hover:bg-black group-hover:text-white transition-all w-fit">
                      <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
                    </div>
                    <h3 className="font-bold text-lg mb-2 line-clamp-2">{doc.name}</h3>
                    <p className="text-xs text-gray-400 font-black uppercase tracking-widest">{doc.category}</p>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <AdminPanel 
              activeTab={currentView.startsWith('admin-users') ? 'users' : currentView.startsWith('admin-personas') ? 'personas' : currentView.startsWith('admin-timeline') ? 'timeline' : 'docs'}
              setActiveTab={(tab) => setCurrentView(`admin-${tab}` as View)}
              documents={documents}
              users={users}
              personas={personas}
              milestones={milestones}
              onAddDoc={handleAddDocument}
              onRemoveDoc={(id) => setDocuments(prev => prev.filter(d => d.id !== id))}
              onInviteUser={(email, role, content) => setUsers(prev => [...prev, { id: Math.random().toString(), email, role, status: 'eingeladen', invitedAt: new Date().toISOString(), inviteEmailContent: content }])}
              onRemoveUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))}
              onAddPersona={(p) => setPersonas(prev => [...prev, p])}
              onUpdatePersona={(p) => setPersonas(prev => prev.map(old => old.id === p.id ? p : old))}
              onRemovePersona={(id) => setPersonas(prev => prev.filter(p => p.id !== id))}
              onUpdateMilestones={setMilestones}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { FAQItem, Persona, Category } from '../types';
import { HelpIcon, ChevronDownIcon, DocIcon, InfoIcon, ShieldIcon, ThumbsUpIcon, ThumbsDownIcon, DownloadIcon, MessageIcon } from './Icons';

interface FAQViewProps {
  faqs: FAQItem[];
  personas: Persona[];
  onViewSource: (docName: string) => void;
  onUpdateFaq: (id: string, updates: Partial<FAQItem>) => void;
  onExport: () => void;
}

const ORDERED_CATEGORIES: Category[] = [
  "Bau",
  "Gemeinsames leben",
  "Nachhaltigkeit",
  "Rechtsform & Finanzen",
  "Solidarität & Bezahlbarkeit",
  "Und sonst",
  "Vielfalt & Inklusion"
];

const FAQView: React.FC<FAQViewProps> = ({ 
  faqs, 
  personas, 
  onViewSource, 
  onUpdateFaq, 
  onExport
}) => {
  const [openId, setOpenId] = useState<string | null>(null);
  const [activePersonaId, setActivePersonaId] = useState<string>(personas[0]?.id || '');
  const activeItemRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if ((!activePersonaId || !personas.find(p => p.id === activePersonaId)) && personas.length > 0) {
      setActivePersonaId(personas[0].id);
    }
  }, [personas, activePersonaId]);

  const filteredFaqs = faqs.filter(f => f.personaId === activePersonaId);
  const activePersona = personas.find(p => p.id === activePersonaId);

  useEffect(() => {
    if (openId && activeItemRef.current) {
      const timer = setTimeout(() => {
        activeItemRef.current?.scrollIntoView({
          behavior: 'smooth',
          block: 'start',
        });
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [openId]);

  if (faqs.length === 0) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center p-12 text-center animate-in fade-in duration-700 h-full">
        <div className="w-32 h-32 bg-white rounded-[3rem] flex items-center justify-center mb-10 shadow-[0_20px_40px_-15px_rgba(0,0,0,0.05)] border border-gray-50">
           <HelpIcon className="w-16 h-16 text-gray-200" />
        </div>
        <h2 className="text-3xl font-black mb-4">Das Hausgedächtnis füllt sich noch...</h2>
        <p className="text-gray-400 max-w-sm leading-relaxed font-medium">
          Sobald Admins Dokumente hochladen, erstellt der Wohnpro Guide automatisch FAQs für dich.
        </p>
      </div>
    );
  }

  return (
    <div className="h-full overflow-y-auto no-scrollbar py-12 px-6">
      <div className="max-w-4xl mx-auto space-y-12 pb-20">
        <header className="space-y-8">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div className="space-y-4">
                <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-widest">
                  <InfoIcon className="w-3 h-3" />
                  Wohnpro FAQ
                </div>
                <h1 className="text-5xl md:text-6xl font-black tracking-tight leading-[0.95]">Haus-Wissen <br /><span className="text-gray-300">zentral verwaltet.</span></h1>
              </div>
              <button 
                onClick={onExport}
                className="bg-black text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-gray-800 transition-all active:scale-95 shadow-xl shadow-black/10 whitespace-nowrap"
              >
                 <DownloadIcon className="w-4 h-4" />
                 Export CSV
              </button>
          </div>

          <div className="flex flex-wrap gap-3 pb-2">
            {personas.map(persona => (
              <button
                key={persona.id}
                onClick={() => setActivePersonaId(persona.id)}
                className={`px-6 py-3 rounded-2xl transition-all duration-300 font-bold text-sm flex items-center gap-2 ${
                  activePersonaId === persona.id 
                  ? 'bg-black text-white shadow-xl shadow-black/10 scale-105' 
                  : 'bg-white border border-gray-100 text-gray-400 hover:border-black/20 hover:text-black'
                }`}
              >
                {persona.role === 'expert' ? <ShieldIcon className="w-4 h-4" /> : <HelpIcon className="w-4 h-4" />}
                {persona.name}
              </button>
            ))}
          </div>

          {activePersona && (
             <div className="bg-gray-50 border border-gray-100 p-6 rounded-3xl animate-in fade-in slide-in-from-top-2">
                <p className="text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Perspektive: {activePersona.name}</p>
                <p className="text-gray-600 text-sm italic leading-relaxed">"{activePersona.description}"</p>
             </div>
          )}
        </header>

        {filteredFaqs.length === 0 ? (
          <div className="py-12 text-center">
            <p className="text-gray-400 font-medium">Noch keine FAQ-Einträge für diese Zielgruppe generiert.</p>
          </div>
        ) : (
          ORDERED_CATEGORIES.map(cat => {
             const categoryFaqs = filteredFaqs.filter(f => f.category === cat);
             if (categoryFaqs.length === 0) return null;

             return (
              <div key={cat} className="space-y-8">
                <h3 className="text-xs font-black uppercase tracking-[0.4em] text-gray-300 flex items-center gap-4">
                  {cat}
                  <div className="h-px bg-gray-100 flex-1" />
                </h3>
                <div className="grid gap-6">
                  {categoryFaqs.map(faq => (
                    <div 
                      key={faq.id}
                      ref={openId === faq.id ? activeItemRef : null}
                      className={`group relative bg-white border border-gray-100 rounded-[2.5rem] transition-all duration-500 overflow-hidden ${openId === faq.id ? 'shadow-[0_40px_80px_-20px_rgba(0,0,0,0.1)] -translate-y-1 ring-1 ring-black/5' : 'hover:shadow-xl hover:border-gray-200'}`}
                    >
                      <button 
                        onClick={() => setOpenId(openId === faq.id ? null : faq.id)}
                        className="w-full text-left p-8 flex items-center justify-between gap-6"
                      >
                        <div className="flex-1">
                          <h4 className="text-lg font-bold text-gray-900 group-hover:text-black transition-colors leading-tight">{faq.question}</h4>
                        </div>
                        <div className={`p-3 rounded-full transition-all duration-500 ${openId === faq.id ? 'bg-black text-white rotate-180' : 'bg-gray-50 text-gray-300'}`}>
                          <ChevronDownIcon className="w-5 h-5" />
                        </div>
                      </button>

                      {openId === faq.id && (
                        <div className="px-8 pb-8 animate-in slide-in-from-top-4 fade-in duration-500">
                          <div className="bg-gray-50 rounded-3xl p-8 mb-6 border border-gray-100/50">
                            <p className="text-gray-700 leading-relaxed font-medium">
                              {faq.answer}
                            </p>
                          </div>

                          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                             <button 
                               onClick={() => onViewSource(faq.sourceDocName)}
                               className="flex items-center gap-3 text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-black transition-colors"
                             >
                               <div className="p-2 bg-white rounded-lg border border-gray-100 shadow-sm">
                                  <DocIcon className="w-3 h-3" />
                               </div>
                               Quelle: {faq.sourceDocName}
                             </button>

                             <div className="flex items-center gap-3">
                               <button 
                                 onClick={() => onUpdateFaq(faq.id, { feedback: 'like' })}
                                 className={`p-2.5 rounded-xl border transition-all ${faq.feedback === 'like' ? 'bg-green-500 border-green-500 text-white' : 'border-gray-100 text-gray-300 hover:border-black/10 hover:text-black'}`}
                                 title="Hilfreich"
                               >
                                 <ThumbsUpIcon className="w-4 h-4" />
                               </button>
                               <button 
                                 onClick={() => onUpdateFaq(faq.id, { feedback: 'dislike' })}
                                 className={`p-2.5 rounded-xl border transition-all ${faq.feedback === 'dislike' ? 'bg-red-500 border-red-500 text-white' : 'border-gray-100 text-gray-300 hover:border-black/10 hover:text-black'}`}
                                 title="Nicht hilfreich"
                               >
                                 <ThumbsDownIcon className="w-4 h-4" />
                               </button>
                             </div>
                          </div>

                          {/* Comment Section */}
                          <div className="mt-6 pt-6 border-t border-gray-100">
                             <div className="relative">
                               <MessageIcon className="absolute top-4 left-4 w-4 h-4 text-gray-300" />
                               <input 
                                  type="text" 
                                  placeholder="Dein Kommentar oder Verbesserungsvorschlag..." 
                                  className="w-full bg-white border border-gray-100 rounded-2xl py-3 pl-12 pr-4 text-sm focus:outline-none focus:border-black/20 focus:ring-1 focus:ring-black/5"
                                  value={faq.userComment || ''}
                                  onChange={(e) => onUpdateFaq(faq.id, { userComment: e.target.value })}
                               />
                             </div>
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
             );
          })
        )}
      </div>
    </div>
  );
};

export default FAQView;

export enum Role {
  USER = 'USER',
  ADMIN = 'ADMIN'
}

export type UserStatus = 'aktiv' | 'eingeladen' | 'deaktiviert';

export type Category = string;

/**
 * Represents a registered user or a pending invitation.
 */
export interface User {
  id: string; // UUID
  email: string;
  role: Role;
  status: UserStatus;
  invitedAt: string; // ISO Date string
  inviteEmailContent?: string;
}

/**
 * Represents a knowledge source. 
 */
export interface Document {
  id: string; // UUID
  name: string;
  category: Category;
  uploadDate: string;
  content: string;
  status: 'aktiv' | 'archiviert';
  fileUrl?: string;
  etag?: string;
}

/**
 * Defines a target audience for FAQ generation.
 */
export interface Persona {
  id: string; // UUID
  name: string;
  description: string;
  role: 'beginner' | 'expert';
}

/**
 * AI-generated FAQ entries linked to specific documents and personas.
 */
export interface FAQItem {
  id: string; // UUID
  question: string;
  answer: string;
  category: Category;
  sourceDocId: string;
  sourceDocName: string;
  personaId: string;
  feedback?: 'like' | 'dislike';
  userComment?: string;
}

export interface Citation {
  source: string;
  text: string;
  section?: string;
  documentId?: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  citations?: Citation[];
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: string;
}

/**
 * Represents a project milestone for the timeline.
 */
export interface Milestone {
  id: string;
  title: string;
  startDate: string; // ISO Date YYYY-MM-DD
  endDate: string;   // ISO Date YYYY-MM-DD
  owner: string;     // Name or Initials
  progress: number;  // 0-100
  description: string;
  status: 'planned' | 'active' | 'done' | 'delayed';
}

export type View = 'chat' | 'voice' | 'admin-docs' | 'admin-users' | 'admin-personas' | 'admin-timeline' | 'docs-view' | 'doc-detail' | 'faq' | 'timeline';

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Document, Citation, Role, FAQItem, Persona } from "../types";

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Analyzes a document and assigns it to an existing category or creates a new one.
   */
  async detectCategory(docContent: string, existingCategories: string[]): Promise<string> {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analysiere den Inhalt des folgenden Dokuments und ordne es einer Kategorie zu.

        EXISTIERENDE KATEGORIEN:
        ${JSON.stringify(existingCategories)}

        REGELN:
        1. Wenn das Dokument gut in eine existierende Kategorie passt, wähle diese.
        2. Wenn es NICHT passt, erstelle einen NEUEN, kurzen Kategorienamen (max. 2 Wörter, z.B. "Gemeinschaft", "Rechtliches", "Garten").
        3. Sei präzise und vermeide generische Begriffe wie "Sonstiges" wenn möglich.

        DOKUMENT AUSZUG:
        ${docContent.substring(0, 5000)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              category: { type: Type.STRING }
            },
            required: ["category"]
          }
        }
      });
      const data = JSON.parse(response.text || '{}');
      return data.category || "Allgemein";
    } catch (e) {
      console.error("Category detection failed", e);
      return "Allgemein";
    }
  }

  async askQuestion(
    question: string, 
    documents: Document[], 
    history: { role: 'user' | 'model'; text: string }[]
  ): Promise<{ text: string, citations: Citation[] }> {
    const ai = this.getAI();
    const context = documents.map(d => `[DOC: ${d.name} (${d.category})] ${d.content}`).join('\n\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: [{ text: h.text }] })),
          { role: 'user', parts: [{ text: `Wissensbasis:\n${context}\n\nFrage: ${question}` }] }
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.1,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              answer: { type: Type.STRING },
              citations: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    source: { type: Type.STRING },
                    text: { type: Type.STRING },
                    section: { type: Type.STRING },
                  },
                  required: ["source", "text"]
                }
              }
            },
            required: ["answer", "citations"]
          }
        },
      });

      const data = JSON.parse(response.text || '{}');
      return {
        text: data.answer || "Fehler beim Laden.",
        citations: data.citations || []
      };
    } catch (e) {
      return { text: "API Error", citations: [] };
    }
  }

  async generateFAQs(doc: Document, persona: Persona, availableCategories: string[]): Promise<Partial<FAQItem>[]> {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analysiere das folgende Dokument des Wohnprojekts.

        DEINE PERSONA / ZIELGRUPPE:
        Name: ${persona.name}
        Beschreibung: ${persona.description}

        AUFGABE:
        Extrahiere basierend auf deiner Persona-Beschreibung 2 bis 4 Fragen, die genau DIESE Person an das Dokument stellen würde.

        KATEGORISIERUNG:
        Ordne jeder Frage eine Kategorie zu. 
        Bevorzuge diese Liste: ${JSON.stringify(availableCategories)}.
        Wenn eine Frage thematisch eindeutig woanders hingehört, nutze die Dokumentenkategorie: "${doc.category}".

        DOKUMENT:
        Name: ${doc.name}
        Inhalt: ${doc.content.substring(0, 15000)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                answer: { type: Type.STRING },
                category: { type: Type.STRING }
              },
              required: ["question", "answer", "category"]
            }
          }
        }
      });
      return JSON.parse(response.text || '[]');
    } catch (e) {
      console.error(e);
      return [];
    }
  }

  async generateInvitation(email: string, role: Role, documents: Document[]): Promise<string> {
    const ai = this.getAI();
    const houseContext = documents.slice(0, 2).map(d => d.content).join(' ');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Erstelle eine Einladung für Bewohner ${email} mit Rolle ${role}. Kontext: ${houseContext}`,
      config: {
        systemInstruction: "Du bist ein professioneller Verwalter eines modernen Wohnpro.",
      }
    });
    return response.text || "Willkommen im Wohnpro!";
  }

  async verifyUser(email: string): Promise<{ success: boolean; reason: string }> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Prüfe die E-Mail "${email}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            success: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["success", "reason"]
        }
      }
    });
    return JSON.parse(response.text || '{"success":true, "reason": "Verifiziert"}');
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useCallback } from 'react';
import { View, ChatSession, Document, User, Message, Role, UserStatus, FAQItem, Persona, Milestone } from './types';
import { INITIAL_DOCUMENTS, INITIAL_USERS, INITIAL_PERSONAS, INITIAL_MILESTONES } from './constants';
import LoginView from './components/LoginView';
import Sidebar from './components/Sidebar';
import ChatView from './components/ChatView';
import VoiceMode from './components/VoiceMode';
import AdminPanel from './components/AdminPanel';
import DocumentDetail from './components/DocumentDetail';
import LandingPage from './components/LandingPage';
import FAQView from './components/FAQView';
import TimelineView from './components/TimelineView';
import { gemini } from './services/geminiService';
import { isNextcloudConfigured, fetchNextcloudDocuments, fetchNextcloudUsers, fetchNextcloudTimeline } from './services/nextcloudService';

const STORAGE_KEY = 'wohnprojekt_docs_cache';
const FAQ_STORAGE_KEY = 'wohnprojekt_faq_cache';
const PERSONA_STORAGE_KEY = 'wohnprojekt_persona_cache';
const SESSIONS_STORAGE_KEY = 'wohnprojekt_chat_sessions';
const MILESTONE_STORAGE_KEY = 'wohnprojekt_milestone_cache';
const CATEGORIES_STORAGE_KEY = 'wohnprojekt_categories_cache';

const App: React.FC = () => {
  const [showLanding, setShowLanding] = useState(true);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>('chat');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [documents, setDocuments] = useState<Document[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : INITIAL_DOCUMENTS;
  });

  const [categories, setCategories] = useState<string[]>(() => {
    const saved = localStorage.getItem(CATEGORIES_STORAGE_KEY);
    return saved ? JSON.parse(saved) : ["Allgemein"];
  });

  const [faqs, setFaqs] = useState<FAQItem[]>(() => {
    const saved = localStorage.getItem(FAQ_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [personas, setPersonas] = useState<Persona[]>(() => {
    const saved = localStorage.getItem(PERSONA_STORAGE_KEY);
    return saved ? JSON.parse(saved) : INITIAL_PERSONAS;
  });

  const [milestones, setMilestones] = useState<Milestone[]>(() => {
      const saved = localStorage.getItem(MILESTONE_STORAGE_KEY);
      return saved ? JSON.parse(saved) : INITIAL_MILESTONES;
  });

  const [sessions, setSessions] = useState<ChatSession[]>(() => {
    const saved = localStorage.getItem(SESSIONS_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [activeDoc, setActiveDoc] = useState<{ doc: Document, highlightText?: string, highlightSection?: string } | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(documents));
  }, [documents]);

  useEffect(() => {
    localStorage.setItem(CATEGORIES_STORAGE_KEY, JSON.stringify(categories));
  }, [categories]);

  useEffect(() => {
    localStorage.setItem(FAQ_STORAGE_KEY, JSON.stringify(faqs));
  }, [faqs]);

  useEffect(() => {
    localStorage.setItem(PERSONA_STORAGE_KEY, JSON.stringify(personas));
  }, [personas]);

  useEffect(() => {
      localStorage.setItem(MILESTONE_STORAGE_KEY, JSON.stringify(milestones));
  }, [milestones]);

  useEffect(() => {
    localStorage.setItem(SESSIONS_STORAGE_KEY, JSON.stringify(sessions));
  }, [sessions]);

  // Nextcloud Sync
  useEffect(() => {
    const syncNextcloud = async () => {
      if (isNextcloudConfigured()) {
        const ncDocs = await fetchNextcloudDocuments(documents);

        // Check for new docs that need categorization logic (optional enhancement for future)
        // For now, we assume Nextcloud docs get a default or are categorized manually later
        // or we could run the AI categorization here if we wanted fully automated background sync.

        if (ncDocs.length > 0) setDocuments(ncDocs);

        const ncUsers = await fetchNextcloudUsers();
        if (ncUsers.length > 0) setUsers(ncUsers);

        const ncTimeline = await fetchNextcloudTimeline();
        if (ncTimeline.length > 0) setMilestones(ncTimeline);
      }
    };
    syncNextcloud();
    const interval = setInterval(syncNextcloud, 60000); // Sync every minute
    return () => clearInterval(interval);
  }, []);

  const handleLogin = (email: string) => {
    const user = users.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user && (user.status === 'aktiv' || user.status === 'eingeladen')) {
      setCurrentUser({ ...user, status: 'aktiv' });
    } else {
      alert("Zugriff verweigert. Bitte wende dich an die Wohnprojekt-Verwaltung.");
    }
  };

  const getActiveMessages = () => {
    if (!activeSessionId) return [];
    return sessions.find(s => s.id === activeSessionId)?.messages || [];
  };

  const handleAddDocument = async (doc: Document) => {
    // 1. Dynamic Category Detection
    let detectedCategory = "Allgemein";
    try {
      detectedCategory = await gemini.detectCategory(doc.content, categories);
    } catch (e) {
      console.warn("Could not detect category, using fallback.");
    }

    const docWithCategory = { ...doc, category: detectedCategory };
    setDocuments(prev => [...prev, docWithCategory]);

    // 2. Update Category List if new
    let updatedCategories = [...categories];
    if (!categories.includes(detectedCategory)) {
       updatedCategories = [...categories, detectedCategory];
       setCategories(updatedCategories);
    }

    // 3. Generate FAQs using the dynamic categories
    for (const persona of personas) {
      try {
        const generated = await gemini.generateFAQs(docWithCategory, persona, updatedCategories);
        const newFaqs: FAQItem[] = generated.map(g => ({
          id: Math.random().toString(36).substr(2, 9),
          question: g.question || '',
          answer: g.answer || '',
          category: g.category || detectedCategory,
          sourceDocId: doc.id,
          sourceDocName: doc.name,
          personaId: persona.id,
          feedback: undefined,
          userComment: ''
        }));
        setFaqs(prev => [...prev, ...newFaqs]);
      } catch (e) {
        console.error("Auto-FAQ Generation Error:", e);
      }
    }
  };

  const handleSendMessage = async (text: string) => {
    let currentId = activeSessionId;
    let currentSessions = [...sessions];

    if (!currentId) {
      currentId = Math.random().toString(36).substr(2, 9);
      const newSession: ChatSession = {
        id: currentId,
        title: text.substring(0, 30) + '...',
        messages: [],
        createdAt: new Date().toISOString()
      };
      currentSessions = [newSession, ...currentSessions];
      setActiveSessionId(currentId);
      setSessions(currentSessions);
    }

    const userMsg: Message = { role: 'user', text };
    const sessionIndex = currentSessions.findIndex(s => s.id === currentId);
    currentSessions[sessionIndex].messages.push(userMsg);
    setSessions([...currentSessions]);

    setIsLoading(true);
    try {
      const history = currentSessions[sessionIndex].messages.map(m => ({ role: m.role, text: m.text }));
      const response = await gemini.askQuestion(text, documents, history);

      const aiMsg: Message = { 
        role: 'model', 
        text: response.text, 
        citations: response.citations 
      };

      currentSessions[sessionIndex].messages.push(aiMsg);
      setSessions([...currentSessions]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleExportCSV = () => {
    const headers = ['Frage', 'Antwort', 'Kategorie', 'Quelle', 'Zielgruppe', 'Feedback', 'Kommentar'];
    const rows = faqs.map(f => [
        `"${f.question.replace(/"/g, '""')}"`,
        `"${f.answer.replace(/"/g, '""')}"`,
        `"${f.category}"`,
        `"${f.sourceDocName}"`,
        `"${personas.find(p => p.id === f.personaId)?.name || 'Unbekannt'}"`,
        `"${f.feedback || ''}"`,
        `"${f.userComment || ''}"`
    ]);
    const csvContent = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `wohnpro_faq_export_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  if (showLanding && !currentUser) {
    return <LandingPage onStart={() => setShowLanding(false)} />;
  }

  if (!currentUser) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)}
        sessions={sessions}
        currentView={currentView}
        setView={(v) => { setCurrentView(v); setActiveDoc(null); if(v==='chat') setActiveSessionId(null); }}
        onSelectSession={(id) => { setActiveSessionId(id); setCurrentView('chat'); setActiveDoc(null); }}
      />

      <main className="flex-1 flex flex-col relative overflow-hidden h-full">
        {/* Header Mobile */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-gray-100 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2">
            <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/></svg>
          </button>
          <span className="font-bold text-gray-900">Wohnpro Guide</span>
          <div className="w-10" />
        </div>

        <div className="flex-1 relative overflow-hidden">
          {activeDoc ? (
            <DocumentDetail 
              document={activeDoc.doc} 
              onClose={() => setActiveDoc(null)} 
              highlightText={activeDoc.highlightText}
              highlightSection={activeDoc.highlightSection}
            />
          ) : currentView === 'chat' ? (
            <ChatView 
              messages={getActiveMessages()} 
              onSendMessage={handleSendMessage}
              onEnterVoice={() => setCurrentView('voice')}
              onViewDocument={(name, text, section) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc, highlightText: text, highlightSection: section });
              }}
              isLoading={isLoading}
            />
          ) : currentView === 'faq' ? (
            <FAQView 
              faqs={faqs}
              personas={personas}
              categories={categories}
              onViewSource={(name) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc });
              }}
              onUpdateFaq={(id, updates) => setFaqs(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f))}
              onExport={handleExportCSV}
            />
          ) : currentView === 'timeline' ? (
              <TimelineView milestones={milestones} />
          ) : currentView === 'voice' ? (
            <VoiceMode 
              documents={documents}
              onClose={(transcript) => {
                if (transcript && transcript.length > 0) {
                  const newId = Math.random().toString(36).substr(2, 9);
                  const newSession: ChatSession = {
                    id: newId,
                    title: 'Sprachgespräch ' + new Date().toLocaleTimeString(),
                    messages: transcript,
                    createdAt: new Date().toISOString()
                  };
                  setSessions(prev => [newSession, ...prev]);
                }
                setCurrentView('chat');
              }}
              onViewDocument={(name) => {
                const doc = documents.find(d => d.name.toLowerCase().includes(name.toLowerCase()));
                if (doc) setActiveDoc({ doc });
              }}
            />
          ) : currentView === 'docs-view' ? (
            <div className="p-10 space-y-8 overflow-y-auto h-full no-scrollbar">
              <h1 className="text-4xl font-black mb-10">Dokumente</h1>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {documents.map(doc => (
                  <button 
                    key={doc.id} 
                    onClick={() => setActiveDoc({ doc })}
                    className="text-left bg-white p-8 rounded-[2.5rem] border border-gray-100 hover:shadow-2xl transition-all group"
                  >
                    <div className="p-4 bg-gray-50 rounded-2xl mb-6 group-hover:bg-black group-hover:text-white transition-all w-fit">
                      <svg className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
                    </div>
                    <h3 className="font-bold text-lg mb-2 line-clamp-2">{doc.name}</h3>
                    <p className="text-xs text-gray-400 font-black uppercase tracking-widest">{doc.category}</p>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <AdminPanel 
              activeTab={currentView.startsWith('admin-users') ? 'users' : currentView.startsWith('admin-personas') ? 'personas' : currentView.startsWith('admin-timeline') ? 'timeline' : 'docs'}
              setActiveTab={(tab) => setCurrentView(`admin-${tab}` as View)}
              documents={documents}
              users={users}
              personas={personas}
              milestones={milestones}
              onAddDoc={handleAddDocument}
              onRemoveDoc={(id) => setDocuments(prev => prev.filter(d => d.id !== id))}
              onInviteUser={(email, role, content) => setUsers(prev => [...prev, { id: Math.random().toString(), email, role, status: 'eingeladen', invitedAt: new Date().toISOString(), inviteEmailContent: content }])}
              onRemoveUser={(id) => setUsers(prev => prev.filter(u => u.id !== id))}
              onAddPersona={(p) => setPersonas(prev => [...prev, p])}
              onUpdatePersona={(p) => setPersonas(prev => prev.map(old => old.id === p.id ? p : old))}
              onRemovePersona={(id) => setPersonas(prev => prev.filter(p => p.id !== id))}
              onUpdateMilestones={setMilestones}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { FAQItem, Persona, Category } from '../types';
import { HelpIcon, ChevronDownIcon, DocIcon, InfoIcon, ShieldIcon, ThumbsUpIcon, ThumbsDownIcon, DownloadIcon, MessageIcon } from './Icons';

interface FAQViewProps {
  faqs: FAQItem[];
  personas: Persona[];
  categories: Category[];
  onViewSource: (docName: string) => void;
  onUpdateFaq: (id: string, updates: Partial<FAQItem>) => void;
  onExport: () => void;
}

const FAQView: React.FC<FAQViewProps> = ({ 
  faqs, 
  personas,
  categories,
  onViewSource, 
  onUpdateFaq, 
  onExport
}) => {
  const [openId, setOpenId] = useState<string | null>(null);
  const [activePersonaId, setActivePersonaId] = useState<string>(personas[0]?.id || '');
  const activeItemRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if ((!activePersonaId || !personas.find(p => p.id === activePersonaId)) && personas.length > 0) {
      setActivePersonaId(personas[0].id);
    }
  }, [personas, activePersonaId]);

  const filteredFaqs = faqs.filter(f => f.personaId === activePersonaId);
  const activePersona = personas.find(p => p.id === activePersonaId);

  // Sort categories alphabetically for consistent display
  const sortedCategories = [...categories].sort((a, b) => a.localeCompare(b));

  useEffect(() => {
    if (openId && activeItemRef.current) {
      const timer = setTimeout(() => {
        activeItemRef.current?.scrollIntoView({
          behavior: 'smooth',
          block: 'start',
        });
      }, 100);
      return () => clearTimeout(timer);
    }
